const Map<String, (String nameId, String descId)> kLandmarkId = {
  'chengdu/panda': ('Pusat Penangkaran Panda Raksasa', 'Chengdu Research Base of Giant Panda Breeding adalah pusat konservasi dan penangkaran panda terbesar di dunia. Jutaan pengunjung datang setiap tahun untuk melihat panda, simbol kesayangan kota ini, berguling-guling riang di antara rumpun bambu.'),
  'chengdu/hotpot': ('Hotpot Sichuan', 'Mendidih dengan merica Sichuan yang membuat lidah kebas dan minyak cabai merah menyala, hotpot adalah jantung budaya kuliner Chengdu. Semua orang mencelupkan suapannya sendiri ke kuali di tengah meja — makan di sini adalah permainan yang dinikmati bersama.'),
  'chengdu/bianlian': ('Bian Lian (Seni Mengubah Wajah)', 'Dalam Bian Lian, seni ajaib dari opera Sichuan, para maestro mengganti topeng warna-warni mereka dalam sekejap mata hanya dengan satu kibasan tangan. Rahasianya diwariskan turun-temurun hanya dari guru kepada murid.'),
  'chengdu/jinli': ('Jalan Kuno Jinli', 'Diterangi lentera merah, Jinli adalah jalan pasar yang sejarahnya membentang hingga era Tiga Kerajaan. Dengan kedai teh, wayang bayangan, dan seniman lukis gula yang menggambar naga, di sinilah ritme hidup Chengdu yang terkenal santai paling terasa.'),
  'nanjing/citywall': ('Tembok Kota Ming', 'Dibangun oleh pendiri Dinasti Ming untuk melindungi ibu kotanya, benteng raksasa ini adalah tembok kota terpanjang di dunia yang masih berdiri. Setiap bata diukir dengan nama pembuatnya sebagai jaminan mutu, dan berjalan di atasnya menyuguhkan wajah lama dan baru Nanjing sekaligus.'),
  'nanjing/plum': ('Bunga Plum', 'Mekar menembus salju di tengah musim dingin, bunga plum melambangkan ketangguhan dan harapan dalam budaya Tiongkok — dan Nanjing memilihnya sebagai bunga kota. Di akhir musim dingin, lereng Bukit Meihua berubah menjadi lautan bunga merah muda dan putih, dan orang-orang berjalan-jalan di bawah pepohonannya.'),
  'nanjing/duck': ('Bebek Asin', 'Bebek asin khas Nanjing diasinkan dalam larutan berbumbu, direbus perlahan, lalu disajikan dingin. Dagingnya lembut dengan rasa asin yang pas, dan bebek adalah kegemaran seisi kota — lelucon setempat mengatakan tak ada bebek yang keluar dari Nanjing dalam keadaan hidup.'),
  'nanjing/bridge': ('Jembatan Sungai Yangtze', 'Selesai dibangun pada 1968 sepenuhnya oleh insinyur Tiongkok, Jembatan Yangtze Nanjing adalah bangunan bertingkat dua raksasa yang membawa jalan raya sekaligus rel kereta melintasi sungai. Karena dibangun tanpa bantuan asing, jembatan ini menjadi simbol kemandirian Tiongkok modern dan masih dibanggakan dalam buku pelajaran sekolah.'),
  'qingdao/beer': ('Bir Tsingtao', 'Didirikan pada masa pendudukan Jerman, pabrik bir Tsingtao menjadikan Qingdao rumah bagi bir paling terkenal di Tiongkok. Setiap musim panas festival bir internasional menyemarakkan kota, dan bir segar dari tong yang dijual dalam kantong plastik — diminum dengan sedotan — tetap menjadi tradisi jalanan Qingdao yang paling menggemaskan.'),
  'qingdao/sailing': ('Kota Pelayaran', 'Lomba layar Olimpiade 2008 digelar di marina Qingdao, dan sejak itu kota ini menyandang gelar \'Kota Layar\'. Dengan teluknya yang berangin, cakrawala yang dihiasi layar-layar putih, dan jalur pejalan kaki di tepi laut, inilah ibu kota olahraga air di Tiongkok.'),
  'qingdao/beach': ('Pantai', 'Pantai-pantai Qingdao terhampar di bawah perbukitan berisi bangunan era Jerman beratap merah, memberi kota ini suasana kota pesisir Eropa yang langka di Tiongkok. Di musim panas pasirnya dipenuhi perenang, dan jalur pantai yang menghubungkan teluk demi teluk adalah rute klasik untuk menikmati matahari terbenam.'),
  'qingdao/crab': ('Hidangan Laut', 'Menghadap Laut Kuning, Qingdao menyantap hasil laut yang segar setiap hari: lapak kerang, tiram, bulu babi, dan kepiting memadati dermaga. Cara khas warga setempat adalah mengukus tangkapan hari itu secara sederhana dan menyandingkannya dengan bir Tsingtao yang dingin menyegarkan.'),
  'changsha/pepper': ('Cabai', 'Berbeda dari pedas Sichuan yang membuat lidah kebas, masakan Hunan terkenal dengan pedas kering yang tajam — cabai segar dan cabai acar hadir di hampir setiap hidangan. Di Changsha, rasa pedas adalah jawaban lama terhadap iklim lembap; warganya bercanda bahwa mereka tidak takut pedas, mereka takut tidak ada pedas.'),
  'changsha/tofu': ('Tahu Busuk', 'Direndam dalam larutan fermentasi lalu digoreng, tahu bau khas Changsha keluar hitam legam dan renyah di luar, tetapi putih bersih dan lembut di dalam. Jangan tertipu aromanya yang menyengat — disiram saus cabai, camilan kecil ini menarik antrean terpanjang di pasar malam Changsha.'),
  'changsha/fireworks': ('Kembang Api', 'Liuyang, tetangga Changsha, selama berabad-abad dianggap sebagai ibu kota kembang api dunia — di tanah kelahiran bubuk mesiu, kerajinan ini diwariskan dari generasi ke generasi. Dalam pertunjukan rutin di tepi Sungai Xiang, langit dan air menyala warna-warni bersamaan.'),
  'changsha/orange': ('Pulau Jeruk', 'Pulau Jeruk, daratan memanjang di tengah Sungai Xiang, mengambil namanya dari kebun jeruk keprok di sepanjang tepiannya. Mao Zedong berenang di perairan ini semasa muda dan menulis puisi terkenal tentang pulau ini; kini patung granit raksasa Mao muda menatap sungai dari ujung pulau.'),
  'zhengzhou/kungfu': ('Kung Fu Shaolin', 'Di kaki Gunung Song dekat Zhengzhou berdiri Kuil Shaolin, tempat lahirnya Buddhisme Chan dan kungfu Shaolin. Di sekitar biara yang berusia sekitar 1.500 tahun ini, ribuan murid sekolah bela diri menjaga warisan itu tetap hidup dengan latihan yang dimulai sejak fajar.'),
  'zhengzhou/train': ('Pusat Kereta Api', 'Zhengzhou tumbuh menjadi metropolis di titik persilangan jalur kereta utama utara-selatan dan timur-barat Tiongkok. Dijuluki \'kota yang dibangun kereta api\', kota ini tetap menjadi salah satu pusat transit tersibuk dalam jaringan kereta cepat negeri itu.'),
  'zhengzhou/wheat': ('Dataran Gandum', 'Dataran Henan yang diairi Sungai Kuning adalah salah satu lumbung gandum terbesar Tiongkok. Tanahnya yang subur menghidupi jiwa masakan utara — mi tarik tangan, pangsit kukus, dan roti pipih panggang semuanya bermula dari gandum ladang-ladang ini.'),
  'zhengzhou/ding': ('Bejana Perunggu Ding', 'Zhengzhou dan sekitarnya pernah menjadi ibu kota Dinasti Shang, salah satu dinasti tertua Tiongkok, dan penggalian di sini menemukan kuali perunggu upacara yang disebut ding. Bejana-bejana ini melambangkan kekuasaan dan persembahan kepada leluhur — itulah sebabnya kota ini terhitung sebagai salah satu tempat lahirnya peradaban Tiongkok.'),
  'wuxi/lake': ('Danau Taihu', 'Wuxi berdiri di tepi Taihu, salah satu danau air tawar terbesar di Tiongkok, yang ikan, udang, dan sayuran airnya menjadi dasar masakan setempat. Dipandang saat matahari terbenam dari tanjung Yuantouzhu, danau ini terlihat semakin memesona di musim bunga sakura.'),
  'wuxi/peach': ('Persik Yangshan', 'Kota kecil Yangshan di Wuxi termasyhur di seluruh Tiongkok berkat buah persiknya yang begitu manis dan berair hingga bisa disantap dengan sendok. Buahnya matang di pertengahan musim panas, saat musim panen membawa suasana pesta dan kebun-kebun dibuka untuk pengunjung.'),
  'wuxi/figurine': ('Kerajinan Tanah Liat Huishan', 'Boneka tanah liat Huishan adalah kerajinan rakyat berusia ratusan tahun yang dibentuk dari tanah liat hitam lembut di kaki Bukit Hui di Wuxi. Yang paling dicintai adalah A-Fu, sosok anak berpipi tembam yang melambangkan kelimpahan dan kegembiraan; dilukis tangan dengan warna-warna cerah, boneka ini adalah oleh-oleh klasik kota.'),
  'wuxi/boat': ('Perahu Kanal', 'Terusan Besar, jalur air buatan manusia terpanjang di dunia, mengalir tepat melalui jantung Wuxi. Naik perahu di kawasan Jembatan Qingming yang diterangi lentera dan menyusuri rumah-rumah tua berdinding putih beratap genting hitam adalah cara terindah untuk berkenalan dengan kota ini.'),
  'nanning/tree': ('Kota Hijau', 'Terletak di sabuk tropis Tiongkok selatan, Nanning dijuluki \'Kota Hijau\' berkat jalan-jalannya yang diteduhi pohon raksasa dan taman-taman yang hijau sepanjang tahun. Dekat perbatasan Vietnam, kota ini menjadi gerbang perdagangan dan pertukaran budaya antara Tiongkok dan Asia Tenggara.'),
  'nanning/noodle': ('Mi Laoyou', 'Laoyou fen, \'mi kawan lama\', adalah hidangan klasik Nanning berkuah asam pedas yang dimasak dengan rebung acar, kacang hitam fermentasi, dan cabai. Konon seorang pemilik kedai teh pertama kali memasak sup ini untuk menyembuhkan kawan lamanya yang sakit — dan sejak itu ia menjadi obat mujarab di hari-hari lembap.'),
  'nanning/song': ('Lagu Rakyat', 'Suku Zhuang di Guangxi telah berabad-abad menuangkan perasaan mereka lewat lagu rakyat improvisasi yang dinyanyikan bersahut-sahutan. Setiap musim semi, pesta lagu \'bulan ketiga\' memenuhi Nanning dengan adu pantun bernyanyi, dan penyanyi legendaris Liu Sanjie tetap menjadi pahlawan tercinta tradisi ini.'),
  'nanning/mango': ('Buah Tropis', 'Iklim tropis Nanning menjadikannya negeri berlimpah mangga, lengkeng, leci, dan pepaya — lapak-lapak jalanan penuh buah segar sepanjang tahun. Di malam yang hangat, hidangan penutup buah dingin dan jus segar adalah cara favorit warga kota untuk menyejukkan diri.'),
  'nanchang/pavilion': ('Paviliun Tengwang', 'Paviliun Tengwang di tepi Sungai Gan, yang telah berkali-kali hancur dan dibangun kembali sejak Dinasti Tang, adalah satu dari tiga menara paling termasyhur di Tiongkok selatan. Kata pengantar yang digubah penyair muda Wang Bo di sini menjadi mahakarya sastra Tiongkok dan mengabadikan paviliun ini.'),
  'nanchang/star': ('Pemberontakan 1 Agustus', 'Pemberontakan Nanchang pada 1 Agustus 1927 dianggap sebagai kelahiran Tentara Pembebasan Rakyat, sehingga Nanchang dijuluki \'Kota Para Pahlawan\'. Angka \'8-1\' pada bendera tentara itu merujuk pada tanggal tersebut — dan memberi nama pada alun-alun utama kota.'),
  'nanchang/porcelain': ('Keramik Jingdezhen', 'Provinsi Nanchang, Jiangxi, adalah rumah bagi Jingdezhen, ibu kota porselen dunia. Selama seribu tahun tungku kekaisarannya membakar \'emas putih\' untuk istana, lalu kafilah dan kapal membawanya ke seluruh dunia — kerajinan yang hingga kini tetap hidup di tangan para perajin muda.'),
  'nanchang/sunset': ('Pemandangan Sungai Gan', 'Saat malam tiba, kedua tepi Sungai Gan berubah wajah: fasad ratusan gedung menjadi satu pertunjukan cahaya raksasa yang sinkron. Taman-taman tepi sungai dan siluet Paviliun Tengwang yang bercahaya menjadikan kawasan ini rute jalan malam favorit warga Nanchang.'),
  'yinchuan/camel': ('Jalur Sutra', 'Sebagai oasis yang diairi Sungai Kuning, Yinchuan adalah salah satu gerbang barat tempat kafilah Jalur Sutra beristirahat sebelum menghadapi gurun. Di luar kota, makam raja Dinasti Xia Barat yang menyerupai piramida masih menjulang sunyi di bawah matahari gurun.'),
  'yinchuan/grapes': ('Kebun Anggur Helan', 'Kaki timur Pegunungan Helan, dengan matahari melimpah, udara kering, dan tanah berbatu, dianggap sebagai daerah anggur terbaik Tiongkok. Anggur dari kebun-kebun di sini kini memenangkan penghargaan internasional, dan para penggemar menjulukinya \'Bordeaux-nya Tiongkok\'.'),
  'yinchuan/desert': ('Gurun Shapotou', 'Di Shapotou dekat Yinchuan, bukit pasir keemasan Gurun Tengger bertemu Sungai Kuning — salah satu pemandangan langka di mana gurun dan sungai berdampingan. Meluncur menuruni bukit pasir, menjelajah gurun dengan kafilah unta, dan menyeberangi sungai dengan rakit kulit domba adalah petualangan klasik daerah ini.'),
  'yinchuan/sheep': ('Daging Domba Khas Hui', 'Daging domba adalah bintang masakan Muslim Hui di Ningxia: sate panggang bertabur jintan, domba rebus yang empuk, dan sup mi tarik tangan memenuhi meja makan kota. Dibesarkan di padang rumput stepa, domba lokal ini terkenal di seluruh Tiongkok karena kelembutan dan rasanya yang bersih.'),
  'lhasa/mountain': ('Istana Potala', 'Menjulang di puncak Bukit Merah, Istana Potala adalah mahakarya arsitektur Tibet dengan ratusan ruangan, makam suci, dan kapel. Dulunya istana musim dingin para Dalai Lama, bangunan merah-putih ini termasuk Situs Warisan Dunia UNESCO dan terlihat dari hampir setiap sudut Lhasa.'),
  'lhasa/prayer': ('Kuil Jokhang', 'Para peziarah menuju Jokhang, kuil paling suci dalam Buddhisme Tibet, kadang dengan bersujud sepanjang perjalanan. Di jalur Barkhor yang mengelilingi kuil, arus peziarah yang memutar roda doa tak pernah berhenti sepanjang hari, dan aroma dupa memenuhi jalan-jalan.'),
  'lhasa/yak': ('Budaya Yak', 'Tahan terhadap dinginnya dataran tinggi, yak adalah tulang punggung kehidupan Tibet: susunya menjadi mentega dan keju, bulunya menjadi tenda dan pakaian, kotorannya menjadi bahan bakar. Bahkan pelita yang menyala siang malam di kuil-kuil pun berbahan bakar mentega dari susu yak.'),
  'lhasa/tea': ('Teh Mentega', 'Teh mentega, yang dikocok dari mentega yak, garam, dan teh pekat, adalah minuman sehari-hari Tibet. Dalam dingin kering di ketinggian, teh ini menghangatkan sekaligus mengenyangkan — dan terus mengisi ulang cangkir tamu adalah aturan termanis dalam keramahan Tibet.'),
  'zhuhai/shell': ('Patung Gadis Nelayan', 'Berdiri di atas batu karang di laut sambil mengangkat mutiara ke langit, patung Gadis Nelayan adalah lambang Zhuhai. Patung ini lahir dari legenda setempat tentang bidadari yang menjelma manusia demi cintanya pada seorang nelayan, dan menyapa siapa pun yang menyusuri jalan pantai dengan sikapnya yang anggun.'),
  'zhuhai/bridge': ('Jembatan HZM', 'Jembatan Hong Kong-Zhuhai-Makau adalah penyeberangan laut terpanjang di dunia sepanjang 55 km, berupa rangkaian jembatan, pulau buatan, dan terowongan bawah laut. Menghubungkan tiga kota di delta Sungai Mutiara dalam satu garis, bangunan raksasa ini termasuk karya ikonik teknik modern.'),
  'zhuhai/island': ('Seratus Pulau', 'Nama Zhuhai berarti \'laut mutiara\', dan lebih dari seratus pulau bertaburan di sepanjang pesisirnya. Pulau-pulau seperti Dong\'ao dan Wailingding, yang dicapai dengan feri, menawarkan desa nelayan, teluk yang tenang, dan restoran hidangan laut — masing-masing hidup dengan iramanya sendiri.'),
  'zhuhai/lobster': ('Hidangan Laut', 'Di tempat Sungai Mutiara bertemu laut, meja makan Zhuhai selalu diisi tangkapan hari itu: lobster, udang mantis, kerang kampak, dan tiram dipilih hidup-hidup dari akuarium lalu langsung dimasak. Pengukusan ringan ala Kanton membuat kesegaran dan rasa manis alaminya menonjol.'),
  'yantai/apple': ('Apel Yantai', 'Iklim laut Yantai yang sejuk dan sinar mataharinya yang melimpah menghasilkan apel paling terkenal di Tiongkok — merah, renyah, dan beraroma madu, dikirim ke segala penjuru negeri. Di musim gugur, kebun-kebun di sepanjang pantai sibuk dengan panen dan kota pun dipenuhi harum apel.'),
  'yantai/wine': ('Anggur Changyu', 'Changyu, kilang anggur modern pertama di Tiongkok, didirikan di Yantai pada 1892 dan hingga kini menjadi merek anggur paling bersejarah di negeri itu. Dengan museum budaya anggur, gudang bawah tanah bersejarah, dan rute kebun anggur di sekitarnya, Yantai termasuk segelintir \'kota anggur\' sejati di Asia.'),
  'yantai/wave': ('Pesisir Penglai', 'Pesisir Penglai di Yantai dikisahkan dalam mitologi Tiongkok sebagai tempat Delapan Dewa mengarungi lautan. Fatamorgana yang kadang berpendar di atas air membuat pantai ini termasyhur sebagai \'negeri para peri\', dan Paviliun Penglai yang bersejarah memandangi laut dari atas tebingnya.'),
  'yantai/cherry': ('Kebun Ceri', 'Yantai adalah salah satu daerah penghasil ceri terpenting di Tiongkok; iklim pesisirnya yang sejuk ideal untuk buah yang besar, berair, dan manis. Di awal musim panas kebun-kebun dibuka untuk pengunjung — memetik ceri langsung dari dahannya adalah tamasya termanis musim itu.'),
  'datong/buddha': ('Gua Yungang', 'Dipahat pada tebing di sebelah barat Datong, Gua Yungang menyimpan ribuan arca Buddha dari Dinasti Wei Utara — salah satu puncak seni Buddha Tiongkok. Ada arca yang muat di telapak tangan, ada pula yang setinggi gedung; gua-gua ini termasuk Situs Warisan Dunia UNESCO.'),
  'datong/citywall': ('Tembok Kota Ming', 'Dahulu kota garnisun perbatasan, Datong telah membangun kembali tembok era Ming-nya, lengkap dengan gerbang megah dan menara sudut. Berjalan di atas benteng yang diterangi lentera saat senja adalah cara terbaik menikmati atap-atap kota tua dan gemerlap Datong baru dalam satu pandangan.'),
  'datong/noodle': ('Mi Potong', 'Dalam daoxiao mian, kebanggaan Shanxi, sang koki menyandarkan bongkahan adonan di lengannya dan menyerut pita-pita mi dengan pisau langsung ke panci mendidih. Tebal di tepi dan tipis di tengah, mi ini menahan kuah dengan sempurna — hidangan klasik yang tak tergantikan di meja makan Datong.'),
  'datong/lantern': ('Kuil Gantung', 'Tertancap pada tebing Gunung Heng dekat Datong, Kuil Gantung seakan melayang di udara di atas tiang-tiang kayu yang ramping. Berusia sekitar 1.500 tahun, kuil ini juga unik karena alasan lain: ia menaungi Buddhisme, Taoisme, dan Konfusianisme di bawah satu atap.'),
  'baotou/horse': ('Kuda Padang Rumput', 'Nama Baotou dalam bahasa Mongol berarti \'tempat yang memiliki rusa\', dan kota ini berdiri di tepi padang stepa Mongolia Dalam. Di padang rumput sekitarnya, kuda masih menjadi bagian dari kehidupan sehari-hari: para penggembala Mongol menggelar pacuan kuda, dan alunan biola berkepala kuda, morin huur, bergema di antara tenda-tenda yurt.'),
  'baotou/deer': ('Taman Rusa', 'Baotou dijuluki \'Kota Rusa\', dan rusa-rusa yang berkeliaran bebas di taman-taman kotanya menjaga julukan itu tetap hidup. Pengunjung boleh memberi mereka makan langsung dari tangan — pemandangan lembut di tengah padang stepa ini memperlihatkan sisi kota industri yang ternyata begitu ramah.'),
  'baotou/factory': ('Kota Baja', 'Baotou menjadi rumah bagi salah satu produsen baja terbesar di Tiongkok dan menempati posisi istimewa di peta industri berat negeri ini. Berkat cadangan mineral di sekitarnya, kota ini juga dikenal sebagai salah satu pusat unsur tanah jarang terpenting di dunia.'),
  'baotou/grass': ('Wisata Padang Rumput', 'Perjalanan singkat dari kota membawa kita ke padang rumput yang membentang hingga cakrawala. Para tamu menginap di tenda yurt dan disambut dengan teh susu serta daging domba panggang; di malam hari, lagu-lagu Mongolia mengalun di sekitar api unggun. Keramahan padang stepa di sini adalah tradisi yang berusia berabad-abad.'),
  'weifang/kite': ('Ibu Kota Layang-layang', 'Weifang, yang dianggap sebagai tanah kelahiran layang-layang, telah menekuni kerajinan ini selama berabad-abad dengan rangka bambu dan sutra yang dilukis tangan. Setiap April, Festival Layang-Layang Internasional Weifang mengubah langit menjadi pesta warna dengan layang-layang yang datang dari seluruh dunia.'),
  'weifang/woodprint': ('Seni Cetak Kayu Yangjiabu', 'Desa Yangjiabu di Weifang adalah salah satu pusat paling terkenal dari cetakan kayu warna-warni yang digantung di pintu saat Tahun Baru Imlek. Dewa pintu, bayi gembil, dan simbol kemakmuran dicetak lapis demi lapis dari balok kayu ukiran tangan — kerajinan yang diwariskan turun-temurun.'),
  'weifang/dragon': ('Layang-layang Naga', 'Bintang di langit Weifang adalah layang-layang lipan raksasa berkepala naga: puluhan lingkaran bambu disambung tubuh sutra yang berkelok-kelok sepanjang berpuluh meter di angin. Menerbangkan raksasa seperti ini membutuhkan keahlian dan tenaga satu tim penerbang sekaligus.'),
  'weifang/radish': ('Lobak Weifang', 'Lobak hijau Weifang begitu manis dan berair sehingga warga setempat mengupas dan mengirisnya seperti buah. Pepatah setempat berbunyi \'lobak Weifang lebih enak daripada pir\', menggambarkan kebanggaan pada sayuran sederhana ini — menyuguhkan lobak bersama teh adalah wujud keramahan kota.'),
  'dezhou/chicken': ('Ayam Dezhou', 'Ayam rebus berbumbu khas Dezhou dimasak hingga dagingnya lepas sendiri dari tulangnya; ketenarannya menyebar ke seluruh negeri berkat lokasi kota yang ramai di Terusan Besar dan kemudian jalur kereta. Dilapisi madu, digoreng, lalu direbus perlahan dalam kuah berbumbu, ayam ini dahulu disajikan di meja kekaisaran.'),
  'dezhou/sun': ('Lembah Surya', 'Sebagai investor awal industri tenaga surya, Dezhou menyandang gelar \'Kota Matahari\'; di kampus raksasa Solar Valley-nya, hotel, lampu jalan, dan rumah-rumah semuanya digerakkan matahari. Kota ini menjadi salah satu etalase energi terbarukan paling mencolok di Tiongkok.'),
  'dezhou/grapes': ('Melon dan Anggur', 'Tanah subur dataran Sungai Kuning menjadikan Dezhou negeri buah musim panas: ladang dipenuhi semangka dan para-para sarat dengan tandan anggur. Sepotong semangka dingin dari lapak pinggir jalan adalah jeda klasik di hari musim panas yang terik.'),
  'dezhou/train': ('Pelabuhan Kanal', 'Pada abad-abad ketika Terusan Besar ramai, Dezhou adalah pelabuhan singgah yang sibuk bagi tongkang pengangkut gandum ke utara. Kini kereta api mengambil alih peran terusan itu: berada di jalur Beijing-Shanghai, kota ini tetap menjadi salah satu gerbang transportasi penting di Tiongkok utara.'),
  'xuzhou/stone': ('Relief Batu Dinasti Han', 'Xuzhou, kampung halaman Liu Bang sang pendiri dinasti Han, adalah arsip sejarah yang terukir di atas batu. Relief batu Han yang menghiasi ruang-ruang makam menggambarkan perjamuan, kereta perang, dan makhluk-makhluk mitos, membentangkan kehidupan sehari-hari dua ribu tahun silam bagaikan komik kuno.'),
  'xuzhou/terracotta': ('Pasukan Terakota', 'Lebih kecil daripada pasukan terkenal di Xi\'an, para prajurit terakota era Han ini ditemukan sedang menjaga makam seorang raja Chu. Figur-figur setinggi lutut itu berdiri dalam barisan yang rapi; meski berukuran mini, ketertiban mereka yang khidmat bercerita tentang pasukan yang tetap bertugas bahkan setelah kematian.'),
  'xuzhou/lake': ('Danau Yunlong', 'Dinamai dari \'Naga Awan\', Danau Yunlong adalah cermin air luas yang dikelilingi perbukitan — paru-paru hijau kota ini. Dengan jalur pejalan kaki di tepiannya, kedai teh, dan bukit-bukit berpuncak kuil, warga Xuzhou mengalir ke sini sepanjang hari, dari olahraga pagi hingga jalan-jalan sore.'),
  'xuzhou/skewer': ('Budaya BBQ', 'Xuzhou dengan bangga menyebut dirinya ibu kota barbeku Tiongkok; asap sate kambing yang dipanggang di atas bara menyebar di jalan-jalannya hingga larut malam. Anglo kecil dibawa langsung ke meja dan setiap orang memanggang satenya sendiri — sebuah tradisi meja makan yang riuh dan gembira bersama teman-teman sampai larut.'),
  'zhenjiang/vinegar': ('Cuka Zhenjiang', 'Cuka beras hitam Zhenjiang lahir dari fermentasi beras ketan yang panjang dan sabar; dengan keasaman lembut dan sedikit rasa manis, inilah cuka paling terkenal dalam masakan Tiongkok. Meja pangsit tak lengkap tanpanya — kata warga setempat, aroma cuka melayang di jalan-jalan Zhenjiang.'),
  'zhenjiang/temple': ('Kuil Jinshan', 'Kuil Jinshan di tepi Yangtze menjadi latar adegan paling dramatis dalam Legenda Ular Putih, dongeng rakyat paling dicintai di Tiongkok: di sinilah roh ular Bai Suzhen membanjiri kuil demi cintanya. Pagoda di puncak bukit menghadap megah ke sungai dan kota.'),
  'zhenjiang/pot': ('Mi Tutup Panci', 'Untuk guogai mian khas Zhenjiang, sebuah tutup kayu kecil diapungkan di dalam panci besar yang mendidih; tutup itu mencegah air meluap dan membuat mi matang dengan sempurna. Mi halusnya berpadu dengan cuka lokal dan kuah kecap — inilah cara klasik memulai hari di kota ini.'),
  'zhenjiang/bridge': ('Tepi Sungai Yangtze', 'Zhenjiang adalah kota pelabuhan tua yang berdiri di titik strategis tempat Yangtze bertemu Terusan Besar. Tiga bukitnya di tepi sungai — Jinshan, Beigushan, dan Jiaoshan — menghiasi tepian dengan pagoda, kuil, dan taman jalan kaki, mengubah tepi air menjadi jalur budaya yang hijau.'),
  'jiaxing/zongzi': ('Zongzi', 'Jiaxing adalah ibu kota zongzi — ketan yang dibungkus daun bambu lalu dikukus. Makanan khas Festival Perahu Naga ini dijual di sini sepanjang tahun dengan isian daging babi, pasta kacang, atau kuning telur asin; membuka zongzi yang masih panas adalah upacara kecil yang dimulai dengan harum daunnya.'),
  'jiaxing/boat': ('Perahu Danau Selatan', 'Pada tahun 1921, karena terpaksa meninggalkan Shanghai, kongres pertama Partai Komunis Tiongkok diselesaikan di atas sebuah perahu di Danau Selatan Jiaxing. Replika \'Perahu Merah\' itu kini mengapung di sana; air yang berkabut, pohon dedalu, dan paviliun di pulaunya memberi kunjungan itu nuansa sejarah yang tenang.'),
  'jiaxing/silk': ('Negeri Sutra', 'Selama berabad-abad, kebun murbei dan budaya ulat sutra Jiangnan menghidupi kota-kota kanal Jiaxing. Benang yang ditarik dari kepompong di sini menjelma menjadi selimut, kain, dan sulaman; kelembutan sutra adalah anugerah iklim wilayah yang berair dan sejuk, terbentang dari ladang hingga lemari pakaian.'),
  'jiaxing/canal': ('Kota Air Wuzhen', 'Wuzhen, yang berada dalam lingkup Jiaxing, termasuk kota air Jiangnan yang paling anggun, dengan jembatan batu, rumah bergenteng hitam, dan anak tangga yang turun ke kanal. Saat lentera menyala di senja hari, air berpendar kemerahan; kerajinan lama seperti pewarnaan nila dan wayang kulit masih hidup di lorong-lorong sempitnya.'),
  'lishui/mountains': ('Puncak Hijau', 'Lishui adalah sudut Zhejiang yang paling bergunung-gunung; lembahnya dipenuhi kabut dan punggung bukitnya diselimuti hutan bambu dan pinus. Desa-desa batu yang bertengger di lereng serta terasering padi yang menyentuh awan menyimpan Tiongkok yang lambat dan hijau, jauh dari hiruk pikuk provinsi pesisir ini.'),
  'lishui/camera': ('Surga Fotografi', 'Lembah yang dipenuhi kabut fajar, para petani yang muncul di terasering, dan lautan awan yang berubah bersama cahaya telah menjadikan Lishui tempat ziarah para fotografer. Kota ini dikenal lewat acara fotografi internasionalnya; bidikan paling terkenal menangkap terasering berisi air yang berkilau keemasan saat matahari terbit.'),
  'lishui/mushroom': ('Negeri Jamur', 'Kabupaten Qingyuan di Lishui dianggap sebagai tempat lahirnya budidaya jamur; metode menumbuhkan jamur shiitake pada batang kayu dikembangkan di pegunungan ini berabad-abad silam. Pasar desanya sampai kini masih harum aroma jamur kering, dan dapur setempat berbangga dengan sup serta masakan berkuah dari panen jamur segar.'),
  'lishui/raft': ('Arung Jeram Bambu', 'Sungai Ou berkelok-kelok di antara lembah hijau Lishui; menghanyutkan diri di airnya yang jernih dengan rakit bambu adalah kenikmatan klasik daerah ini. Sementara pengemudi rakit mengarahkan dengan galah panjangnya, desa nelayan, bukit berkabut, dan pemandangan yang mengingatkan pada lukisan tinta Tiongkok silih berganti di sepanjang tepian.'),
  'anqing/opera': ('Opera Huangmei', 'Opera Huangmei tumbuh dari lagu-lagu pemetik teh di pedesaan Anqing menjadi salah satu opera daerah paling dicintai di Tiongkok. Melodinya yang sederhana dan mengalir serta kisah cintanya yang dituturkan dalam bahasa sehari-hari dihafalkan turun-temurun — dan Anqing hingga kini dianggap sebagai ibu kota seni ini.'),
  'anqing/pagoda': ('Pagoda Zhenfeng', 'Menjulang di tepi Yangtze, Pagoda Zhenfeng selama berabad-abad menjadi mercusuar bagi pelaut sungai dan dijuluki \'pagoda pertama Yangtze\'. Menara segi delapan dari era Ming ini menghadiahi pengunjung yang mendaki tingkat-tingkatnya dengan panorama kelokan besar sungai.'),
  'anqing/tea': ('Teh Yuexi', 'Lereng Pegunungan Dabie yang sejuk dan berkabut di belakang Anqing adalah kebun ideal bagi teh hijau yang harum. Di kabupaten Yuexi, pucuk daun muda yang dipetik tangan di musim semi menghasilkan seduhan ringan beraroma bunga — dan di desa-desa pegunungan, panen teh masih menjadi peristiwa terbesar musim itu.'),
  'anqing/sail': ('Gerbang Sungai', 'Anqing, yang namanya berarti \'perayaan damai\', adalah gerbang pelabuhan bersejarah Provinsi Anhui ke Yangtze — suku kata \'An\' dalam nama provinsi itu berasal dari kota ini. Dermaga tepi sungainya dan kampung-kampung tuanya masih menyimpan jejak masa jaya pelabuhannya yang ramai.'),
  'ganzhou/orange': ('Jeruk Navel Gannan', 'Tanah merah Ganzhou dan iklim selatannya yang sejuk menumbuhkan jeruk navel Gannan, yang terhitung sebagai jeruk termanis di Tiongkok. Di musim panen, perbukitan berubah menjadi jingga; buah yang berair dan tanpa biji ini membawa nama kota ke seluruh negeri sebagai sumber kebanggaan.'),
  'ganzhou/house': ('Rumah Hakka', 'Suku Hakka, para pendatang dari utara, membangun rumah-benteng di desa-desa pegunungan Ganzhou; di balik tembok pertahanan yang tebal itu, puluhan keluarga hidup di bawah satu atap. Di dalamnya terdapat halaman bersama, aula leluhur, dan budaya solidaritas erat yang dijaga selama berabad-abad.'),
  'ganzhou/pavilion': ('Paviliun Yugu', 'Paviliun Yugu menghadap titik pertemuan Sungai Zhang dan Gong yang bersatu melahirkan Sungai Gan. Diabadikan dalam bait-bait para penyair dinasti Song, paviliun kayu ini menjalin pemandangan sungai dengan tradisi puisi seribu tahun; di senja hari, inilah sudut kota yang paling syahdu.'),
  'ganzhou/star': ('Long March', 'Pada tahun 1934, Tentara Merah memulai mundur besar-besarannya yang legendaris, yang dikenang sebagai Mars Panjang, dari kabupaten Yudu di Ganzhou. Kisah para prajurit yang menyeberangi sungai sepanjang malam dikenang di sini dengan monumen dan museum; kota ini menandai garis awal salah satu titik balik sejarah Tiongkok modern.'),
  'putian/shrine': ('Kuil Mazu', 'Dewi Mazu, pelindung para pelaut, lahir di Putian; kuil induknya berdiri di Pulau Meizhou dan dianggap sebagai sumber ribuan kuil Mazu di seluruh dunia. Kepercayaan dan adat Mazu terdaftar sebagai warisan budaya takbenda UNESCO; pada hari-hari perayaan, pulau ini dipenuhi asap dupa dan para peziarah.'),
  'putian/lychee': ('Kebun Leci', 'Putian juga dikenal sebagai \'Kota Leci\'; pohon-pohon leci berusia ratusan tahun masih berbuah dan menaungi jalan-jalannya. Buah manis yang memerah saat panen musim panas ini adalah kemewahan selatan yang dipuji dalam puisi klasik; menikmati leci segar dari pohonnya adalah salah satu momen terindah musim panas di Putian.'),
  'putian/shoe': ('Ibu Kota Sepatu', 'Putian adalah salah satu raksasa diam-diam produksi sepatu olahraga dunia; bengkel dan pabriknya menghasilkan jutaan pasang untuk merek-merek besar. Pembuatan sepatu di sini berjalan seperti usaha keluarga — dari pembuat cetakan hingga penjahit, satu rantai keterampilan yang utuh membentuk dapur tersembunyi mode olahraga global.'),
  'putian/wave': ('Pulau Meizhou', 'Pulau Meizhou yang dicapai dengan feri terkenal akan pantai berpasir keemasan, teluk-teluk berbatu, dan festival kuil Mazu-nya. Saat perayaan ulang tahun sang dewi, pulau ini hidup dengan tabuhan genderang dan arak-arakan; di hari-hari lainnya, ia menjadi tempat ziarah dan peristirahatan tepi laut yang tenang berhembus angin.'),
  'mudanjiang/snow': ('Desa Salju Tiongkok', '\'Kota Salju Tiongkok\' dekat Mudanjiang adalah salah satu desa paling bersalju di negeri itu, tempat bantalan salju tebal menggembung di atap dan mengubah rumah-rumah menjadi pondok dongeng. Saat lentera merah menyala di senja hari, lorong-lorong berselimut salju berpendar dengan cahaya yang hangat.'),
  'mudanjiang/lake': ('Danau Jingpo', 'Danau Jingpo, yang terbentuk ketika letusan gunung berapi purba membendung aliran sungai, termasuk danau bendungan vulkanik terbesar di Tiongkok. Airnya tumpah melalui Air Terjun Diaoshuilou, yang terkenal dengan penyelam tebing pemberani di musim panas dan pemandangan beku yang spektakuler di musim dingin.'),
  'mudanjiang/tiger': ('Taman Harimau Siberia', 'Hengdaohezi di kawasan Mudanjiang adalah salah satu pusat terdepan dunia untuk perlindungan dan penangkaran harimau Siberia, kucing terbesar di dunia. Pengunjung menyaksikan harimau berkeliaran di lahan hutan yang luas dari jalur yang terlindung, dan pusat ini menjadi jantung upaya menyelamatkan masa depan spesies langka tersebut.'),
  'mudanjiang/ski': ('Musim Ski', 'Di Mudanjiang, jauh di dalam sabuk salju Tiongkok, musim dingin berlangsung panjang dengan salju yang kering dan melimpah; bukit-bukit berhutan di sekeliling kota dipenuhi pemain ski setiap musim. Rute ski yang dipadukan dengan kunjungan ke Kota Salju menjadikan kawasan ini salah satu pusat wisata musim dingin di timur laut Tiongkok.'),
  'changzhou/dino': ('Taman Dinosaurus', 'Taman Dinosaurus Changzhou, taman bertema dinosaurus paling terkenal di Tiongkok, memadukan museum fosil dengan taman hiburan lengkap dan akrab dijuluki \'Jurassic Park-nya Tiongkok\'. Dengan replika dinosaurus raksasa, wahana air, dan roller coaster, taman ini adalah tujuan nomor satu kota bagi keluarga.'),
  'changzhou/pagoda': ('Pagoda Tianning', 'Pagoda setinggi 153 meter di Kuil Tianning di pusat kota dianggap sebagai pagoda tertinggi di dunia. Menjulang dari pelataran kuil yang berusia lebih dari seribu tahun, lantai teratasnya menghamparkan seluruh Changzhou dan liku-liku Terusan Besar di bawah kakimu.'),
  'changzhou/comb': ('Kerajinan Sisir', 'Sisir Changzhou adalah kerajinan berusia ratusan tahun, dibentuk dari kayu-kayu pilihan seperti boxwood dan eboni melalui puluhan tahap pengerjaan tangan. Dahulu dipersembahkan sebagai hadiah untuk istana kekaisaran, sisir dengan ukiran halus dan lukisan tangan ini tetap menjadi cendera mata paling elegan dari kota ini.'),
  'changzhou/canal': ('Kanal Besar', 'Terusan Besar telah mengalir melalui Changzhou selama berabad-abad, dan kota ini menjadi makmur berkat perdagangan dan industri tenun yang dibawa jalur air itu. Di malam hari kampung-kampung tua di tepiannya bercahaya lentera, dan menyusuri dermaga batunya adalah kenikmatan paling klasik di kota ini.'),
  'shaoxing/wine': ('Anggur Shaoxing', 'Arak beras kuning Shaoxing yang berwarna ambar difermentasi dengan air Danau Jianhu setempat, dihargai baik sebagai minuman maupun bumbu penting dalam masakan Tiongkok. Menurut tradisi kota yang paling anggun, guci arak dikubur saat seorang anak perempuan lahir dan dibuka pada hari pernikahannya.'),
  'shaoxing/bridge': ('Jembatan Batu', 'Di Shaoxing yang berjalin kanal, jalur airnya sesibuk jalan rayanya, dan dengan ratusan jembatan batu berlengkung kota ini dijuluki \'museum jembatan\'. Sebagian jembatannya telah berdiri berabad-abad; lengkungan batunya yang berlumut masih menaungi perahu-perahu yang meluncur di bawahnya.'),
  'shaoxing/pen': ('Tempat Kelahiran Kaligrafi', 'Wang Xizhi, yang dihormati sebagai maestro kaligrafi terbesar, menulis mahakaryanya, Kata Pengantar Paviliun Anggrek, dalam sebuah pertemuan di antara rumpun bambu Shaoxing. Tradisi mengapungkan cangkir arak di sungai kecil sambil menggubah puisi berasal dari hari itu, dan paviliun tersebut tetap menjadi persinggahan suci bagi para pecinta kaligrafi.'),
  'shaoxing/boat': ('Perahu Wupeng', 'Di perahu wupeng bertenda hitam khas Shaoxing, sang pendayung mengayuh dengan kakinya sambil mengemudikan perahu dengan tangan — teknik unik yang diwariskan turun-temurun. Meluncur di bawah jembatan batu di sepanjang kanal sempit, perahu-perahu ini juga berlayar dalam kenangan masa kecil Lu Xun, penulis besar yang dibesarkan kota ini.'),
  'bengbu/shell': ('Pelabuhan Mutiara', 'Nama Bengbu berarti \'dermaga kerang\', dan tepian Sungai Huai ini dahulu termasyhur berkat para pemungut mutiara air tawarnya. Mutiara tetap menjadi lambang kota hingga kini — muncul di mana-mana, dari patung-patung alun-alun hingga lambang resmi kota.'),
  'bengbu/train': ('Gerbang Kereta Api', 'Bengbu tumbuh dari kota kecil menjadi kota besar di titik tempat jalur kereta Tianjin-Pukou menyeberangi Sungai Huai. Gerbang di jalur utara-selatan ini hingga kini terus menghubungkan Anhui utara dengan jaringan transportasi utama negeri itu.'),
  'bengbu/river': ('Sungai Huai', 'Sungai Huai dianggap sebagai garis alami yang membelah Tiongkok menjadi utara dan selatan: gandum tumbuh di utaranya dan padi di selatannya, dan pemanas sentral musim dingin pun berhenti di tepiannya. Bengbu hidup tepat di garis peralihan ini, di antara dua iklim dan dua tradisi kuliner.'),
  'bengbu/blossom': ('Festival Musim Semi', 'Di musim semi, taman-taman di sepanjang Sungai Huai bermekaran, dan warga Bengbu menghabiskan akhir pekan di tepi sungai dengan piknik dan pesta bunga. Taman Zhanggongshan di tepi danau menjadi titik kumpul tersibuk kota saat pohon sakura dan persik berbunga.'),
  'jiujiang/mountain': ('Gunung Lu', 'Menjulang di antara Yangtze dan Danau Poyang, Gunung Lu adalah gunung paling puitis di Tiongkok — puncak berselimut kabut, air terjun, dan dataran tinggi yang sejuk, tercatat dalam daftar Warisan Dunia UNESCO. Dari bait-bait Li Bai tentang air terjunnya hingga vila-vila batu kota Guling di lerengnya, setiap sudutnya menuturkan sebuah cerita.'),
  'jiujiang/tea': ('Teh Yunwu', 'Teh yunwu (\'awan-kabut\'), yang tumbuh di lereng Gunung Lu yang berselimut awan, termasuk teh hijau termasyhur di Tiongkok. Kelembapan gunung dan sinar matahari yang tersaring kabut memberi daunnya aroma segar dan manis; pucuk pertama musim semi dipetik dengan tangan dan dihargai sebagai panen terbaik.'),
  'jiujiang/lake': ('Danau Poyang', 'Poyang, danau air tawar terbesar di Tiongkok, bertemu Yangtze tepat di samping Jiujiang. Airnya pasang dan surut mengikuti musim, dan padang rumput basah yang tersingkap di musim dingin menjamu puluhan ribu burung migran — termasuk bangau Siberia yang langka.'),
  'jiujiang/scroll': ('Kota Puisi', 'Pelabuhan tua di tepi Yangtze ini pernah menyambut nama-nama besar puisi Tiongkok: Bai Juyi menulis \'Nyanyian Pipa\' yang termasyhur di sini, terinspirasi oleh melodi yang didengarnya di sungai. Berdiri di bawah bayang Gunung Lu, Jiujiang termasuk gerbang sungai yang paling sering disebut dalam syair.'),
  'quanzhou/ship': ('Jalur Sutra Maritim', 'Dikenal di dunia abad pertengahan sebagai \'Zayton\', Quanzhou adalah pelabuhan terbesar Jalur Sutra Maritim — Marco Polo menggambarkannya sebagai salah satu pelabuhan tersibuk di bumi. Dengan masjid, kuil, dan gereja yang berdiri berdampingan, warisan kosmopolitan kota ini mengantarkannya ke daftar Warisan Dunia UNESCO.'),
  'quanzhou/mosque': ('Masjid Qingjing', 'Didirikan pada tahun 1009 oleh para saudagar Arab, Masjid Qingjing termasuk masjid tertua yang masih berdiri di Tiongkok. Gerbang granit dan dinding batunya yang terinspirasi arsitektur Timur Tengah menjadi saksi betapa majemuk dan kosmopolitannya pelabuhan Quanzhou di era Jalur Sutra Maritim.'),
  'quanzhou/puppet': ('Seni Wayang Tali', 'Dalam seni marionet Quanzhou, para maestro menghidupkan figur kayu dengan mengendalikan puluhan benang halus sekaligus — boneka-bonekanya bisa menulis kaligrafi atau menghunus pedang dan berduel. Tradisi berusia seribu tahun ini tetap menjadi tamu kehormatan di pesta kuil dan panggung perayaan.'),
  'quanzhou/tea': ('Teh Tieguanyin', 'Kabupaten pegunungan Anxi di Quanzhou adalah tanah kelahiran Tieguanyin, sang \'Dewi Besi\' — teh oolong paling terkenal di dunia. Daunnya yang setengah fermentasi mekar dengan aroma menyerupai anggrek, dan upacara teh gongfu yang diseduh dalam cangkir-cangkir mungil adalah kehidupan sehari-hari itu sendiri di sini.'),
  'shanghai/pearl': ('Menara Oriental Pearl', 'Menjulang di kawasan Lujiazui, Pudong, menara berbola merah muda ini adalah siluet paling terkenal dari Shanghai modern. Dari dek pandang berlantai kaca, Sungai Huangpu dan kawasan Bund di seberangnya terbentang di bawah kaki kita; di malam hari, warna-warni menara berkilauan memantul di air sungai.'),
  'shanghai/bund': ('The Bund', 'Deretan fasad bank dan hotel bersejarah di tepi Sungai Huangpu masih menyimpan kemegahan masa ketika Shanghai menjadi pelabuhan dunia. Saat berjalan-jalan di senja hari, gedung-gedung dagang tua berpilar batu bersinar di satu sisi dan gedung pencakar langit Pudong di sisi lain — dua abad bertemu dalam satu pandangan.'),
  'shanghai/garden': ('Yu Garden', 'Taman klasik peninggalan Dinasti Ming ini, dengan susunan batu karang, kolam, dan jembatan zigzagnya, adalah oase di jantung kota. Pasar di sekelilingnya ramai dengan kedai teh dan lapak jajanan, sementara di balik tembok berhiaskan kepala naga tersimpan seni taman Jiangnan yang halus.'),
  'shanghai/xlb': ('Xiaolongbao', 'Xiaolongbao, pangsit berkulit tipis yang menyimpan kuah kaldu panas di dalamnya, adalah mahakarya masakan Shanghai. Kita menggigit kecil pinggirnya dulu untuk menyeruput kuahnya, lalu mencelupkannya ke cuka hitam berjahe. Setiap pagi, kukusan bambu memenuhi jalan-jalan kota dengan kepulan uap.'),
  'hangzhou/lake': ('Danau Barat', 'Dengan pohon willow, pulau-pulau kecil, dan jembatan melengkungnya, Danau Barat (West Lake) adalah pemandangan yang paling banyak dipuji dalam puisi Tiongkok dan terdaftar sebagai Warisan Dunia UNESCO. Berjalan menyusuri tanggul Su dan Bai telah menjadi kebiasaan selama berabad-abad, dan Jembatan Patah dikisahkan sebagai tempat bertemunya sepasang kekasih dalam legenda Ular Putih.'),
  'hangzhou/tea': ('Teh Longjing', 'Tumbuh di lereng-lereng bukit di sekitar danau, teh hijau \'Sumur Naga\' adalah teh paling terkenal di Tiongkok. Daunnya yang pipih masih dibentuk dengan tangan di atas wajan panas, dan panen awal musim semi dianggap yang paling berharga. Secangkir Longjing di kedai teh desa menyuguhkan jiwa Hangzhou yang sesungguhnya.'),
  'hangzhou/temple': ('Kuil Lingyin', 'Lingyin, yang berarti \'Kuil Peristirahatan Jiwa\', adalah salah satu kuil Buddha tertua di Tiongkok. Di seberangnya, ratusan figur Buddha dipahat pada bebatuan Puncak Feilai selama berabad-abad. Berjalan di antara asap dupa dan keteduhan pohon pinus membuat kita lupa akan hiruk-pikuk kota.'),
  'hangzhou/silk': ('Kota Sutra', 'Sutra Hangzhou telah ditenun selama lebih dari seribu tahun, dan kota ini dulu menjadi lambang kemakmuran di ujung timur Jalur Sutra. Kini kain, syal, dan sulaman berpindah tangan di pasar sutranya, sementara museum sutra menceritakan perjalanan dari kepompong hingga alat tenun. Dengan teksturnya yang lembut, sutra Hangzhou tetap menjadi hadiah yang paling elegan.'),
  'chongqing/hongya': ('Gua Hongya', 'Hongya, kompleks rumah panggung tradisional yang menempel di tebing curam, menjaga arsitektur tua kota pegunungan ini tetap hidup. Ketika teras-terasnya yang bertingkat menyala di malam hari, bangunan ini berpendar bagai negeri dongeng di tepi Sungai Jialing, dan lorong-lorong sempitnya penuh dengan jajanan lokal serta toko kerajinan tangan.'),
  'chongqing/hotpot': ('Hotpot Chongqing', 'Mendidih dengan minyak merah membara dan merica Sichuan yang membuat lidah kesemutan, hotpot adalah jiwa Chongqing yang berapi-api. Menurut legenda, hidangan ini lahir dari kuali para kuli angkut yang bekerja di dermaga sungai. Setiap suapan yang dicelupkan ke kuali bersekat sembilan di tengah meja berubah menjadi obrolan panjang bersama sahabat.'),
  'chongqing/monorail': ('Monorel Pegunungan', 'Di Chongqing yang berbukit-bukit, jalur metro melintasi lembah-lembah, bahkan di salah satu stasiun keretanya melaju tepat menembus sebuah gedung apartemen. Pemandangan itu kini menjadi ikon kota. Dengan tanjakan, lift, dan jembatannya, \'kota pegunungan\' ini menantang logika datar peta.'),
  'chongqing/river': ('Ngarai Yangtze', 'Kota ini berdiri di titik pertemuan Sungai Yangtze dan Sungai Jialing; pelayaran wisata Tiga Ngarai berangkat dari dermaga Chaotianmen. Saat kapal meluncur di antara tebing-tebing terjal, ribuan tahun kisah perdagangan dan puisi yang dibawa sungai terbesar Tiongkok mengalir di depan mata kita.'),
  'dalian/square': ('Alun-alun Xinghai', 'Terbuka ke arah laut, Xinghai adalah salah satu alun-alun kota terbesar di dunia, dan namanya berarti \'lautan bintang\'. Layang-layang beterbangan di atas hamparan rumputnya yang luas dan para pesepeda meluncur di jalur pantai pada sore hari; saat musim festival, alun-alun ini dipenuhi konser dan pertunjukan.'),
  'dalian/beach': ('Pantai Dalian', 'Dengan teluk berbatu, pantai yang bersih, dan musim panas yang sejuk, Dalian adalah tujuan wisata pantai favorit di Tiongkok utara. Jalan Binhai yang berkelok di sepanjang pesisir menyuguhkan pemandangan menakjubkan di antara tebing dan teluk. Ketika udara panas menyengat, warga utara datang ke sini untuk menghirup kesegaran laut.'),
  'dalian/football': ('Kota Sepak Bola', 'Dalian disebut sebagai \'buaian sepak bola\' Tiongkok; klub-klub juara yang mendominasi liga nasional dan banyak pemain tim nasional lahir dari kota ini. Anak-anak yang mengejar bola di taman-taman tepi laut meneruskan tradisi itu, dan pada hari pertandingan seluruh kota berubah menjadi satu tribun yang berdebar.'),
  'dalian/seafood': ('Hidangan Laut', 'Laut Kuning yang dingin dan jernih memasok kerang scallop, udang, bulu babi, dan teripang ke meja makan Dalian. Di restoran-restoran tepi pantai, kita memilih sendiri hasil laut dari akuarium dan dalam hitungan menit hidangan itu sudah dikukus. Sementara itu, aroma cumi panggang adalah jiwa pasar malam kota ini.'),
  'shenyang/palace': ('Istana Mukden', 'Dibangun oleh para pendiri Dinasti Qing, Istana Mukden adalah istana pertama mereka sebelum kerajaan pindah ke Beijing. Sering disebut adik kecil Kota Terlarang, istana ini punya karakter tersendiri dengan aula-aula segi delapan bergaya Manchu — kini menjadi museum yang terdaftar sebagai Warisan Dunia UNESCO.'),
  'shenyang/tomb': ('Makam Qing', 'Makam Timur dan Makam Utara yang mengelilingi kota adalah mausoleum monumental para penguasa pendiri Dinasti Qing dan terdaftar sebagai Warisan Dunia UNESCO. Jalan suci berhias patung-patung hewan dari batu membelah hutan pinus tua, dan pada musim gugur taman makam ini berubah keemasan.'),
  'shenyang/factory': ('Pusat Industri', 'Sebagian besar industri berat Tiongkok lahir di Shenyang, dan pabrik-pabrik mesinnya yang raksasa membuat kota ini dijuluki \'Ruhr dari Timur\'. Bengkel-bengkel tua di distrik Tiexi kini berubah menjadi museum dan ruang seni, tetapi kebanggaan generasi yang pernah bekerja di depan mesin bubut masih terasa di udara.'),
  'shenyang/dumpling': ('Pangsit Laobian', 'Dibuat sejak era Dinasti Qing, pangsit kukus Laobian adalah hidangan khas meja makan Tiongkok utara. Isiannya dimasak terlebih dahulu agar meresap kaldunya sendiri, sehingga pangsit ini memiliki kelembutan yang tiada duanya. Sekeranjang pangsit di salah satu restoran tua kota ini hampir menjadi sambutan resmi bagi siapa pun yang datang ke Shenyang.'),
  'hefei/judge': ('Kuil Bao Zheng', 'Bao Zheng, hakim legendaris Dinasti Song, lahir di Hefei; rakyat menyebutnya \'Bao Qingtian\', langit yang tak bernoda. Keadilannya yang tak dapat disuap menginspirasi banyak opera dan drama televisi. Taman peringatannya di tepi danau terasa bagai kuil yang dipersembahkan bagi kejujuran.'),
  'hefei/science': ('Kota Sains', 'Hefei adalah kota ilmu pengetahuan yang menjadi rumah bagi sejumlah universitas dan laboratorium terkemuka di Tiongkok. Berbagai proyek, mulai dari eksperimen fusi hingga riset kuantum, dijalankan di sini; kampus dan taman teknologinya memberi kota ini jiwa yang muda dan penuh rasa ingin tahu.'),
  'hefei/lake': ('Danau Chaohu', 'Chaohu adalah salah satu dari lima danau air tawar terbesar di Tiongkok dan terbentang tepat di selatan Hefei. Ikan perak, udang putih, dan kepitingnya dikenal sebagai \'tiga harta karun\' danau ini. Di kota-kota kecil di tepiannya, perahu nelayan dan kedai teh berpemandangan danau menyuguhkan irama hidup yang tenang.'),
  'hefei/cake': ('Kue Wijen Lu', 'Nama lama Hefei adalah Luzhou, dan kue wijen berisi manis adalah suguhan berusia ratusan tahun yang membawa nama itu. Aroma wijen panggang berpadu dengan isian lembut di balik kulitnya yang renyah. Saat hari raya, kue ini selalu menempati tempat terhormat dalam kotak-kotak hadiah.'),
  'foshan/wingchun': ('Wing Chun', 'Seni bela diri Wing Chun mencapai kematangannya di Foshan; guru legendaris Ip Man berlatih di sini, dan melalui muridnya Bruce Lee warisan ini menyebar ke seluruh dunia. Balai peringatan dan sekolah bela diri di kota ini menjaga tradisi tetap hidup — melihat para guru berlatih jurus di taman pada pagi hari adalah pemandangan sehari-hari.'),
  'foshan/lion': ('Barongsai', 'Foshan adalah ibu kota tari singa gaya selatan, dan pahlawan rakyat termasyhur Wong Fei-hung juga berasal dari daerah ini. Saat festival, singa-singa berwarna cerah melompat di atas tiang-tiang tinggi diiringi tabuhan genderang. Membuat kepala singa adalah kerajinan halus yang diwariskan dari generasi ke generasi.'),
  'foshan/ceramic': ('Keramik Shiwan', 'Tungku keramik Shiwan telah menyala tanpa padam selama berabad-abad; tungku Nanfeng adalah salah satu tungku kayu tertua di Tiongkok yang masih beroperasi. Dengan figurin berekspresi hidup dan ornamen atap berglasir, keramik Shiwan bahkan memahkotai atap kuil-kuil di Guangdong.'),
  'foshan/opera': ('Opera Kanton', 'Opera Kanton, seni panggung paling dicintai di Tiongkok selatan, mencapai kematangannya di tanah ini. Dahulu rombongan seniman berkeliling delta Sungai Mutiara dengan \'perahu merah\', tampil dari desa ke desa. Kostum yang megah, akrobatik, dan alunan lagu berbahasa Kanton masih memenuhi gedung-gedung teater hingga kini.'),
  'guiyang/pavilion': ('Paviliun Jiaxiu', 'Berdiri di atas batu karang di tengah Sungai Nanming, Paviliun Jiaxiu yang bertingkat tiga telah menjadi lambang kota sejak era Dinasti Ming. Namanya berarti \'sarjana pertama\', dibangun dengan harapan kota ini melahirkan para cendekiawan yang unggul dalam ujian kekaisaran. Ketika lampu-lampunya memantul di sungai pada malam hari, lahirlah pemandangan paling anggun di Guiyang.'),
  'guiyang/sourfish': ('Sup Ikan Asam', 'Ikan kuah asam adalah hidangan khas Guizhou, berakar pada tradisi fermentasi masyarakat Miao. Ikan air tawar direbus dalam kuah merah menyala yang diasamkan dengan tomat dan fermentasi beras. Perpaduan rasa asam, pedas, dan harum rempahnya sangat cocok dengan iklim pegunungan di selatan.'),
  'guiyang/waterfall': ('Air Terjun Huangguoshu', 'Dapat dicapai dari Guiyang, Huangguoshu adalah salah satu air terjun terbesar di Asia. Kita bisa berjalan melewati Gua Tirai Air di balik tirai air yang menggelegar, dan percikannya melukis pelangi di bawah sinar matahari. Pada musim hujan, gemuruhnya terdengar hingga berkilo-kilometer di sepanjang lembah.'),
  'guiyang/miao': ('Budaya Miao', 'Desa-desa pegunungan Guizhou adalah kampung halaman suku Miao yang terkenal dengan hiasan kepala peraknya. Saat festival, para gadis mengenakan mahkota perak buatan tangan dan busana bersulam, lalu menari melingkar diiringi alunan seruling buluh lusheng. Batik dan sulaman adalah bahasa yang diwariskan dari ibu kepada anak perempuannya.'),
  'changchun/film': ('Kota Film', 'Studio Film Changchun adalah tempat lahirnya sinema Tiongkok baru; selama beberapa generasi, film-film klasik negeri ini dibuat di sini. Karena itulah kota ini dijuluki \'Hollywood dari Timur\'. Lokasi syuting lamanya kini menjadi taman bertema sinema, sementara tradisi festival filmnya terus berlanjut.'),
  'changchun/car': ('Kota Otomotif', 'Truk pertama dan mobil pertama buatan dalam negeri Tiongkok keluar dari pabrik-pabrik Changchun, dan limusin Hongqi yang mengantar para kepala negara juga diproduksi di sini. Gelar \'kota otomobil\' memang pantas disandangnya: dengan pabrik, museum, dan pameran otomotifnya, budaya mobil adalah identitas kota ini.'),
  'changchun/palace': ('Istana Boneka', 'Kaisar terakhir Tiongkok, Puyi, tinggal di istana ini sebagai penguasa boneka pada era Manchukuo. Kini menjadi museum, bangunan ini menceritakan pengawasan dan kesepian di balik aula-aulanya yang megah. Istana ini adalah jendela sunyi menuju gejolak sejarah abad kedua puluh.'),
  'changchun/snow': ('Salju Musim Dingin', 'Musim dingin Changchun yang panjang dan serba putih mengubah kota ini menjadi festival salju. Patung-patung es berpendar dengan lampu warna-warni di malam hari, dan danau berhutan Jingyuetan menyambut para pemain ski dan kereta luncur. Meski udaranya membekukan, musim dingin di sini justru musim paling ceria sepanjang tahun.'),
  'xining/lake': ('Danau Qinghai', 'Danau Qinghai adalah danau terbesar di Tiongkok, terbentang bagai lautan biru kehijauan di tengah dataran tinggi. Pada musim panas, tepiannya diselimuti hamparan bunga kanola kuning keemasan dan burung-burung migran hinggap di pulau-pulaunya. Bersepeda mengelilingi danau ini adalah petualangan dataran tinggi favorit para pelancong.'),
  'xining/monastery': ('Biara Kumbum', 'Kumbum adalah salah satu biara terbesar dalam Buddhisme Tibet, berdiri di tempat kelahiran Tsongkhapa, pendiri aliran Gelug. Patung-patung berwarna dari mentega yak, lukisan dinding, dan aplikasi kainnya termasyhur sebagai \'tiga seni\'. Di halaman-halamannya, roda doa para peziarah tak pernah berhenti berputar.'),
  'xining/flower': ('Bunga Kanola', 'Ketika bulan Juli tiba, dataran tinggi Qinghai terselimuti bunga kanola kuning keemasan hingga cakrawala. Tepian danau dan kaki-kaki gunung bergelombang dalam seribu nuansa kuning. Di udara dataran tinggi yang sejuk, pemandangan ini menarik para fotografer dan pasangan berbulan madu dari tahun ke tahun.'),
  'xining/lamb': ('Daging Yak dan Domba', 'Meja makan Xining adalah titik temu masakan Hui dan Tibet. Mi tarik tangan disajikan dalam mangkuk yang mengepul, sate domba berderak di atas bara, sementara yoghurt yak dan teh mentega adalah cita rasa sehari-hari dataran tinggi. Di malam hari, pasar-pasarnya dipenuhi aroma rempah.'),
  'guilin/karst': ('Karst Sungai Li', 'Sungai Li berkelok di antara bukit-bukit kapur yang menjulang dari kabut — pemandangan inilah yang tercetak pada uang kertas 20 yuan. Perahu-perahu yang berlayar dari Guilin ke Yangshuo, rakit bambu, dan nelayan burung kormoran menghadirkan lukisan Tiongkok yang hidup.'),
  'guilin/elephant': ('Bukit Belalai Gajah', 'Menyerupai gajah yang mencelupkan belalainya ke Sungai Li, batu karang ini adalah lambang Guilin yang paling dicintai. Lengkungan antara belalai dan badannya memantulkan bayangan bulan purnama di air dan disebut \'Gua Air-Bulan\'. Para penyair telah menuangkan pemandangan ini ke dalam syair selama berabad-abad.'),
  'guilin/terrace': ('Terasering Sawah Longji', 'Membalut punggung-punggung gunung undak demi undak, teras Longji atau \'Tulang Punggung Naga\' adalah buah kerja keras suku Zhuang dan Yao selama berabad-abad. Pada musim semi, teras-teras yang terisi air berkilau bagai cermin; pada musim gugur, semuanya berubah keemasan. Desa-desa kayu di ketinggian masih meneruskan kehidupan tradisional.'),
  'guilin/osmanthus': ('Bunga Osmanthus', 'Nama Guilin berarti \'hutan osmanthus\', dan pada musim gugur kota ini tenggelam dalam wangi manis bunga-bunga mungil itu. Teh, arak, dan manisan osmanthus menempati urutan teratas suguhan khas setempat. Berjalan di bawah pepohonan yang harum di tepi sungai adalah ritual terindah musim ini.'),
  'wenzhou/merchant': ('Semangat Pedagang', 'Warga Wenzhou termasyhur sebagai salah satu komunitas paling berjiwa wirausaha di Tiongkok; melalui jaringan keluarga dan kampung halaman, mereka membangun jembatan dagang dari Eropa hingga Amerika. Sebagai pelopor usaha swasta pada masa reformasi, kota ini penuh kisah yang merentang dari bengkel kecil hingga pasar dunia.'),
  'wenzhou/shoe': ('Sepatu dan Kulit', 'Wenzhou dianggap sebagai ibu kota sepatu dan kulit Tiongkok; sebagian besar sepatu kulit di dunia keluar dari kota pabrik ini. Piawai pula dalam barang-barang kecil dari korek api hingga kacamata, kota ini masih membawa semangat perajin dari era ketika setiap rumah adalah sebuah bengkel.'),
  'wenzhou/mountain': ('Pegunungan Yandang', 'Terkenal dengan air terjun dan puncak-puncaknya yang runcing, Pegunungan Yandang dipuji sebagai \'gunung pertama di atas laut\'. Air Terjun Naga Besar menggelegar jatuh dari tebing, dan saat matahari terbenam siluet beberapa puncaknya seolah berubah bentuk. Pegunungan ini adalah geopark yang dilindungi karena keunikan geologinya.'),
  'wenzhou/seafood': ('Hidangan Laut', 'Menghadap Laut Tiongkok Timur, masakan Wenzhou ringan dan segar; cumi-cumi, kerang scallop, dan ikan menjadi dasar hidangan sehari-hari. Masakan Ou khas setempat membiarkan cita rasa asli hasil laut yang berbicara. Sup bakso ikan yang ditumbuk dengan tangan adalah jajanan kaki lima paling dicintai di kota ini.'),
  'tangshan/memorial': ('Monumen Gempa Bumi', 'Gempa besar tahun 1976 meratakan Tangshan; di taman peringatan yang ada kini, nama-nama para korban terukir pada dinding granit yang panjang. Upacara peringatan digelar setiap tahun di tepi kolam-kolamnya yang hening. Kota yang dibangun kembali ini telah menjadi lambang ketangguhan dan kelahiran kembali.'),
  'tangshan/coal': ('Tambang Batu Bara dan Baja', 'Tambang batu bara modern pertama di Tiongkok dan salah satu jalur kereta api pertamanya dibuka di Tangshan; lokomotif uap pertama negeri ini pun dibuat di sini. Karena itulah kota ini dianggap sebagai buaian industri Tiongkok. Budaya pertambangan dan baja masih terjalin erat dalam identitas kota hingga kini.'),
  'tangshan/ceramic': ('Keramik Tangshan', 'Tangshan dikenal sebagai \'kota porselen dari utara\', termasyhur terutama karena produksi porselen tulang (bone china). Peralatan makan putihnya yang halus dan tembus cahaya menghiasi meja-meja makan di seluruh Tiongkok. Pameran keramik dan bengkel para empu menjaga tradisi ini tetap hidup di kota.'),
  'tangshan/lake': ('Taman Nanhu', 'Nanhu lahir ketika bekas kawasan tambang yang ambles diubah menjadi danau dan taman yang hijau; kini ia menjadi paru-paru hijau kota. Jalur sepeda dan taman bunga membentang di tepiannya, dan taman ini bahkan pernah menjadi tuan rumah pameran hortikultura besar. Nanhu adalah lambang kota industri yang berdamai dengan alam.'),
  'anshan/steel': ('Kota Baja', 'Anshan adalah rumah bagi salah satu pabrik baja terbesar di Tiongkok dan dijuluki \'ibu kota baja\' negeri ini. Selama beberapa generasi, cahaya tanur tinggi menerangi malam-malam kota. Di sini, membuat baja bukan sekadar pekerjaan, melainkan identitas kota itu sendiri.'),
  'anshan/jade': ('Giok Xiuyan', 'Xiuyan, di wilayah Anshan, adalah salah satu negeri giok terpenting di Tiongkok. Istana Buddha Giok di kota ini memamerkan patung Buddha yang termasyhur di dunia, dipahat dari satu bongkahan giok raksasa yang utuh. Bengkel dan pasar gioknya dipenuhi keahlian para perajin yang menghidupkan batu.'),
  'anshan/mountain': ('Gunung Qian', 'Qianshan, yang berarti \'Puncak Seribu Teratai\', adalah gunung suci di timur laut Tiongkok; puncak-puncak granitnya berjajar bagai kelopak bunga teratai. Kuil-kuil Buddha dan Tao tersebar di lereng-lerengnya, dan sebuah batu raksasa termasyhur karena menyerupai sosok Buddha yang sedang duduk. Pada musim semi, gunung ini berselimut bunga.'),
  'anshan/spring': ('Pemandian Air Panas Tanggangzi', 'Kesembuhan telah dicari di mata air panas Tanggangzi selama seribu tahun; dari generasi ke generasi orang berendam di air mineral hangat dan lumpur termalnya yang diyakini meredakan nyeri sendi. Setelah menyambut para penguasa dan tamu termasyhur sepanjang sejarah, pemandian ini tetap menjadi persinggahan bagi mereka yang ingin beristirahat.'),
  'linyi/market': ('Pasar Grosir', 'Linyi adalah pusat perdagangan grosir terbesar di Tiongkok utara; di aula-aula pasarnya yang luas tersedia segalanya, dari jarum hingga perabot rumah. Truk-truk yang berangkat dari sini mengantar barang ke seluruh penjuru negeri. Kesibukan itulah yang membuat kota ini menyandang gelar \'ibu kota logistik\'.'),
  'linyi/brush': ('Master Kaligrafi', 'Wang Xizhi, \'begawan kaligrafi\' Tiongkok, lahir di Linyi; goresan kuasnya yang mengalir telah menjadi teladan selama lebih dari seribu tahun. Kuil peringatan dan festival kaligrafi di kota ini menjaga warisannya tetap hidup. Di Linyi, aroma tinta menjadi penyeimbang yang anggun bagi riuhnya perdagangan.'),
  'linyi/mountain': ('Gunung Meng', 'Mengshan, mutiara pegunungan Yimeng, adalah salah satu gunung tertinggi di Shandong. Hutannya yang lebat, air terjunnya, dan udaranya yang jernih membuatnya dijuluki \'bar oksigen alami\'. Dengan jalur pendakian, desa-desa lereng, dan madu gunungnya, tempat ini menawarkan pelarian yang tenang bagi para pelancong.'),
  'linyi/pancake': ('Pancake Yimeng', 'Serabi tipis dari jagung dan biji-bijian adalah makanan pokok masyarakat pegunungan Yimeng sejak berabad-abad silam. Dimasak di atas lempengan batu panas, serabi ini secara tradisional disantap dengan digulung bersama daun bawang segar. Tahan lama dan mengenyangkan, roti ini menjadi teman setia dalam kerasnya kehidupan desa-desa pegunungan.'),
  'cangzhou/lion': ('Singa Besi', 'Berdiri tegak selama lebih dari seribu tahun, singa raksasa dari besi tuang adalah lencana kebanggaan Cangzhou dan salah satu artefak besi kuno terbesar di Tiongkok. Warga menyebutnya \'auman penakluk laut\', konon dituang untuk membendung air bah. Kota ini merangkul lambangnya bagaikan seorang penjaga.'),
  'cangzhou/martial': ('Seni Bela Diri', 'Cangzhou termasyhur sebagai \'kampung halaman wushu\' Tiongkok; aliran-aliran yang keras dan mematikan seperti bajiquan berkembang di sini. Dahulu, banyak pengawal bersenjata yang melindungi kafilah dagang berasal dari kota ini. Sekolah bela diri dan turnamennya menjaga tradisi itu tetap berdiri tegak hingga kini.'),
  'cangzhou/canal': ('Kanal Besar', 'Terusan Besar yang menghubungkan Beijing dan Hangzhou mengalir tepat melalui Cangzhou, dan selama berabad-abad kota ini makmur berkat perdagangan kanal. Dermaga tua dan kampung-kampung pelabuhannya masih menyimpan jejak masa itu. Taman-taman di sepanjang kanal kini menjadi tempat favorit untuk berjalan-jalan di sore hari.'),
  'cangzhou/jujube': ('Kurma Jujube Emas', 'Jujube \'benang emas\' dari Cangzhou, yang berkulit tipis dan semanis madu, dianggap sebagai raja buah kering. Namanya berasal dari serat-serat manis keemasan yang memanjang dari daging buahnya saat dibelah dua. Kebun-kebunnya memerah saat panen musim gugur, dan teh serta manisan jujube adalah hidangan wajib di meja makan setempat.'),
  'nantong/textile': ('Kota Tekstil', 'Kisah tekstil modern Nantong bermula dari pabrik-pabrik kapas yang didirikan oleh industrialis Zhang Jian. Kini kota ini adalah ibu kota tekstil rumah tangga Tiongkok; seprai hingga tirainya menjangkau pasar-pasar dunia. Budaya menenun juga tetap hidup dalam seni kain cetak biru-putih khas setempat.'),
  'nantong/mountain': ('Gunung Lang', 'Menjulang di tempat Sungai Yangtze bertemu laut, Langshan yang berpuncak lima adalah bukit suci wilayah ini. Para peziarah dan pelancong menaiki anak-anak tangga menuju kuil Buddha berusia ratusan tahun di puncaknya. Dari atas, pertemuan sungai besar itu dengan laut terhampar di bawah kaki kita.'),
  'nantong/kite': ('Layang-layang Bersiul', 'Layang-layang \'banyao\' dari Nantong berdengung di angkasa lewat puluhan peluit kecil yang terpasang pada rangkanya; ketika angin bertiup makin kencang, suaranya mengembang bagai sebuah orkestra. Membuat layang-layang berpeluit ini adalah kerajinan berusia ratusan tahun yang diwariskan turun-temurun dan dipelihara dengan saksama oleh para empu setempat.'),
  'nantong/school': ('Pelopor Pendidikan', 'Industrialis sekaligus pembaharu Zhang Jian mengabdikan kekayaannya untuk kampung halamannya: ia mendirikan sekolah-sekolah modern, perpustakaan, dan museum pertama di Tiongkok yang didirikan oleh warga Tiongkok sendiri. Berkat itu, kota ini menjadi pelopor pendidikan. Cita-citanya \'menyelamatkan bangsa melalui industri\' tetap hidup dalam ingatan warga.'),
  'taizhou/opera': ('Mei Lanfang', 'Akar Mei Lanfang, maestro legendaris opera Peking, terentang hingga ke Taizhou; keanggunan yang ia bawakan pada peran-peran wanita memperkenalkan seni ini ke seluruh dunia. Taman peringatan dan museumnya menuturkan kisah itu melalui kostum dan foto-foto panggung. Alunan opera masih terdengar di taman-taman kota.'),
  'taizhou/tea': ('Teh Pagi', 'Taizhou memulai hari dengan \'zaocha\': bakpao kukus, salad tahu kering yang diiris halus, dan sup bakso ikan tersaji ditemani teh yang pekat. Teh pagi di sini tak pernah terburu-buru — para tetangga berkumpul di kedai teh dan memasuki hari dengan obrolan.'),
  'taizhou/boat': ('Festival Perahu Qintong', 'Setiap musim semi, ratusan perahu berkumpul di lahan basah kota kecil Qintong; para pendayung berlomba diiringi tabuhan genderang, dan buih putih memercik setiap kali galah menghantam air. Festival perahu berusia ratusan tahun ini adalah hari paling meriah dalam budaya kota air dan terdaftar sebagai warisan budaya nasional.'),
  'taizhou/meatball': ('Bakso Kepala Singa', 'Bakso babi yang besar dan sangat lembut bernama \'kepala singa\' adalah hidangan klasik masakan Huaiyang; namanya berasal dari teksturnya yang mengembang menyerupai surai singa. Direbus perlahan berjam-jam dengan api kecil, bakso ini lumer di mulut. Versi yang diperkaya telur kepiting adalah suguhan paling terhormat di meja makan musim gugur.'),
  'jinhua/ham': ('Ham Jinhua', 'Ham Jinhua dimatangkan dengan metode penggaraman dan pengeringan udara yang berusia ratusan tahun; warna merah tua pada irisannya dan aromanya yang dalam menjadikannya ham paling terkenal di Tiongkok. Ham ini paling sering dipakai untuk memperkaya rasa sup dan masakan rebus. Sepotong ham Jinhua yang baik adalah buah kesabaran bertahun-tahun.'),
  'jinhua/film': ('Studio Hengdian', 'Hengdian, di wilayah Jinhua, adalah studio film terbuka terbesar di dunia; di dalamnya berdiri replika raksasa Kota Terlarang dan istana-istana dinasti kuno. Tak terhitung film dan drama sejarah dibuat di sini. Saat berkeliling lokasi syuting, pengunjung bisa saja berpapasan dengan para aktor berkostum lengkap.'),
  'jinhua/cave': ('Gua Shuanglong', 'Memasuki Shuanglong, gua \'Naga Kembar\', adalah pengalaman yang tak terlupakan: pengunjung meluncur masuk dengan perahu sambil berbaring telentang di bawah gerbang batu yang rendah. Di dalamnya terbuka dunia bawah tanah yang sejuk, berhias stalaktit dan stalagmit. Gua ini juga dipuji dalam catatan para pengembara zaman dahulu.'),
  'jinhua/bridge': ('Jembatan Kuno', 'Kawasan sekitar Jinhua, yang dahulu bernama Wuzhou, dipenuhi jembatan batu melengkung dan kota-kota air yang dijalin kanal. Rumah-rumah berdinding putih dan beratap genting hitam berkilau memantul di air, sementara kedai-kedai teh berjajar di ujung jembatan. Pemandangan ini membawa gaya hidup Jiangnan yang anggun hingga ke masa kini.'),
  'wuhu/park': ('Fangte Wonderland', 'Wuhu menjadi rumah bagi gugusan taman hiburan yang termasuk terbesar di Tiongkok, menawarkan hari-hari penuh keseruan bagi keluarga, dari roller coaster hingga dunia animasi. Berkat itu, kota ini tumbuh menjadi ibu kota hiburan kawasan; setiap akhir pekan, pengunjung berdatangan dari provinsi-provinsi tetangga.'),
  'wuhu/ironart': ('Seni Lukis Besi', 'Dalam seni \'lukisan besi\' Wuhu, besi tempa dibentuk menjadi gambar-gambar anggun yang menyerupai goresan kuas; kerajinan berusia sekitar tiga abad ini membawa jiwa lukisan tinta ke dalam logam. Dengan palu dan landasan, para empu menggarap figur gunung, pinus, dan burung. Karya-karya ini adalah hadiah paling khas dari kota ini.'),
  'wuhu/rice': ('Pelabuhan Beras', 'Sepanjang sejarahnya, Wuhu adalah salah satu pasar beras terbesar di Tiongkok; berkat letaknya di tepi Yangtze, hasil panen dari selatan berpindah tangan di sini. Gudang-gudang modern kini menggantikan para kuli yang memikul karung di dermaga, tetapi kota ini tetap bangga akan warisan perdagangan gandumnya.'),
  'wuhu/river': ('Pelabuhan Yangtze', 'Pelabuhannya yang sibuk di tepi Yangtze menjadikan Wuhu gerbang Provinsi Anhui menuju dunia. Kapal barang dan derek kontainer tak pernah berhenti di sepanjang sungai, dan kesibukan itu asyik dipandangi dari taman-taman tepi air. Sungai ini membawa perdagangan sekaligus kesejukan senja bagi kota.'),
  'huangshan/peak': ('Gunung Huangshan', 'Dengan puncak granit, lautan awan, pohon pinus yang meliuk, dan mata air panasnya, Huangshan adalah gunung paling terkenal di Tiongkok dan situs Warisan Dunia UNESCO. Keindahan yang dijuluki \'empat keajaiban\' ini telah mengilhami para pelukis dan penyair selama berabad-abad. Berdiri di atas awan saat matahari terbit adalah kenangan seumur hidup.'),
  'huangshan/village': ('Desa Hongcun', 'Hongcun, desa Hui berdinding putih dan beratap genting hitam yang dijalin saluran air dan kolam berbentuk bulan sabit, tampak bagai keluar dari sebuah lukisan dan terdaftar sebagai Warisan Dunia UNESCO. Tata letak desanya dirancang menyerupai tubuh seekor kerbau. Ketika kabut pagi turun ke danau, para pelukis memasang kanvas mereka di tepiannya.'),
  'huangshan/tea': ('Teh Maofeng', 'Dipetik di lereng-lereng berkabut, Huangshan Maofeng adalah salah satu teh hijau paling terkenal di Tiongkok; namanya berasal dari daunnya yang berbulu halus dan berbentuk puncak gunung. Panen awal musim semi adalah yang paling dihargai. Teh ini meninggalkan aroma anggrek yang lembut di cangkir, seakan awan gunung terjalin dalam daunnya.'),
  'huangshan/ink': ('Tinta dan Seni Huizhou', 'Wilayah Huizhou kuno menghasilkan batang tinta dan batu tinta paling bergengsi di Tiongkok, yang dicari para kaligrafer selama berabad-abad. Rumah-rumah besarnya yang berhias ukiran kayu, bata, dan batu lahir dari semangat kerajinan yang sama. Budaya Hui menyatukan tinta dan arsitektur dalam satu estetika.'),
  'yichun/moon': ('Gunung Mingyue', 'Gunung Mingyue, yang namanya berarti \'Bulan Terang\', adalah lambang Yichun, kota yang juga dikenal dengan festival-festival bertema bulannya. Kereta gantung membawa pengunjung ke jalur-jalur di tepi tebing dan padang rumput pegunungan yang tinggi. Ketika kabut tersibak di puncak, lembah-lembah di bawah berpendar dengan cahaya keperakan.'),
  'yichun/spring': ('Pemandian Air Panas', 'Mata air panas di kota kecil Wentang, Yichun, kaya akan mineral selenium yang langka dan sejak lama diyakini menyembuhkan. Hotel spa dan kolam-kolam terbukanya menyambut pengunjung sepanjang tahun. Perpaduan udara pegunungan dan air yang mengepul hangat menjadikan kota ini salah satu tujuan pemandian air panas favorit di Tiongkok.'),
  'yichun/zen': ('Buddhisme Chan', 'Pegunungan Yichun termasuk tanah tempat lahirnya aliran-aliran penting Buddhisme Chan (Zen) Tiongkok; kuil-kuil berusia ratusan tahun tersebar di lembah-lembahnya yang sunyi. Kebun teh para biksu dan aula meditasinya mengajak pengunjung untuk memperlambat langkah. Dentang lonceng bergema di hutan yang berkabut.'),
  'yichun/rice': ('Dataran Padi', 'Dataran subur Sungai Yuan sejak dahulu menjadi lumbung padi Jiangxi; sawah-sawahnya yang berlimpah air memberikan panen padi yang melimpah tahun demi tahun. Musim panen berlalu bagai pesta di desa-desa. Mi lokal yang dibuat dari beras segar dan arak beras membawa kemurahan dataran ini ke atas meja makan.'),
  'zhangzhou/narcissus': ('Bunga Bakung', 'Umbi bunga narsis paling terkenal di Tiongkok ditanam di Zhangzhou, dan bunga ini adalah hiasan wajib Festival Musim Semi. Para perajin mengukir umbinya dengan sayatan khusus agar bunganya mekar dalam bentuk-bentuk yang anggun. Narsis yang berbunga di rumah saat tahun baru dianggap membawa berkah bagi tahun yang akan datang.'),
  'zhangzhou/tulou': ('Rumah Tanah Hakka', 'Benteng-hunian bundar raksasa dari tanah yang dipadatkan, yang disebut \'tulou\', menaungi satu desa utuh di bawah satu atap dan terdaftar sebagai Warisan Dunia UNESCO. Dindingnya yang tebal memberikan pertahanan sekaligus kesejukan, dan kehidupan bersama terus berlangsung di halamannya selama berabad-abad. Berkelompok di antara bukit-bukit hijau, tulou melukiskan pemandangan bagai dari buku dongeng.'),
  'zhangzhou/banana': ('Buah Tropis', 'Delta Zhangzhou yang hangat dan lembap berbuah sepanjang tahun: kebun pisang, rumpun lengkeng, dan ladang jeruk mandarin membentang hingga cakrawala. Pomelo daerah ini yang besar dan berair juga menjadi primadona meja makan. Apa pun musimnya, pasar buahnya selalu semarak dengan warna dan aroma.'),
  'zhangzhou/coast': ('Pulau Dongshan', 'Dengan pantai berpasir keemasan dan desa-desa nelayannya, Pulau Dongshan adalah mutiara pesisir selatan. Pemandangan paling terkenalnya adalah \'batu goyang angin\' raksasa yang bertengger seimbang di tepi tebing dan konon bergoyang lembut ditiup angin. Di sore hari, perahu-perahu yang pulang ke pelabuhan membawa tangkapan segar hari itu.'),
  'guangzhou/tower': ('Canton Tower', 'Menara yang menjulang di tepi Sungai Mutiara ini dijuluki \'Pinggang Kecil\' karena siluetnya yang ramping dan berpilin. Sebagai salah satu menara tertinggi di dunia, ia berpendar dalam warna-warni yang terus berganti setelah gelap, memahkotai cakrawala modern Guangzhou dengan pemandangan luas ke arah delta.'),
  'guangzhou/dimsum': ('Yum Cha', 'Pagi hari di Guangzhou dimulai dengan \'yum cha\': teh hangat disajikan bersama dim sum yang dikukus dalam keranjang bambu bersusun. Pangsit udang, siu mai, dan kue renyah menemani obrolan yang berlangsung berjam-jam — sebuah ritual yang menjadi jantung budaya kuliner Kanton.'),
  'guangzhou/academy': ('Akademi Klan Chen', 'Dibangun pada akhir era Qing dengan sumbangan keluarga-keluarga bermarga Chen, balai leluhur megah ini memukau dengan ukiran kayu, relief batu, dan figur keramik warna-warni yang memenuhi atapnya. Kini bangunan ini menjadi museum seni rakyat yang memamerkan puncak kerajinan Tiongkok selatan.'),
  'guangzhou/flower': ('Kota Bunga', 'Berkat iklimnya yang sejuk, bunga bermekaran di Guangzhou sepanjang tahun, sehingga sejak dahulu kota ini dijuluki \'Kota Bunga\'. Menjelang Tahun Baru Imlek, pasar bunga raksasa memenuhi jalan-jalan, tempat keluarga membeli pohon kumquat dan ranting bunga persik untuk membawa keberuntungan di tahun baru.'),
  'wuhan/crane': ('Menara Bangau Kuning', 'Menatap Sungai Yangtze, Menara Bangau Kuning menelusuri kisahnya hingga era Tiga Kerajaan dan termasuk menara paling termasyhur di Tiongkok. Diabadikan dalam sajak para penyair seperti Cui Hao dan Li Bai, menara ini berkali-kali hancur dan dibangun kembali, namun jiwa puitisnya tetap terjaga.'),
  'wuhan/noodle': ('Mi Kering Pedas', 'Reganmian, atau \'mi panas-kering\', dibuat dengan mengaduk mi rebus yang kenyal dalam pasta wijen kental bersama acar dan daun bawang. Warga Wuhan memulai hari dengan semangkuk mi dari kios kaki lima; budaya sarapan di kota ini begitu dicintai hingga punya nama sendiri, \'guozao\'.'),
  'wuhan/duckneck': ('Leher Bebek Pedas', 'Leher bebek yang direbus berjam-jam dalam kuah harum berisi cabai dan aneka rempah adalah camilan paling digemari di Wuhan. Dinikmati langsung dari tulangnya, cita rasanya yang pedas dan sedikit membuat lidah kebas menjadi teman setia obrolan tepi sungai dan bir dingin di malam musim panas.'),
  'wuhan/university': ('Bunga Sakura Kampus', 'Setiap musim semi, kampus bersejarah Universitas Wuhan tertutup awan bunga sakura merah muda dan putih, menarik pengunjung dari seluruh Tiongkok. Berpadu dengan gedung-gedung tua di lereng Bukit Luojia, bunga-bunga itu menciptakan pemandangan musim semi paling romantis di kota ini.'),
  'tianjin/eye': ('Tianjin Eye', 'Berdiri tepat di tengah jembatan di atas Sungai Hai, Tianjin Eye adalah salah satu kincir ria langka di dunia yang dibangun langsung di atas air yang mengalir. Dari puncaknya, kedua tepi sungai terhampar sekaligus — fasad bergaya Eropa di satu sisi, menara kaca berkilau di sisi lainnya.'),
  'tianjin/baozi': ('Bakpao Goubuli', 'Dibuat sejak era Qing, bakpao kukus Goubuli terkenal karena kulitnya yang tipis, isian babinya yang berair, dan lipatannya yang rapi. Nama uniknya berarti \'anjing pun tak peduli\' — konon sang pendiri begitu sibuk melipat bakpao hingga tak sempat mengobrol dengan pelanggannya.'),
  'tianjin/crosstalk': ('Komedi Crosstalk', 'Xiangsheng adalah seni panggung tradisional tempat dua pelawak beradu dialog cepat, permainan kata, dan tiruan suara. Berakar di kedai-kedai teh Tianjin, seni ini membuat kota tersebut dijuluki tempat lahirnya komedi Tiongkok, dan hingga kini penonton masih menikmatinya sambil menyeruput teh hangat.'),
  'tianjin/architecture': ('Kawasan Eropa', 'Wudadao, \'Lima Jalan Besar\', menyimpan ratusan vila bergaya Eropa peninggalan era konsesi asing. Dengan gaya Inggris, Prancis, dan Italia yang berdiri berdampingan, kawasan ini membuat Tianjin dijuluki \'museum arsitektur dunia\' — paling nikmat dijelajahi dengan kereta kuda atau sepeda.'),
  'xiamen/island': ('Pulau Gulangyu', 'Di Gulangyu, pulau kecil di lepas pantai Xiamen, kendaraan bermotor dilarang — lorong-lorong sempitnya hanya diisi langkah kaki dan alunan piano. Dengan bekas gedung konsulat dan vila berselimut bugenvil, pulau warisan dunia UNESCO ini adalah museum terbuka yang dicapai dengan feri singkat.'),
  'xiamen/piano': ('Pulau Piano', 'Musik Barat berakar di Gulangyu pada abad kesembilan belas, dibawa oleh para misionaris dan pedagang yang menetap di sana. Terkenal karena jumlah pianonya yang luar biasa banyak per rumah tangga, \'Pulau Piano\' ini menjaga tradisinya lewat sebuah museum piano dan musisi lintas generasi.'),
  'xiamen/egret': ('Bangau Putih', 'Nama lama Xiamen, \'Ludao\', berarti \'pulau kuntul\', dan kuntul putih yang anggun masih melayang di atas pantai dan lagunanya hingga kini. Dijadikan lambang kota, burung ini muncul di mana-mana, dari patung hingga nama jalan, mengingatkan eratnya ikatan Xiamen dengan laut dan alam.'),
  'xiamen/oyster': ('Omelet Tiram', 'Tiram segar diaduk bersama telur dan tepung ubi jalar, lalu digoreng hingga renyah di luar dan lembut di dalam — omelet ini adalah jajanan klasik pesisir Minnan. Disajikan dengan saus manis-pedas di pasar malam Xiamen, hidangan ini juga sangat digemari di Taiwan di seberang selat.'),
  'harbin/ice': ('Festival Es', 'Setiap musim dingin, balok-balok raksasa yang dipotong dari Sungai Songhua yang membeku disusun menjadi istana, menara, dan seluncuran yang berpendar warna-warni setelah gelap. Festival Es dan Salju Harbin, yang terbesar di dunia, mengubah kota yang membeku ini menjadi negeri dongeng bagi jutaan pengunjung.'),
  'harbin/cathedral': ('Katedral Santa Sofia', 'Dengan kubah bawang hijau dan dinding bata merahnya, Katedral Santa Sofia adalah peninggalan termegah dari era kereta api Rusia di Harbin. Kini berfungsi sebagai museum arsitektur, katedral ini menaungi alun-alun yang ramai dengan merpati dan musisi jalanan — titik temu favorit warga kota.'),
  'harbin/sausage': ('Sosis Merah', 'Sosis merah asap, yang pertama kali dibuat menurut resep Rusia yang dibawa para imigran lebih dari seabad lalu, adalah cita rasa khas Harbin. Aroma asap kayu dan rasa bawang putihnya yang lembut sangat cocok dengan roti segar dan bir dingin, menghadirkan akar Eropa kota ini langsung ke meja makan.'),
  'harbin/accordion': ('Kota Musik', 'Biola, akordeon, dan opera tiba bersama para pemukim Rusia, menjadikan Harbin salah satu pusat musik Barat paling awal di Tiongkok. Sebagai rumah bagi orkestra simfoni perintis negeri itu, kota ini menjaga gelar \'kota musik\' lewat festival musik musim panas yang telah berlangsung lama.'),
  'fuzhou/alley': ('Tiga Jalur dan Tujuh Gang', 'Kawasan \'Tiga Lorong dan Tujuh Gang\' melestarikan rumah-rumah berdinding putih dan beratap genting hitam dari era Ming dan Qing. Para cendekiawan dan negarawan pernah tinggal di lorong batunya yang sempit; kini rumah-rumah berhalaman itu diisi kedai teh dan toko kerajinan, menjaga kawasan tua ini tetap hidup.'),
  'fuzhou/banyan': ('Kota Beringin', 'Berkat penanaman pohon yang dimulai pada era Song, jalan-jalan Fuzhou dipenuhi pohon beringin yang masih berdiri berabad-abad kemudian. Akar udaranya menjuntai seperti janggut panjang, memberi naungan sejuk di tengah musim panas yang lembap — itulah mengapa kota ini disayangi dengan julukan \'Rongcheng\', Kota Beringin.'),
  'fuzhou/hotspring': ('Pemandian Air Panas', 'Mata air panas alami menyembur tepat di jantung Fuzhou, menghidupi budaya pemandian yang berusia lebih dari seribu tahun. Warga masih melepas lelah dengan berendam di spa-spa lingkungan mereka, menjadikan Fuzhou salah satu kota langka di Tiongkok yang berdiri tepat di atas harta karun panas bumi.'),
  'fuzhou/soup': ('Buddha Jumps Over the Wall', 'Fotiaoqiang adalah sup legendaris yang merebus puluhan bahan berharga — kerang, jamur, abalone, dan banyak lagi — selama berjam-jam dalam guci tanah liat. Namanya berasal dari sebait syair yang menyebut aromanya begitu menggoda hingga biksu pun rela melompati tembok demi mencicipinya; sup ini tetap menjadi mahkota masakan Fujian.'),
  'dongguan/robot': ('Pabrik Dunia', 'Terletak di jantung Delta Sungai Mutiara, Dongguan adalah raksasa industri yang pabrik-pabriknya menghasilkan porsi besar elektronik dan mainan dunia. Kini lini perakitan padat karya mulai digantikan pabrik pintar dan lengan robot, seiring \'pabrik dunia\' ini memperbarui dirinya untuk era baru.'),
  'dongguan/basketball': ('Kota Bola Basket', 'Bola basket adalah gairah di Dongguan: lapangan ada di hampir setiap lingkungan, dengan jalur pembinaan kuat dari lapangan kampung hingga liga profesional. Guangdong Southern Tigers, salah satu klub tersukses di liga Tiongkok, bermarkas di sini — kota ini resmi dinobatkan sebagai \'kota basket\' Tiongkok.'),
  'dongguan/keyuan': ('Taman Keyuan', 'Dibangun oleh seorang pejabat era Qing, Keyuan terkenal karena kepiawaiannya menata paviliun, kolam, dan koridor berkelok dalam lahan yang sangat ringkas. Termasuk salah satu dari empat taman klasik besar Guangdong, Keyuan menyuling kehalusan seni lanskap Tiongkok selatan.'),
  'dongguan/cannon': ('Benteng Humen', 'Benteng-benteng Humen dahulu menjaga muara Sungai Mutiara dengan deretan meriam. Di pantai inilah pada tahun 1839 Komisaris Lin Zexu memusnahkan candu sitaan, memicu Perang Candu; kini benteng dan museumnya menuturkan titik balik penting dalam sejarah modern Tiongkok.'),
  'lanzhou/beefnoodle': ('Mi Sapi Lanzhou', 'Mi tarik tangan Lanzhou mengikuti resep yang termasyhur: kaldu sapi bening, lobak putih, minyak cabai merah, dan ketumbar hijau segar. Para ahli merentangkan adonan menjadi helai-helai halus dalam hitungan detik di depan mata Anda, dan semangkuk mi hangat di pagi hari adalah ritual harian sekaligus salah satu hidangan paling terkenal di Tiongkok.'),
  'lanzhou/waterwheel': ('Kincir Air', 'Kincir air kayu raksasa, yang pertama kali dibangun pada era Ming untuk mengangkat air Sungai Kuning ke ladang, menjadi simbol abadi Lanzhou. Di taman kincir air tepi sungai, replika setianya masih berputar hingga kini, dengan derit pelannya yang menggemakan berabad-abad kecerdikan irigasi.'),
  'lanzhou/statue': ('Patung Ibu Sungai Kuning', 'Di tepi sungai, patung \'Ibu Sungai Kuning\' menggambarkan seorang ibu berambut tergerai yang tenang mendekap bayi di dadanya. Sang ibu melambangkan sungai yang menyusui peradaban Tiongkok, sementara sang anak mewakili rakyat yang lahir dari airnya — penghormatan paling tulus kota ini kepada sungainya.'),
  'lanzhou/raft': ('Rakit Kulit Domba', 'Rakit dari kulit domba yang digelembungkan dan diikat pada rangka kayu mengangkut barang dan penumpang di Sungai Kuning selama berabad-abad. Kini rakit tradisional ini membawa wisatawan menyusuri tepian Lanzhou, dan mengapung di atas arus berlumpurnya tetap menjadi pengalaman paling otentik di kota ini.'),
  'urumqi/bazaar': ('Grand Bazaar', 'Grand Bazaar Urumqi, dengan menara bergaya Islam dan aula berkubahnya, menjaga semangat perdagangan Jalur Sutra tetap hidup. Kios-kiosnya melimpah dengan buah kering, rempah, sutra, dan pisau buatan tangan, dan di malam hari alun-alunnya semarak dengan pertunjukan musik dan tari.'),
  'urumqi/tianshan': ('Danau Surgawi', 'Tianchi, \'Danau Surgawi\', terhampar di bawah Puncak Bogda yang bersalju di pegunungan Tianshan, dengan airnya yang biru pekat dibingkai hutan cemara. Legenda menyebutnya sebagai tempat perjamuan Ratu Ibunda dari Barat, dan danau ini merupakan bagian dari pegunungan Tianshan yang terdaftar sebagai warisan dunia UNESCO.'),
  'urumqi/kebab': ('Kebab Domba', 'Tusukan daging domba yang mendesis di atas bara arang ditaburi jintan dan bubuk cabai, aroma asapnya menyebar ke seluruh jalanan Urumqi. Sebagai ikon masakan Uighur, kebab paling nikmat disantap di pasar malam bersama naan hangat dari tandur dan teh pekat berteko-teko.'),
  'urumqi/dance': ('Tarian Uighur', 'Tarian Uighur, berputar mengikuti tabuhan gendang dan petikan rawap serta dutar, menjadi mahkota setiap pernikahan dan perayaan. Dengan gerak tangan yang anggun dan putaran yang kian cepat, tarian ini adalah seni kebersamaan yang penuh suka cita — para tamu selalu ditarik ke dalam lingkaran untuk ikut menari.'),
  'haikou/coconut': ('Kota Kelapa', 'Di Haikou, ibu kota Pulau Hainan, jalan-jalan besarnya dinaungi barisan pohon kelapa — karena itulah kota ini dijuluki \'Yecheng\', Kota Kelapa. Pedagang kaki lima membelah kelapa dingin dengan sekali ayunan parang, menawarkan obat paling alami untuk panasnya udara tropis.'),
  'haikou/arcade': ('Arkade Qilou', 'Jalan-jalan dagang tua Haikou berjajar dengan \'qilou\' — ruko berarkade yang dibangun para pedagang yang pulang dari Asia Tenggara. Lorong beratapnya melindungi pembeli dari hujan tropis dan terik matahari, sebuah arsitektur naungan yang anggun dan telah melayani kota ini selama sekitar satu abad.'),
  'haikou/crater': ('Kawah Vulkanik', 'Tepat di luar Haikou, lapangan vulkanik purba telah menjadi geopark hijau berisi kawah mati dan terowongan lava. Batu basal sisa letusan zaman dahulu masih mewarnai kehidupan setempat — rumah desa dan pagar ladang dibangun darinya — dan pengunjung bisa berjalan turun langsung ke mulut kawah.'),
  'haikou/turtle': ('Laut Tropis', 'Perairan hangat dan jernih di lepas pantai Hainan menaungi terumbu karang dan padang lamun yang kaya kehidupan. Penyu laut mencari makan dan bertelur di pantai-pantai ini, dan berkat proyek konservasi, tukik-tukik yang berlarian menuju ombak kembali menjadi pemandangan yang penuh harapan.'),
  'luoyang/grotto': ('Gua Longmen', 'Terpahat di tebing yang mengapit Sungai Yi, Gua Longmen menyimpan puluhan ribu patung Buddha dan terdaftar sebagai warisan dunia UNESCO. Dimulai pada era Wei Utara dan mencapai puncaknya di masa Tang, pahatan-pahatan itu berpuncak pada Buddha Vairocana raksasa dengan senyumnya yang teduh.'),
  'luoyang/peony': ('Ibu Kota Peony', 'Luoyang telah identik dengan bunga peoni sejak era Tang; legenda mengisahkan bunga ini dibuang ke sini karena menolak perintah Maharani Wu Zetian untuk mekar di musim dingin. Setiap April kota ini meledak dalam warna pada festival peoninya, merayakan bunga yang dinobatkan tradisi sebagai \'raja segala bunga\'.'),
  'luoyang/whitehorse': ('Kuil Kuda Putih', 'Didirikan pada tahun 68 Masehi, Kuil Kuda Putih dihormati sebagai kuil Buddha pertama di Tiongkok. Namanya mengenang kuda putih yang konon membawa kitab suci dari India. Sebagai simbol masuknya agama Buddha ke negeri ini, kuil tersebut hingga kini tetap menjadi tempat ibadah dan ziarah yang aktif.'),
  'luoyang/capital': ('Ibu Kota Kuno', 'Luoyang pernah menjadi ibu kota bagi tiga belas dinasti, termasuk Han dan Tang, menempatkannya di pusat sejarah Tiongkok. Kota kuno di lembah Sungai Kuning ini adalah salah satu ujung timur Jalur Sutra, dan museum serta reruntuhannya menjaga ingatan kekaisaran selama ribuan tahun.'),
  'shantou/gongfutea': ('Teh Gongfu', 'Teh gongfu dari kawasan Chaoshan adalah seni menyeduh yang penuh upacara: cangkir-cangkir mungil diisi, dikosongkan, dan diisi kembali dalam putaran yang cermat. Menyuguhkan teh di sini adalah ungkapan hormat yang paling dalam, dan tatanan tiga cangkir beserta gerak tangannya yang halus diwariskan dari generasi ke generasi.'),
  'shantou/beefpot': ('Hotpot Daging Sapi', 'Hotpot daging sapi Chaoshan termasyhur karena pengabdiannya pada kesegaran: daging yang dipotong hari itu juga dipilah menurut bagiannya dan dicelupkan ke kaldu bening hanya beberapa detik. Setiap irisan punya waktu masak yang persis, dan dagingnya dicocol saus sate kacang yang gurih hingga rasa manis alaminya bersinar.'),
  'shantou/opera': ('Opera Teochew', 'Dengan sejarah yang merentang berabad-abad, opera Teochew memikat penonton lewat melodi halus yang dinyanyikan dalam dialek setempat dan kostum bersulam yang memukau. Dibawa merantau oleh para perantau Chaoshan, seni panggung ini menyebar ke seluruh Asia Tenggara dan tetap mengikat komunitasnya pada akarnya.'),
  'shantou/harbor': ('Pelabuhan Shantou', 'Dibuka untuk perdagangan luar negeri pada abad kesembilan belas, pelabuhan Shantou menjadi gerbang bagi tak terhitung orang Chaoshan yang merantau ke seberang lautan. Banyak keluarga Tionghoa di Asia Tenggara menelusuri akarnya ke sini, ikatan yang diabadikan dalam surat \'qiaopi\' yang dahulu dikirim para perantau ke kampung halaman.'),
  'baoding/mansion': ('Kediaman Gubernur', 'Kediaman Gubernur Zhili adalah pusat kekuasaan para raja muda yang memerintah Zhili, provinsi yang mengelilingi ibu kota kekaisaran, pada era Qing. Tokoh-tokoh berpengaruh seperti Li Hongzhang dan Yuan Shikai pernah bertugas di sini, dan halaman-halamannya yang terawat baik menjadi dokumen hidup pemerintahan provinsi kekaisaran.'),
  'baoding/donkeyburger': ('Burger Keledai', '\'Lurou huoshao\' mengisi roti pipih yang renyah dan baru keluar dari tungku dengan daging keledai berbumbu yang dimasak perlahan. Dipuji dalam pepatah setempat — \'daging naga di langit, daging keledai di bumi\' — hidangan ini adalah jajanan kaki lima paling terkenal di Baoding sekaligus kebanggaan daerahnya.'),
  'baoding/balls': ('Bola Kesehatan', 'Bola kesehatan Baoding, yang diputar-putar di telapak tangan, adalah alat latihan tangan tradisional yang dibuat sejak era Ming. Lempengan bunyi di dalamnya menghasilkan dua nada — satu tinggi, satu rendah — saat berputar, dan latihan rutin diyakini memelihara kelenturan jari sekaligus ketenangan pikiran.'),
  'baoding/reeds': ('Rawa Baiyangdian', 'Baiyangdian, salah satu lahan basah terbesar di Tiongkok utara, adalah labirin ratusan kolam yang terhubung kanal-kanal berpagar gelagah. Bunga teratai mekar memenuhi air di musim panas sementara rumpun gelagah riuh dengan kicau burung, dan warga desa masih memancing serta memanen gelagah dari perahu ramping — itulah \'Mutiara dari Utara\'.'),
  'jilin/rime': ('Bunga Es', 'Pada malam musim dingin, kabut yang naik dari Sungai Songhua yang tak membeku mengkristal di dahan-dahan tepi sungai menjadi embun beku putih berkilau. Dikenal sebagai \'wusong\', fenomena ini termasuk empat keajaiban alam besar Tiongkok, dan saat matahari terbit pepohonan berlapis perak itu berkilauan bagai adegan dongeng.'),
  'jilin/snowboard': ('Resor Ski', 'Dengan musim dinginnya yang panjang dan bersalju, Jilin termasuk kawasan olahraga musim dingin terdepan di Tiongkok. Resor-resor modern di pegunungan sekitarnya menarik pemain ski dan snowboard dengan salju bubuknya yang kering, dan daerah ini telah membesarkan banyak atlet pertandingan musim dingin negeri itu.'),
  'jilin/meteorite': ('Museum Meteorit', 'Pada tahun 1976, sebuah meteorit pecah di langit Jilin, menghasilkan salah satu hujan meteorit batu terbesar yang pernah tercatat. Bongkahan utamanya, yang beratnya melebihi satu ton, dipajang di museum meteorit kota, tempat pengunjung dapat bertatap muka langsung dengan tamu dari luar angkasa ini.'),
  'jilin/skate': ('Sungai Songhua Beku', 'Saat musim dingin tiba, bagian-bagian tenang Sungai Songhua membeku tebal dan menjadi gelanggang es terbuka bagi warga kota. Para peseluncur meluncur, gasing es diputar di atas permukaan, dan anak-anak berlomba dengan kereta luncur — di bulan-bulan dingin, tepi sungai adalah tempat berkumpul paling meriah di Jilin.'),
  'ordos/khan': ('Mausoleum Genghis Khan', 'Mausoleum Genghis Khan di padang rumput Ordos menghormati sang khan agung di bawah tiga kubah berbentuk yurt Mongolia. Selama berabad-abad para penjaga Darhad memelihara api upacara dan persembahannya, menjadikan tempat suci ini salah satu situs paling sakral dalam budaya Mongol.'),
  'ordos/cashmere': ('Kasmir', 'Kambing-kambing yang ditempa musim dingin ganas di stepa Ordos menumbuhkan bulu bawah halus yang menghasilkan salah satu kasmir terbaik di dunia. \'Emas lembut\' ini menjadikan kota tersebut pusat produksi kasmir global, mengubah tradisi menggembala menjadi industri mewah yang modern.'),
  'ordos/sanddune': ('Bukit Pasir Bernyanyi', 'Gumuk-gumuk raksasa Gurun Kubuqi mengeluarkan dengung dalam yang bergema saat Anda meluncur menuruni lerengnya — karena itu dinamai \'pasir bernyanyi\'. Pengunjung menyeberangi gumuk dengan kafilah unta atau berselancar di atasnya dengan papan pasir, dan saat matahari terbenam gurun berkilau keemasan dalam keheningan bagai puisi.'),
  'ordos/yurt': ('Yurt Mongolia', 'Yurt Mongolia yang bundar dan berbalut kain kempa putih dirancang untuk bertahan melawan angin stepa namun mudah dilipat untuk perpindahan berikutnya. Pintunya menghadap ke selatan dan perapian di tengahnya adalah jantung kehidupan keluarga; bermalam di sebuah yurt di padang rumput Ordos adalah cara terbaik mencicipi keramahan kaum nomaden.'),
  'jining/confucius': ('Kuil Konfusius', 'Qufu, yang termasuk wilayah Jining, adalah tempat kelahiran sang bijak agung Konfusius. Kuil yang didirikan untuk menghormatinya, kediaman keluarga Kong, dan pemakaman keluarga yang rindang bersama-sama terdaftar sebagai warisan dunia UNESCO; halaman-halaman berpohon cemara dan prasasti kunonya menjadi saksi bisu penghormatan selama lebih dari dua milenium.'),
  'jining/barge': ('Kanal Besar', 'Sebagai pelabuhan sibuk di Kanal Besar yang menghubungkan Beijing dan Hangzhou, Jining berkembang selama berabad-abad berkat tongkang gandum dan lalu lintas pedagang. Perdagangan kanal membawa kemakmuran dan budaya dermaga yang hidup ke kota ini, dan ruas selatan jalur air agung itu masih mengangkut kargo hingga kini.'),
  'jining/sword': ('Pahlawan Liangshan', 'Dalam novel klasik \'Batas Air\' (Water Margin), 108 pahlawan yang dizalimi pejabat korup berkumpul di perbukitan Liangshan yang dikelilingi rawa. Dipimpin Song Jiang, para pendekar itu berjuang membela rakyat kecil melawan kaum berkuasa. Kini Liangshan menyambut pengunjung dengan situs-situs yang menghidupkan kembali adegan legendaris novel tersebut.'),
  'jining/fishnet': ('Danau Weishan', 'Weishan, salah satu danau air tawar terbesar di Tiongkok utara, setiap musim panas terselimuti hamparan teratai yang membentang hingga cakrawala. Keluarga nelayan menebar jala dengan cara yang diwariskan turun-temurun dan hidup mengikuti irama danau, sementara dapur setempat mengagungkan ikan segar dan akar teratai yang renyah.'),
  'langfang/culture': ('Pusat Budaya Jalur Sutra', 'Terletak di antara Beijing dan Tianjin, pusat kebudayaan modern Langfang yang luas menghimpun pameran bertema Jalur Sutra, seni pertunjukan, dan kerajinan tangan di bawah satu atap. Terinspirasi estetika jalur kafilah kuno, bangunan ini melambangkan peran kota sebagai jembatan budaya di antara dua metropolis besar.'),
  'langfang/furniture': ('Kota Mebel', 'Kabupaten Xianghe di Langfang termasuk pusat terbesar di Tiongkok untuk produksi dan perdagangan mebel. Ruang pamer dan bengkelnya membentang berkilometer-kilometer, menawarkan segalanya dari ukiran kayu sonokeling klasik hingga desain modern — banyak keluarga di Tiongkok utara datang ke sini untuk melengkapi rumah mereka.'),
  'langfang/tunnel': ('Terowongan Perang Kuno', 'Di sepanjang perbatasan lama antara dinasti Song dan Liao di utara, jaringan terowongan pertahanan rahasia digali di bawah tanah. Bertahan sekitar seribu tahun, lorong-lorong berlapis bata dengan lubang udara dan ruang penyergapan ini menjadi saksi bawah tanah peperangan perbatasan zaman dahulu.'),
  'langfang/themepark': ('Taman \'Kota No. 1\'', '\'Tianxia Diyi Cheng\', \'Kota Pertama di Bawah Langit\', adalah taman hiburan raksasa yang dengan megah menghidupkan kembali tembok dan gerbang Beijing lama. Dengan pekan raya kuil, pertunjukan tradisional, dan arsitektur klasiknya, taman ini mengajak keluarga berwisata ke masa lalu kekaisaran ibu kota.'),
  'yancheng/salt': ('Kota Garam', 'Nama Yancheng berarti \'kota garam\': selama berabad-abad tambak garam pesisirnya mengisi kas kekaisaran. Garam yang diperoleh dengan menguapkan air laut di bawah matahari menentukan nasib kota ini, dan warisan itu tetap hidup hingga kini di museum, nama tempat, dan kisah-kisah setempat.'),
  'yancheng/crane': ('Bangau Mahkota Merah', 'Lahan basah pesisir Yancheng adalah tempat menetap musim dingin terbesar di dunia bagi bangau mahkota merah liar. Sebagai lambang umur panjang dan keanggunan dalam budaya Tionghoa, burung-burung agung ini bermigrasi ke sini dari utara setiap musim dingin, dan terbang perlahannya di atas rumpun gelagah memukau para pengamat burung.'),
  'yancheng/elk': ('Rusa Père David', 'Rusa milu pernah punah di alam liar Tiongkok dan hanya bertahan di taman-taman di luar negeri. Setelah diperkenalkan kembali ke cagar Dafeng di Yancheng, spesies ini berkembang pesat, dan kini kawanan milu terbesar di dunia berkeliaran bebas di padang basah pesisir ini — sebuah kemenangan konservasi.'),
  'yancheng/wetland': ('Lahan Basah Pesisir', 'Dataran pasang surut di pesisir Laut Kuning membentuk persinggahan raksasa bagi burung migran dan telah ditetapkan sebagai Situs Warisan Dunia UNESCO. Jutaan burung pantai di jalur terbang Asia Timur-Australasia beristirahat dan mencari makan di sini, memenuhi dataran lumpur dengan kepakan sayap setiap musim semi dan gugur.'),
  'huzhou/brush': ('Kuas Hu', 'Kuas Hu buatan Huzhou adalah kuas tulis Tiongkok yang paling dihormati, salah satu dari \'empat pusaka ruang belajar\'. Ujungnya dari bulu kambing, kelinci, dan musang melewati puluhan tahap yang cermat hingga menjadi runcing sekaligus lentur — para kaligrafer menghargainya tanpa batas.'),
  'huzhou/bamboo': ('Hutan Bambu Anji', 'Hutan bambu yang menyelimuti perbukitan Anji bergoyang tertiup angin bagai lautan hijau tanpa tepi. Menjadi latar adegan tak terlupakan dalam film \'Crouching Tiger, Hidden Dragon\', hutan ini menyegarkan pengunjung dengan udara sejuk, jalur pendakian, dan kuliner lokal yang berporos pada rebung muda.'),
  'huzhou/silkworm': ('Ulat Sutra', 'Di pesisir selatan Danau Tai, Huzhou telah menjadi jantung sutra murbei selama ribuan tahun. Sistem tradisionalnya yang memadukan kebun murbei dengan kolam ikan kini diakui sebagai warisan pertanian dunia, dan sutra Huzhou dahulu membalut para kaisar beserta istananya.'),
  'huzhou/whitetea': ('Teh Putih Anji', 'Teh putih Anji sebenarnya adalah teh hijau, dibuat dari kultivar langka yang daun musim seminya tumbuh begitu pucat hingga tampak hampir putih. Dicintai karena kesegarannya yang lembut dan manis dengan rasa sepat yang rendah, masa panennya yang singkat menjadikannya salah satu teh paling diburu di Tiongkok.'),
  'quzhou/go': ('Go (Weiqi)', 'Legenda mengisahkan seorang penebang kayu di Gunung Lanke yang menonton dua dewa bermain Go, begitu terpaku hingga zaman berlalu dan gagang kapaknya lapuk termakan waktu. Berkat kisah ini, Quzhou dihormati sebagai tanah suci permainan Go, dan permainan strategi kuno itu dirayakan dengan meriah di seluruh kota.'),
  'quzhou/peaks': ('Gunung Jianglang', 'Tiga pilar batu raksasa Gunung Jianglang menjulang tegak dari hutan hijau menuju langit. Sebagai contoh menawan bentang alam \'danxia\' dari batu pasir merah, gunung ini terdaftar sebagai warisan dunia UNESCO, dan berjalan menyusuri celah sempit di antara pilar-pilarnya adalah pengalaman yang membuat kepala berputar.'),
  'quzhou/ponkan': ('Jeruk Ponkan Quzhou', 'Jeruk ponkan yang tumbuh di perbukitan sejuk Quzhou terkenal karena kulitnya yang mudah dikupas dan bulir-bulirnya yang manis bagai madu. Di penghujung musim gugur, kebun-kebun berpendar jingga; masa panen mempertemukan keluarga di antara pepohonan, dan buahnya menceriakan meja musim dingin di seluruh wilayah.'),
  'quzhou/cake': ('Roti Wijen Panggang', 'Roti pipih panggang khas Quzhou dibuat dengan menempelkan adonan beragi ke dinding dalam tungku tong yang membara. Di balik kulitnya yang renyah bertabur wijen tersembunyi isian gurih, dan antrean pagi di depan pemanggang menunjukkan betapa warga mencintai awal hari yang satu ini.'),
  'huainan/tofu': ('Tempat Kelahiran Tahu', 'Legenda menyebut para alkemis Pangeran Liu An di Gunung Bagong sebagai pencipta tahu pada masa dinasti Han, ketika susu kedelai pertama kali digumpalkan. Ditemukan di sini sekitar dua ribu tahun lalu, makanan sederhana ini menyebar ke dapur seluruh dunia, dan Huainan merayakan warisannya dengan festival tahu setiap tahun.'),
  'huainan/coalmine': ('Kota Batu Bara', 'Dibangun di atas lapisan batu bara yang kaya, Huainan telah lama menjadi basis energi Tiongkok timur. Tambang dan pembangkit listriknya memasok jaringan regional, sementara kota ini kian giat mengubah bekas lahan tambang menjadi danau dan taman, mengarahkan warisan industrinya menuju masa depan yang lebih hijau.'),
  'huainan/oldtown': ('Kota Tua Shou', 'Kota tua di Kabupaten Shou adalah salah satu dari sedikit kota di Tiongkok yang tembok era Song-nya masih utuh sepenuhnya. Benteng bata yang tebal dan gerbang berlengkungnya bahkan pernah melindungi kota dari banjir, dan jalan-jalan di dalamnya menyimpan jejak negara kuno Chu, yang mendirikan ibu kota terakhirnya di sini.'),
  'huainan/classic': ('Huainanzi', 'Huainanzi adalah karya klasik filsafat yang disusun para cendekiawan yang berkumpul di istana Liu An, Pangeran Huainan, pada era Han. Memadukan pemikiran Taois, kosmologi, dan tata negara, karya ini juga melestarikan legenda-legenda tercinta seperti kisah dewi Nüwa yang menambal langit yang runtuh.'),
  'jingdezhen/porcelain': ('Ibu Kota Porselen', 'Jingdezhen telah membakar porselen selama lebih dari seribu tahun, mengirim karya-karya terbaiknya ke istana kekaisaran sebagai pusat tungku resmi. Kaolin, tanah liat utama porselen, mengambil namanya dari desa Gaoling di dekat sini, dan hingga kini kota ini menarik seniman keramik dari seluruh dunia.'),
  'jingdezhen/kiln': ('Tungku Kuno', 'Di situs warisan Tungku Kuno, tungku kayu bakar tradisional dan bengkel kerajinan menjaga teknik-teknik lama tetap hidup. Dari tungku naga di lereng bukit hingga ruang bakar berbentuk telur, pengunjung dapat mengikuti ujian api sang porselen, sementara para ahli membentuk, mengglasir, dan melukis karya di depan mata mereka.'),
  'jingdezhen/bluewhite': ('Porselen Biru Putih', '\'Qinghua\' — motif biru kobalt yang dilukis di bawah glasir porselen putih bersih — adalah tanda tangan Jingdezhen yang mendunia. Disempurnakan pada era Yuan dan Ming, porselen biru-putih ini mengarungi Jalur Sutra dan jalur laut, menjadi buruan para kolektor di istana-istana Eropa.'),
  'jingdezhen/painting': ('Lukisan Porselen', 'Di Jingdezhen, porselen bukan sekadar wadah melainkan kanvas: para ahli melukis lanskap, burung, dan bait-bait puisi dengan kuas terhalus. Teknik seperti lukisan bawah glasir dan enamel atas glasir diwariskan lintas generasi, dan karya bertanda tangan sang ahli dikoleksi layaknya lukisan bernilai tinggi.'),
  'jian/jinggang': ('Pegunungan Jinggang', 'Pegunungan Jinggang yang berselimut kabut adalah tempat berdirinya basis pedesaan pertama revolusi Tiongkok pada tahun 1927. Kini menjadi jantung \'wisata merah\', pegunungan ini menyambut pengunjung dengan situs-situs bersejarah berdampingan dengan air terjun, hutan bambu, dan lautan awan yang bergulung di bawah puncak-puncaknya.'),
  'jian/torch': ('Percikan Revolusi', 'Pepatah \'sepercik api dapat membakar padang rumput\' menggambarkan bagaimana revolusi menyebar dari pegunungan ini ke seluruh negeri. Tugu peringatan, museum, dan markas yang terpelihara di kawasan Jinggang mendokumentasikan perjuangan berat masa itu, dan para pendaki menyusuri jalur bersejarah di tengah panorama pegunungan yang luas.'),
  'jian/academy': ('Akademi Bailuzhou', 'Didirikan pada era Song di sebuah pulau di tengah Sungai Gan, Akademi Bailuzhou mendidik para cendekiawan selama berabad-abad — di antaranya pahlawan nasional Wen Tianxiang. Halaman-halamannya yang tenang, dipeluk sungai dari segala sisi, tetap menjadi kenangan anggun akan tradisi pendidikan klasik Tiongkok.'),
  'jian/pine': ('Pinus Jinggang', 'Pohon-pohon pinus yang berakar di lereng curam Pegunungan Jinggang berdiri kokoh melawan kabut dan angin. Tumbuh dengan mencengkeram batu telanjang, pohon-pohon ini menjadi lambang ketangguhan dan harapan, dan siluetnya yang muncul dari lautan awan saat fajar adalah pemandangan yang tak mudah dilupakan.'),
  'nanping/wuyi': ('Pegunungan Wuyi', 'Pegunungan Wuyi, dengan tebing merah tua, lembah hijau, dan sungai jernih yang berkelok di antaranya, terdaftar sebagai warisan dunia UNESCO untuk alam sekaligus budayanya. Prasasti tebing kuno, kebun teh berundak, dan jejak akademi-akademi Zhu Xi menjalin pegunungan ini ke dalam sejarah pemikiran Tiongkok.'),
  'nanping/rocktea': ('Teh Batu', 'Da Hong Pao, \'Jubah Merah Besar\', adalah mahkota para \'teh batu\' — oolong yang tumbuh di tanah kaya mineral tebing Wuyi. Daun dari perdu induk tua di dinding batunya pernah mencapai harga legendaris, dan aroma panggangnya yang dalam dihormati penuh takzim di dunia teh.'),
  'nanping/bambooraft': ('Rakit Sembilan Kelokan', 'Sungai Sembilan Kelok mengalir menembus tebing merah Pegunungan Wuyi dalam sembilan tikungan besar. Meluncur di atas rakit bambu yang dikayuh galah oleh para pengemudi perahu, pengunjung melewati peti mati perahu kuno yang misterius terselip tinggi di celah batu dan menyaksikan pemandangan yang berganti di setiap kelokan.'),
  'nanping/scholar': ('Zhu Xi', 'Zhu Xi, mahaguru Neo-Konfusianisme, menghabiskan sebagian besar hidupnya di sekitar Pegunungan Wuyi, mendirikan akademi dan membimbing murid-murid di sini. Penafsiran ulangnya atas pemikiran Konfusius membentuk sistem pendidikan dan ujian kekaisaran di Tiongkok serta Asia Timur selama berabad-abad.'),
  'shenzhen/skyscraper': ('Pencakar Langit', 'Empat puluh tahun lalu masih desa nelayan, Shenzhen berubah menjadi hutan pencakar langit setelah ditetapkan sebagai zona ekonomi khusus pertama Tiongkok. Siluet kotanya yang dimahkotai menara Ping An yang menembus awan melambangkan laju era reformasi — orang menyebut \'kecepatan Shenzhen\', lantai-lantai gedung yang tumbuh dalam semalam.'),
  'shenzhen/chip': ('Kota Teknologi', 'Di pasar elektronik Huaqiangbei, cip, papan sirkuit, dan suku cadang drone mengalir dari satu kios ke kios lainnya; raksasa seperti Tencent, Huawei, dan DJI tumbuh besar di kota ini. Di \'Lembah Silikon Tiongkok\', ide berubah menjadi prototipe dalam hitungan hari — Shenzhen adalah ibu kota dunia bagi startup perangkat keras.'),
  'shenzhen/miniature': ('Window of the World', 'Taman hiburan Window of the World mengumpulkan miniatur bangunan-bangunan terkenal dunia, dari Menara Eiffel hingga piramida. Kamu bisa berjalan melintasi benua-benua dalam satu sore; \'Eiffel\' milik taman ini menyala di malam hari, merangkum semangat Shenzhen yang jenaka sekaligus ambisius.'),
  'shenzhen/mangrove': ('Teluk Shenzhen', 'Hutan bakau Teluk Shenzhen yang terhampar di kaki gedung-gedung pencakar langit adalah persinggahan penting bagi burung-burung di jalur migrasinya. Kuntul dan burung pantai mencari makan di dataran lumpur, sementara jalur pejalan di taman pesisirnya menyuguhkan pemandangan langka bagi warga kota: alam dan metropolis berdampingan.'),
  'xian/terracotta': ('Prajurit Terakota', 'Ribuan prajurit terakota yang menjaga makam Kaisar Qin Shi Huang ditemukan secara tak sengaja pada tahun 1974 oleh para petani yang sedang menggali sumur. Wajah setiap prajurit berbeda-beda; pasukan yang berbaris rapi ini memamerkan kekuasaan seorang kaisar yang mencari keabadian, dan sering disebut keajaiban dunia kedelapan.'),
  'xian/citywall': ('Tembok Kota Xi\'an', 'Tembok kota Xi\'an dari era Ming adalah tembok kota yang terawetkan paling utuh di Tiongkok; badannya yang tebal mengelilingi kota tua dalam persegi panjang tanpa putus. Menyewa sepeda dan berkeliling di atasnya adalah pengalaman klasik Xi\'an; dari menara pengawasnya, kota modern dan ibu kota kuno bertemu dalam satu bingkai.'),
  'xian/drumtower': ('Menara Lonceng', 'Menara Lonceng era Ming yang berdiri tepat di pusat kota menandai jantung ibu kota kuno; dahulu loncengnya mengabarkan jam-jam dalam sehari. Bersama Menara Genderang di sebelahnya dan jalan-jalan kuliner Kampung Muslim di belakangnya, ia membentuk alun-alun paling semarak di malam-malam Xi\'an.'),
  'xian/roujiamo': ('Roujiamo', 'Daging berbumbu yang direbus berjam-jam lalu dijejalkan ke dalam roti pipih renyah — itulah sebabnya roujiamo dijuluki \'burger Tiongkok\'. Suapan kuno jajanan kaki lima Shaanxi ini sangat cocok dengan kesibukan ibu kota Jalur Sutra: cukup dipegang satu tangan, dan dalam dua gigitan kamu terhubung dengan tradisi rasa seribu tahun.'),
  'suzhou/garden': ('Taman Klasik Suzhou', 'Taman-taman klasik Suzhou adalah karya keahlian yang menciptakan kembali alam dalam ruang kecil dengan susunan batu karang, kolam, dan paviliun; yang terindah masuk daftar Warisan Dunia UNESCO. Setiap jendela dibingkai bak sebuah lukisan; berjalan di tamannya terasa seperti membuka gulungan lukisan yang berubah di setiap langkah.'),
  'suzhou/watertown': ('Kota Air', 'Dengan kanal-kanalnya, jembatan batu melengkung, dan rumah-rumah berdinding putih, Suzhou dijuluki \'Venesia dari Timur\'. Di lorong-lorong tua seperti Jalan Pingjiang, air mengalir tepat di depan pintu rumah; sambil meluncur dengan perahu, terdengar alunan pipa dan tembang balada lokal dari kedai-kedai teh.'),
  'suzhou/embroidery': ('Sulam Su', 'Sulaman Su adalah kerajinan Suzhou berusia seribu tahun yang dikerjakan di atas sutra dengan benang yang lebih halus dari rambut; para empu terhebatnya mampu menyulam motif berbeda pada dua sisi kain yang sama. Menangkap kilau bulu kucing atau sisik ikan dengan jarum, seni ini menjadi lambang kesabaran dan kehalusan kota.'),
  'suzhou/kunqu': ('Opera Kunqu', 'Kunqu, yang dihormati sebagai induk semua opera Tiongkok, lahir di sekitar Suzhou; ia dikenal lewat melodinya yang mengalir seperti air dan gerak tangan yang anggun. Seni yang masuk daftar warisan budaya takbenda UNESCO ini masih dipentaskan hingga kini di paviliun taman dan panggung-panggung kecil.'),
  'kunming/stoneforest': ('Hutan Batu', 'Pilar-pilar batu kapur raksasa yang dipahat air selama jutaan tahun membentuk labirin bernama Hutan Batu di dekat Kunming. Suku Sani setempat menuturkan bebatuan ini lewat legenda Ashima: gadis cantik yang berubah menjadi batu, yang hingga kini menyapa para pengunjung dalam wujud salah satu pilarnya.'),
  'kunming/springcity': ('Kota Musim Semi', 'Di dataran tinggi Yunnan yang beriklim sejuk, musim dingin terasa lembut dan musim panas terasa segar; itulah sebabnya Kunming dijuluki \'Kota Musim Semi\', tempat bunga tak pernah layu. Kota ini menjadi tuan rumah salah satu pasar bunga terbesar di Asia; buket segar bahkan dijual di sudut-sudut jalannya.'),
  'kunming/seagull': ('Burung Camar Kepala Hitam', 'Setiap musim dingin, ribuan camar berparuh merah datang dari Siberia dan memutihkan tepi danau serta taman-taman kota Kunming. Memberi makan burung-burung itu dari tangan adalah ritual musim dingin kesayangan warga; kembalinya para camar dirayakan di Kunming hampir seperti kabar gembira datangnya sebuah musim.'),
  'kunming/ricenoodle': ('Mi Crossing-Bridge', 'Mi melintasi jembatan adalah hidangan khas Yunnan: kaldu mendidih tiba di meja, lalu mi beras yang tipis dan aneka pelengkap dimasukkan ke mangkuk di depan matamu. Menurut legenda, seorang istri menemukan cara menjaga sup tetap panas ini saat mengantar makanan melintasi jembatan untuk suaminya yang sedang belajar.'),
  'jinan/spring': ('Kota Mata Air', 'Di Jinan, air bawah tanah menyembul ke permukaan tepat di jantung kota; yang paling digemari dari 72 mata airnya yang terkenal adalah Mata Air Baotu yang menyembur-nyembur. Di \'Kota Mata Air\' ini, air jernih mengalir bahkan di lorong-lorong permukiman tua; warganya masih bangga menyeduh teh dengan air mata air.'),
  'jinan/daminglake': ('Danau Daming', 'Danau Daming yang diberi makan oleh mata air kota adalah oase perkotaan yang dikelilingi pohon dedalu dan teratai. Di musim panas, perahu-perahu berlayar di antara hamparan teratai yang mekar; paviliun dan kedai teh di tepi danau meneruskan irama hidup Jinan yang tenang dan anggun, yang telah tercatat dalam sastra.'),
  'jinan/buddhamountain': ('Gunung Seribu Buddha', 'Ratusan figur Buddha dipahat di lereng Gunung Seribu Buddha selama berabad-abad; relief tertuanya berasal dari masa dinasti Sui. Para pengunjung yang mendaki jalur setapaknya dapat melihat patung-patung di ceruk batu sekaligus, dari puncaknya, panorama Jinan sang kota mata air.'),
  'jinan/poet': ('Penyair Li Qingzhao', 'Li Qingzhao, yang dianggap sebagai penyair perempuan terbesar dalam sastra Tiongkok, lahir di kota mata air ini pada masa dinasti Song. Puisi-puisi ci-nya yang halus dan menyayat berbicara tentang cinta, pengasingan, dan kehilangan; aula peringatan di samping Mata Air Baotu menghadirkan kembali dunia bergemericik air tempat bait-baitnya lahir.'),
  'ningbo/library': ('Paviliun Tianyi', 'Didirikan pada masa dinasti Ming, Tianyi Ge adalah perpustakaan pribadi tertua di Asia yang masih berdiri; pendirinya seorang negarawan pencinta buku. Untuk melindungi naskah-naskah langkanya dari lembap dan kebakaran, tempat ini dirancang hampir seperti kuil buku, dengan taman, kolam, dan aturan keluarga yang ketat.'),
  'ningbo/port': ('Pelabuhan Kargo', 'Pelabuhan Ningbo-Zhoushan adalah pelabuhan tersibuk di dunia berdasarkan volume kargo; kapal-kapal kontainer raksasa dan derek-derek menjulang mengubah pantainya menjadi hutan mesin. Riwayat bahari Ningbo terentang jauh ke masa lampau: kota ini adalah salah satu gerbang keberangkatan Jalur Sutra Maritim kuno.'),
  'ningbo/tangyuan': ('Tangyuan', 'Tangyuan gaya Ningbo adalah bola-bola tepung ketan yang licin dengan isian pasta wijen manis; sekali gigit, isian hangatnya mengalir keluar seperti kejutan kecil. Kudapan khas Festival Lentera ini, dengan bentuknya yang bulat, melambangkan keutuhan keluarga dan pertemuan kembali.'),
  'ningbo/seafood': ('Hidangan Laut', 'Menghadap Laut Tiongkok Timur, Ningbo menata mejanya dari laut: ikan kroker kuning, kepiting, dan kerang-kerangan menjadi dasar masakannya. Lidah setempat mengagungkan keseimbangan \'asin-segar\'; kukusan sederhana dan asinan ringan yang tak menutupi cita rasa asli ikan adalah tanda tangan dapur ini.'),
  'shijiazhuang/bridge': ('Jembatan Zhaozhou', 'Dibangun pada masa dinasti Sui oleh ahli teknik Li Chun, Jembatan Zhaozhou adalah jembatan lengkung batu berspandrel terbuka tertua di dunia. Bertahan dari banjir dan gempa selama sekitar 1.400 tahun, lengkungan anggun ini diajarkan di buku-buku pelajaran sebagai mahakarya klasik rekayasa Tiongkok.'),
  'shijiazhuang/clifftemple': ('Gunung Cangyan', 'Di Gunung Cangyan, sebuah kuil yang bertengger di atas jembatan batu yang terentang di antara dua tebing menghadirkan salah satu pemandangan paling memukau di Tiongkok. Dicapai lewat tangga batu curam yang mendaki dari lembah hijau, bangunan ini menjadi latar adegan penutup film \'Crouching Tiger, Hidden Dragon\'.'),
  'shijiazhuang/redbase': ('Basis Xibaipo', 'Desa Xibaipo di dekat Shijiazhuang menjadi markas besar revolusi pada fase akhir perang saudara; rencana pendirian Tiongkok Baru disusun di halaman-halaman rumah tanahnya. Kini desa ini adalah salah satu persinggahan suci \'wisata merah\'; rumah-rumah desanya yang sederhana menjadi saksi keputusan-keputusan besar sejarah.'),
  'shijiazhuang/pharma': ('Kota Farmasi', 'Shijiazhuang adalah salah satu pusat produksi obat terbesar di Tiongkok, dijuluki \'kota obat\' terutama karena antibiotik dan bahan baku farmasinya. Ibu kota provinsi yang muda ini tumbuh sebagai simpul kereta api, dan memadukan identitas industrinya dengan farmasi dan manufaktur modern.'),
  'taiyuan/jincitemple': ('Kuil Jinci', 'Kuil Jinci di pinggiran Taiyuan adalah taman kuil paling anggun di Tiongkok utara, dengan mata air keramat, pohon saru berusia ratusan tahun, dan patung-patung dayang dari dinasti Song. Di Aula Bunda Suci yang terbuat dari kayu, setiap patung memiliki raut wajah yang berbeda — seolah mereka telah berbisik-bisik selama seribu tahun.'),
  'taiyuan/coalcart': ('Negeri Batu Bara', 'Pegunungan Shanxi dijalin urat-urat batu bara, dan sebagian besar energi Tiongkok digali dari sana; Taiyuan adalah ibu kota kekayaan itu. Pertambangan memberi kota ini industri, jalur kereta, dan budaya mesin berat; kini kota berupaya menyeimbangkan warisan batu baranya dengan energi yang lebih bersih.'),
  'taiyuan/vinegar': ('Cuka Hitam', 'Cuka tua matang khas Shanxi dibuat dari fermentasi panjang sorgum dan biji-bijian; warnanya yang pekat dan asamnya yang berasap menjadikannya primadona meja makan. Warga setempat menyiramkan cuka ke hampir semua makanan, dari mi hingga pangsit — di sini cuka bukan sekadar bumbu, melainkan hampir sebuah identitas.'),
  'taiyuan/twinpagoda': ('Pagoda Kembar', 'Dua pagoda Ming segi delapan yang menjulang berdampingan di tenggara kota telah menjadi lambang Taiyuan yang tak berubah selama berabad-abad. Menara-menara bata ini memamerkan kehalusan seni pasangan bata; di musim semi, bunga plum yang mekar di sekelilingnya menyuguhkan momen kunjungan yang paling layak difoto.'),
  'hohhot/lamatemple': ('Kuil Dazhao', 'Didirikan pada era Ming, Kuil Dazhao adalah jantung spiritual Hohhot; harta terbesarnya adalah patung Buddha dari perak. Pusat Buddhisme Tibet di padang stepa ini menawarkan dunia yang sama sekali berbeda dari keriuhan kota, berselimut asap dupa, roda doa, dan lantunan doa bernada rendah.'),
  'hohhot/dairy': ('Ibu Kota Susu', 'Merek-merek susu terbesar Tiongkok lahir di Hohhot; tradisi susu padang stepa di sini tumbuh menjadi industri modern, dan kota ini dijuluki \'ibu kota susu\'. Di meja makan, kelezatan Mongol seperti teh susu, dadih susu kering, dan kepala susu tetap hidup berdampingan dengan produk-produk pabrik.'),
  'hohhot/wrestling': ('Gulat Mongolia', 'Gulat Mongol bökh adalah lomba primadona festival Naadam; para pegulat memasuki arena dengan rompi bersulam sambil menarikan tarian elang. Sang pemenang ditepuktangani bukan hanya karena kekuatan tetapi juga keanggunannya — di padang stepa, gulat bersama berkuda dan memanah terhitung sebagai \'tiga keterampilan lelaki\'.'),
  'hohhot/prairie': ('Padang Rumput', 'Tepat di luar Hohhot, padang rumput Mongol terbentang hingga cakrawala; di padang penggembalaan yang berombak bagai lautan hijau di musim panas, kawanan kuda dan domba merumput. Tamu yang menginap di yurt disambut dengan teh susu dan jamuan daging domba; malam harinya, langit dipenuhi bintang-bintang yang telah lama terlupakan di kota.'),
  'sanya/resortbeach': ('Pantai Tropis', 'Di ujung selatan Pulau Hainan, Sanya adalah ibu kota wisata tropis Tiongkok; pasir selembut bedak dan air toska Teluk Yalong membuatnya dijuluki \'Hawaii-nya Tiongkok\'. Musim panas berlangsung sepanjang tahun di pantainya yang berjajar pohon palem — salah satu dari sedikit pesisir Tiongkok tempat orang bisa berenang bahkan di musim dingin.'),
  'sanya/guanyin': ('Patung Guanyin', 'Patung Guanyin setinggi 108 meter yang menjulang di atas laut di Nanshan termasuk patung dewi tertinggi di dunia. Figur berwajah tiga ini memandang ke daratan, ke laut, dan ke perairan lepas; jalan lintasan menuju kaki sang dewi welas asih menjadi tujuan para peziarah maupun pelancong yang penasaran.'),
  'sanya/diving': ('Menyelam', 'Dengan airnya yang hangat dan sebening kristal, Sanya adalah surga menyelam Tiongkok; terumbu karang di sekitar Pulau Wuzhizhou dipenuhi ikan warna-warni. Pemula menyelam di terumbu dangkal didampingi instruktur; bahkan hanya dengan snorkel pun kamu bisa menikmati taman tropis di bawah permukaan air.'),
  'sanya/coconutdrink': ('Kelapa', 'Di Sanya, kelapa adalah bagian dari kehidupan sehari-hari: di sepanjang pantai, para pedagang membelah buah segar dengan parang dan menyodorkannya bersama sedotan. Air kelapa yang sejuk adalah obat paling alami untuk panas tropis; santannya membumbui masakan ayam dan kudapan manis setempat, sementara tempurungnya menjadi kerajinan tangan.'),
  'yangzhou/slenderlake': ('Danau Slender West', 'Danau Barat Ramping mengambil namanya sebagai penghormatan anggun kepada danau termasyhur di Hangzhou; jalur air yang panjang dan sempit ini dihiasi pohon dedalu, jembatan putih melengkung, dan paviliun. Pemandangan yang dikagumi para kaisar Qing dalam lawatan selatan mereka ini hingga kini tetap seanggun lukisan tinta.'),
  'yangzhou/friedrice': ('Nasi goreng Yangzhou', 'Nasi goreng Yangzhou adalah hidangan klasik keemasan berisi udang, telur, dan daun bawang yang diaduk hingga setiap butirnya terurai; namanya hidup di restoran-restoran Tionghoa di seluruh dunia. Rahasianya terletak pada kesederhanaan: setiap butir nasi terbalut telur, bahan-bahannya segar dan tak pernah berlebihan.'),
  'yangzhou/morningtea': ('Morning tea', 'Di Yangzhou, hari dimulai dengan ritual \'teh pagi\': teh kental disajikan bersama bakpao kukus, kue kering dari adonan yang diiris setipis kertas, dan pangsit berkuah. Di kedai teh tua, sarapan ini berlangsung berjam-jam — terburu-buru menikmatinya nyaris dianggap tidak sopan.'),
  'yangzhou/gegarden': ('Taman Ge', 'Dibangun oleh seorang saudagar garam kaya, Taman Ge berutang nama pada bentuk daun bambu. Daya tarik utamanya adalah susunan batu karang yang menghidupkan empat musim dengan bebatuan berbeda — dalam beberapa langkah kamu berjalan dari musim semi ke musim dingin, menyaksikan puncak seni taman klasik.'),
  'weihai/navalisland': ('Pulau Liugong', 'Pulau Liugong di lepas pantai Weihai adalah pangkalan Armada Beiyang, angkatan laut modern dinasti Qing, yang kalah di sini dalam perang melawan armada Jepang. Dengan museum dan benteng-benteng tuanya, pulau ini kini menuturkan sebuah lembaran yang pahit namun penuh pelajaran dalam sejarah maritim Tiongkok.'),
  'weihai/swan': ('Danau Angsa', 'Setiap musim dingin, ratusan angsa whooper datang dari Siberia dan menjadikan laguna pesisir dekat Weihai rumah mereka. Burung-burung putih yang meluncur di atas air dalam kabut pagi memikat para fotografer dan pencinta alam; warga desa merawat dan memberi makan angsa-angsa itu layaknya tetangga sendiri.'),
  'weihai/seacucumber': ('Teripang', 'Teripang yang dibudidayakan di perairan Weihai yang dingin dan bersih termasuk hidangan laut paling berharga di meja makan Tiongkok. Dianggap sangat bergizi, ia disuguhkan pada acara-acara istimewa dan menjadi hadiah yang dihormati; tambak-tambak di sepanjang pesisir merupakan sumber penghidupan penting bagi kota.'),
  'weihai/cape': ('Tanjung Tiongkok', 'Tanjung Chengshantou di timur Weihai adalah salah satu titik paling timur tempat daratan Tiongkok bertemu laut — matahari menyapa negeri ini pertama kali di sini. Menurut legenda, Kaisar Pertama Qin Shi Huang datang sejauh ini untuk mencari negeri keabadian di seberang ombak; tanjung ini juga disebut \'ujung langit\'.'),
  'handan/taichi': ('Tai Chi', 'Kota bertembok Guangfu di dekat Handan adalah tempat lahirnya gaya Yang dan Wu dalam taijiquan; sang guru legendaris Yang Luchan ditempa di sini. Setiap pagi, para murid yang berlatih gerakan lambat dan mengalir di kaki tembok dan di halaman-halaman rumah menjaga warisan hidup seni bela diri \'lembut\' ini.'),
  'handan/congtai': ('Teras Congtai', 'Teras Congtai adalah peninggalan Kerajaan Zhao yang perkasa dari zaman Negara-Negara Berperang; panggung tinggi tempat para raja menyaksikan upacara dan pertunjukan itu kini berada di jantung sebuah taman. Siapa pun yang menaikinya akan memandang dari atas sejarah Handan yang lebih dari dua ribu tahun sebagai ibu kota kuno.'),
  'handan/idiom': ('Kota Idiom', 'Handan adalah \'kota idiom\': lebih dari 1.500 idiom bahasa Tionghoa berakar pada peristiwa dan kisah dari tanah ini. Yang paling terkenal adalah \'belajar cara berjalan orang Handan\' — tentang seseorang yang meniru orang lain sampai lupa cara berjalannya sendiri — idiom yang mengukir nama kota ini secara abadi dalam bahasa.'),
  'handan/ciporcelain': ('Keramik Cizhou', 'Porselen Cizhou dikenal lewat motif hitam yang disapukan dengan kuas bebas di atas lapisan dasar putih; bunga, ikan, dan bait-bait puisi digoreskan ke wadah dengan ketulusan seni rakyat. Tradisi yang hidup sejak dinasti Song ini berdiri sebagai keramik kehidupan sehari-hari, penyeimbang porselen istana kekaisaran.'),
  'daqing/oilpump': ('Ladang minyak', 'Penemuan ladang minyak Daqing membebaskan Republik Rakyat Tiongkok yang masih muda dari ketergantungan pada minyak impor; kota ini nyaris tumbuh di atas sumur-sumurnya. Pompa-pompa angguk masih perlahan menunduk dan mengangkat kepalanya di padang hingga kini; Daqing tercatat dalam sejarah sebagai ladang minyak terbesar Tiongkok.'),
  'daqing/oilworker': ('Iron Man', 'Pekerja minyak Wang Jinxi mendapat julukan \'Manusia Besi\' berkat kegigihannya membuka sumur di tengah dingin membeku; konon ia pernah melompat ke kubangan lumpur dan mengaduk adonan pengeboran dengan tubuhnya sendiri. Museum yang didirikan atas namanya dan \'semangat Manusia Besi\' menghidupkan legenda berdirinya Daqing.'),
  'daqing/reedlake': ('Lahan basah', 'Di antara sumur-sumur minyak tersembunyi alam yang mengejutkan: danau-danau beralang luas dan lahan basah Daqing menjadi rumah bagi burung jenjang, angsa, dan unggas air yang bermigrasi. Di musim gugur, saat alang-alang keemasan bergoyang ditiup angin, kota industri ini berubah menjadi surga burung.'),
  'daqing/hotspring': ('Pemandian air panas', 'Di sekitar Daqing, air panas kaya mineral yang naik dari kedalaman bumi menawarkan tempat berlindung yang menyembuhkan di musim dingin timur laut yang menggigit. Kabupaten Lindian termasyhur sebagai kota pemandian air panas; berendam di kolam-kolamnya yang beruap adalah jawaban manis atas iklim keras kota minyak ini.'),
  'zibo/bbq': ('Sate Zibo', 'Barbeku Zibo terkenal dengan trionya: anglo arang kecil, sate tipis, dan roti pipih selembut kulit lumpia. Kamu memanggang satemu sendiri, lalu menggulungnya di roti bersama daun bawang segar dan saus; ritual akrab ini menyapu media sosial Tiongkok dan membuat nama kota melejit menjadi sensasi nasional dalam semalam.'),
  'zibo/cuju': ('Cuju', 'Cuju, permainan sepak bola tertua di dunia, dimainkan di Linzi, ibu kota negara kuno Qi — warisan yang diakui FIFA sebagai asal-usul sepak bola. Permainan menimang bola kulit dengan kaki ini punya riwayat yang kaya, terentang dari hiburan istana hingga latihan militer.'),
  'zibo/ceramic': ('Keramik Zibo', 'Tungku-tungku Zibo telah menyala lebih dari seribu tahun; kota ini adalah salah satu pusat keramik paling berakar di Tiongkok utara. Tradisi produksi yang terbentang dari wadah sehari-hari hingga porselen seni kini dihidupkan lewat museum dan bengkel kerja; pameran keramiknya menarik para perajin dari seluruh negeri.'),
  'zibo/glass': ('Liuli', 'Liuli, yang dibentuk dengan tangan dari kaca leleh berwarna, adalah kerajinan Zibo yang bermain dengan cahaya; distrik Boshan termasyhur sebagai pusat historis seni ini. Para perajin menarik dan melengkungkan kaca pijar dengan penjepit; manik-manik, burung, dan vas yang dihasilkan berkilau di bawah matahari bagaikan kaca patri.'),
  'taian/mounttai': ('Gunung Tai', 'Gunung Tai, pemimpin Lima Gunung Suci, adalah puncak paling keramat di Tiongkok; selama berabad-abad para kaisar menggelar upacara persembahan di sini untuk memaklumkan kekuasaan mereka kepada langit. Pada bebatuan gunung warisan UNESCO ini terukir prasasti para penyair dan kaligrafer; setiap batunya adalah selembar halaman sejarah.'),
  'taian/sunrise': ('Matahari Terbit di Puncak', 'Hadiah utama mendaki Gunung Tai adalah menyaksikan matahari terbit di atas lautan awan dari puncaknya. Ribuan orang mendaki sepanjang malam dan menanti fajar di Puncak Kaisar Giok; saat ufuk memerah, sorak gembira yang membubung dari kerumunan seketika menghapus segala kelelahan.'),
  'taian/stonesteps': ('Anak Tangga Batu', 'Sekitar 7.000 anak tangga batu menuju puncak adalah ujian fisik yang telah didaki para peziarah selangkah demi selangkah selama berabad-abad. Bagian tercuram disebut \'Delapan Belas Tikungan Menuju Langit\'; para kuli angkut yang naik-turun tangga ini setiap hari sambil memikul barang adalah pahlawan bisu sang gunung.'),
  'taian/daitemple': ('Kuil Dai', 'Kuil Dai di kaki gunung adalah kompleks megah tempat para kaisar menginap dan mempersiapkan diri sebelum upacara di Gunung Tai. Aula utamanya yang bergaya istana termasyhur karena mural raksasa yang mengisahkan perjalanan dewa Gunung Tai, dan pohon-pohon saru purba di halamannya adalah para saksi sejarah.'),
  'lianyungang/monkey': ('Gunung Huaguo', 'Huaguoshan, Gunung Bunga dan Buah — kampung halaman Raja Kera Sun Wukong dari kisah \'Perjalanan ke Barat\' — menjulang di sini. Gua Tirai Air dimasuki dari balik air terjun, dan monyet-monyet makaka sungguhan yang berkeliaran di bebatuan mengaburkan batas antara legenda dan pemandangan nyata.'),
  'lianyungang/seaport': ('Pelabuhan Laut', 'Lianyungang adalah ujung Pasifik dari jembatan darat kereta api yang membentang melintasi benua Eurasia; kereta-kereta yang dimuat di sini melaju lewat Asia Tengah menuju Eropa. Pelabuhan yang dianggap sebagai gerbang laut timur Jalur Sutra ini terasa bagaikan kelanjutan modern jalur-jalur perdagangan kuno.'),
  'lianyungang/mountain': ('Gunung Yuntai', 'Puncak-puncak terjal Gunung Yuntai menyimpan titik tertinggi Provinsi Jiangsu — pengecualian yang mengejutkan di provinsi yang dikenal dengan dataran rendahnya. Dengan lereng berhutan, kuil-kuil, dan punggung bukit berpemandangan laut, pegunungan ini adalah pelarian kota ke alam.'),
  'lianyungang/crystal': ('Negeri Kristal', 'Kabupaten Donghai di Lianyungang menjadi tuan rumah salah satu pasar kristal kuarsa terbesar di dunia. Kristal-kristal jernih yang digali dari tanahnya dimanfaatkan di segala bidang, dari perhiasan hingga bahan baku industri; kios-kios di pasar kota kecil ini berkilauan dipenuhi batu-batu gemerlap.'),
  'maanshan/libai': ('Penyair Li Bai', 'Li Bai, yang dianggap sebagai penyair terbesar Tiongkok, menghabiskan tahun-tahun terakhirnya di sekitar kota sungai ini; makamnya berada di Dangtu yang tak jauh dari sini. Jejak sang empu yang menyulap anggur, rembulan, dan kebebasan menjadi puisi hidup di taman peringatannya; Ma\'anshan dengan bangga memperkenalkan diri sebagai \'kota puisi\'.'),
  'maanshan/steel': ('Kota Baja', 'Kompleks baja Magang menjadikan Ma\'anshan salah satu basis besi dan baja penting Tiongkok; tanur-tanur tingginya telah berasap di tepi Sungai Yangtze selama puluhan tahun. Kota ini menyeimbangkan identitas industri beratnya dengan masa lalu yang puitis: di satu sisi lelehan baja, di sisi lain bait-bait Li Bai.'),
  'maanshan/rivercliff': ('Tebing Caishiji', 'Tebing Caishiji, dengan tanjungnya yang terjun tegak lurus ke Sungai Yangtze, menyuguhkan salah satu pemandangan paling puitis di sungai itu. Menurut legenda, Li Bai jatuh ke sungai di sini saat hendak memeluk pantulan rembulan di air dan menjadi abadi; paviliun dan jalan setapak di tebing masih membisikkan kisah itu.'),
  'maanshan/moonwine': ('Bulan dan Anggur', 'Dua citra agung dalam bait-bait Li Bai, rembulan dan anggur, masih dirayakan di Ma\'anshan; kota ini menggelar festival puisi untuk mengenangnya. Mengangkat cawan di tepi sungai sambil memandang rembulan adalah cara paling sederhana untuk berbagi rasa yang sama dengan sang penyair dari seribu tahun silam.'),
  'longyan/tulou': ('Tulou Yongding', 'Tulou bundar raksasa yang tersebar di pegunungan Yongding adalah rumah-benteng yang dibangun suku Hakka dari tanah dan kayu, kini Warisan Dunia UNESCO. Di balik tembok tanah yang tebal, puluhan keluarga hidup berdampingan; asap tungku yang membubung dari halamannya membawa aroma kehidupan bersama selama berabad-abad.'),
  'longyan/redmeeting': ('Pertemuan Gutian', 'Pada tahun 1929, Rapat Gutian yang bersejarah, yang menetapkan prinsip dan arah Tentara Merah, digelar di desa pegunungan Longyan ini. Aula pertemuan berdinding putih itu terjaga hingga kini; desa ini menjadi persinggahan bagi mereka yang ingin melihat salah satu titik balik sejarah revolusi.'),
  'longyan/hakka': ('Budaya Hakka', 'Suku Hakka, yang namanya berarti \'keluarga tamu\', memperolehnya dari perjalanan mereka bermigrasi ke selatan dari Tiongkok utara demi menghindari perang. Di pegunungan Longyan mereka telah menjaga bahasa khas mereka, masakan seperti ayam panggang garam, dan ikatan keluarga yang kuat selama berabad-abad.'),
  'longyan/mountain': ('Gunung Guanzhi', 'Gunung Guanzhi dikenal lewat puncak batu merahnya yang konon menyerupai topi hakim zaman dahulu; tebing-tebing merah yang disebut danxia ini dikelilingi kolam-kolam jernih dan lembah terjal. Dengan tangga yang dipahat di batu karang dan wisata perahu di danaunya, gunung ini dianggap sebagai mutiara alam Fujian selatan.'),
  'sanming/danxia': ('Danxia Taining', 'Taining di barat laut Fujian adalah geopark UNESCO dengan tebing batu pasir merah, ngarai sempit, dan gua-gua. Air mengukir labirin batu ini selama jutaan tahun; kini kamu bisa menyusurinya dengan perahu sambil menyaksikan aliran hijau meluncur di antara dinding-dinding merah tua.'),
  'sanming/shaxian': ('Camilan Sha County', 'Dapur sederhana Kabupaten Sha telah menjadi fenomena kuliner murah dan mengenyangkan di seluruh Tiongkok. Wonton berkulit setipis kertas, mi berbumbu saus kacang, dan sup kukus disajikan dengan kehangatan yang sama di kedai jajanan Shaxian yang ada di hampir setiap jalan di negeri ini.'),
  'sanming/forest': ('Ibu Kota Hijau', 'Sanming termasuk kota dengan tutupan hutan tertinggi di Tiongkok; gunung-gunungnya berselimut hijau dari punggung bukit hingga lembah. Dulu kota kayu, kini beralih ke ekowisata dan dengan bangga menyandang gelar \'ibu kota hijau\' berkat udaranya yang bersih dan jalur-jalur hiking di hutan.'),
  'sanming/goldenlake': ('Danau Emas', 'Danau Emas, atau Jinhu, adalah waduk luas yang berkelok di antara tebing Danxia merah di Taining. Wisata perahu membawamu melewati ngarai air yang sempit, dinding batu terjal, dan Kuil Ganlu yang dibangun di dalam gua — salah satu pemandangan langka tempat air bertemu batu.'),
  'ningde/mudflat': ('Dataran Lumpur Xiapu', 'Setiap hari air laut surut di Xiapu, menyingkap dataran lumpur luas yang berkilau dalam cahaya yang terus berubah. Ladang rumput laut, deretan tiang bambu, dan para nelayan yang bekerja di perairan dangkal menjadikan pesisir ini tempat berkumpulnya fotografer dari seluruh dunia.'),
  'ningde/whitetea': ('Teh Putih Fuding', 'Fuding adalah tanah kelahiran teh putih Tiongkok: kuncup berbulu keperakan hanya dilayukan dan dikeringkan, tidak pernah disangrai. Pepatah setempat — \'satu tahun teh, tiga tahun obat, tujuh tahun harta\' — menggambarkan bagaimana daun lembut ini makin berharga seiring usianya.'),
  'ningde/taimu': ('Gunung Taimu', 'Gunung Taimu menjulang menghadap laut dengan menara-menara granit membulat, celah batu sempit, dan lorong-lorong gua. Sejak zaman kuno dijuluki \'negeri peri di atas laut\', jalur-jalur setapaknya menyelinap di antara bebatuan menuju titik pandang tempat kabut dan samudra bertemu.'),
  'ningde/croaker': ('Ikan Croaker Kuning', 'Teluk-teluk terlindung Sandu\'ao menjadikan Ningde pusat budidaya ikan kuning besar (yellow croaker) terbesar di Tiongkok. Keramba-keramba apung membentuk desa di atas air, dan daging putihnya yang lembut, cukup dikukus sederhana, menjadi bintang di meja makan Fujian.'),
  'shaoguan/redcliff': ('Gunung Danxia', 'Gunung Danxia adalah masif batu pasir merah yang memberi nama pada bentang alam \'danxia\' di seluruh dunia dan tercatat sebagai Warisan Dunia UNESCO. Menara dan pilar yang dipahat angin serta air menyala bagai bara saat matahari terbenam, dan bisa dijelajahi lewat jalur setapak berliku maupun pelayaran sungai.'),
  'shaoguan/chantemple': ('Kuil Nanhua', 'Kuil Nanhua di dekat Shaoguan adalah tempat Huineng, Patriark Keenam Buddhisme Chan (Zen), menyebarkan ajarannya. Dengan sejarah hampir lima belas abad, kuil ini tetap menjadi pusat suci tradisi Chan selatan, tempat para peziarah masih menelusuri jejak sang guru di antara asap dupa.'),
  'shaoguan/ancestor': ('Zhuji Lane', 'Lorong Zhuji di Nanxiong adalah tempat persinggahan keluarga-keluarga yang bermigrasi dari utara pada zaman Song sebelum menetap di selatan. Jutaan orang Kanton kini menelusuri silsilah mereka ke lorong batu sempit ini, kembali tahun demi tahun untuk mencari nama leluhur mereka.'),
  'shaoguan/yaodance': ('Suku Yao', 'Suku Yao yang tinggal di kabupaten-kabupaten pegunungan Shaoguan dikenal dengan busana bersulam memukau dan tarian gendang panjang mereka. Saat festival panen, gendang bergema di lembah-lembah, sementara pola sulaman mewariskan sejarah marga dari generasi ke generasi bagai bahasa tanpa aksara.'),
  'zhanjiang/oyster': ('Tiram Zhanjiang', 'Tiram yang dibesarkan di perairan selatan Zhanjiang yang hangat dan bersih tumbuh gemuk dan seputih susu. Di malam hari tiram-tiram ini dipanggang di atas bara arang dengan bawang putih dan minyak di lapak-lapak kaki lima — ritual beraroma laut yang menjadi jantung kehidupan malam kota ini.'),
  'zhanjiang/navy': ('Pangkalan Angkatan Laut', 'Dengan pelabuhan alami yang dalam dan terlindung, Zhanjiang menjadi markas Armada Laut Selatan angkatan laut Tiongkok. Kota pelabuhan yang dulu disewakan kepada Prancis dengan nama Guangzhouwan ini kini menjadi gerbang maritim strategis negara menuju Laut Tiongkok Selatan.'),
  'zhanjiang/mangrove': ('Hutan Mangrove', 'Hutan bakau di sepanjang pesisir Zhanjiang membentuk cagar mangrove terbesar di Tiongkok. Terisi dan surut mengikuti pasang, hutan air asin ini menjadi rumah bagi kuntul, ikan gelodok, dan kepiting, sementara akar-akarnya yang kusut melindungi pantai dari badai sekaligus menjadi tempat pembesaran alami bagi anak-anak ikan.'),
  'zhanjiang/donghai': ('Pulau Donghai', 'Pulau Donghai di lepas pantai Zhanjiang terkenal dengan pantainya yang membentang tanpa putus sepanjang berkilo-kilometer. Anginnya yang stabil menarik para peselancar, dan pulau ini juga dikenal dengan \'tarian naga manusia\' tradisional, saat puluhan penari saling bertaut bahu menjadi satu naga.'),
  'maoming/lychee': ('Ibu Kota Leci', 'Maoming adalah salah satu kawasan penghasil leci terbesar di dunia; di awal musim panas bukit-bukitnya memerah dipenuhi buah. Pada zaman kekaisaran, leci dari tanah ini dikirim sebagai upeti ke istana, dan pohon-pohon leci berusia ratusan tahun di kebunnya masih berbuah hingga kini.'),
  'maoming/refinery': ('Pusat Petrokimia', 'Maoming tumbuh menjadi kota industri pada 1950-an dengan mengolah serpih minyak, dan kini menjadi salah satu kompleks petrokimia terbesar di Tiongkok selatan. Kilang minyak dan pabrik etilena memberi tulang punggung ekonomi yang kuat bagi kawasan hijau yang kaya pertanian ini.'),
  'maoming/ladyxian': ('Lady Xian', 'Lady Xian, pemimpin bijak dari abad keenam, mempersatukan bangsa-bangsa di selatan jauh dalam damai. Ratusan kuil di sekitar Maoming didedikasikan untuknya, dan upacara peringatan tahunan menjadi bukti penghormatan yang telah bertahan hampir lima belas abad.'),
  'maoming/seaside': ('Pantai', 'Pantai Maoming, yang dipromosikan sebagai \'Pantai Nomor Satu Tiongkok\', membentang berkilo-kilometer dengan pasir keemasan. Hutan cemara laut yang ditanam di sepanjang pesisir menjadi tirai hijau penahan angin, dan keluarga-keluarga menghabiskan hari dengan berenang sebelum menutupnya di rumah makan hidangan laut.'),
  'zhaoqing/sevenstar': ('Seven Star Crags', 'Tujuh bukit batu kapur menjulang dari Danau Bintang dalam formasi yang konon mencerminkan rasi Biduk. Bebatuannya menyembunyikan gua-gua berhias prasasti dari berbagai abad, dan berjalan menyusuri tanggul di tepi danau membuktikan mengapa tempat ini dijuluki \'Guilin-nya Guangdong\'.'),
  'zhaoqing/inkstone': ('Batu Tinta Duan', 'Dari \'empat pusaka ruang belajar\', batu tinta yang paling termasyhur adalah batu Duan dari Zhaoqing. Ditambang di sini sejak dinasti Tang, batu ungu ini berubah menjadi karya seni di tangan para pengukir; batu Duan yang baik menjaga tinta tetap lembap dan tidak melukai kuas.'),
  'zhaoqing/dinghu': ('Gunung Dinghu', 'Gunung Dinghu menjadi cagar alam pertama Tiongkok pada tahun 1956. Dengan hutan hujan subtropis yang masih perawan, air terjun, dan Kuil Qingyun, gunung ini adalah tempat berteduh sejuk yang oleh warga kota disebut dengan sayang sebagai \'bar oksigen\' alami.'),
  'zhaoqing/songwall': ('Tembok Kota Song', 'Tembok kota Zhaoqing didirikan pada dinasti Song dan lingkarnya bertahan hampir utuh hingga kini. Lapisan-lapisan batanya merekam jejak perbaikan dari dinasti demi dinasti, dan berjalan di atas temboknya bagaikan berkeliling menyusuri hampir seribu tahun sejarah kota.'),
  'huizhou/westlake': ('Danau Barat Huizhou', 'Danau Barat Huizhou adalah pemandangan klasik yang anggun dengan tanggul berjajar pohon willow, jembatan batu, dan pulau-pulau kecil. Penyair besar Su Dongpo, yang diasingkan ke sini, mengabadikan danau ini dalam puisinya, dan sebuah tanggul di tepi danau masih menyandang namanya hingga kini.'),
  'huizhou/luofu': ('Gunung Luofu', 'Gunung Luofu adalah salah satu gunung Tao paling suci di Tiongkok selatan; selama berabad-abad para pertapa dan ahli alkimia tertarik ke puncak-puncaknya. Hutannya yang terkenal dengan tanaman obat menyembunyikan kuil-kuil, mata air, dan jalur setapak yang mendaki hingga ke awan.'),
  'huizhou/alchemy': ('Alkimia Ge Hong', 'Ge Hong, ahli alkimia sekaligus tabib dari dinasti Jin, mengasingkan diri ke Gunung Luofu untuk meramu obat dan menulis karya-karya kedokterannya. Catatannya tentang tanaman artemisia manis dalam sebuah buku kuno, berabad-abad kemudian, mengilhami penemuan obat malaria modern.'),
  'huizhou/xunliao': ('Teluk Xunliao', 'Teluk Xunliao memikat dengan air dangkal sebening pirus dan hamparan panjang pasir pucat, menjadikannya tempat wisata favorit di pesisir Guangdong. Desa-desa yang dulunya kampung nelayan kini menyajikan hidangan laut segar, dan lautnya yang tenang cocok untuk keluarga dengan anak-anak.'),
  'meizhou/weilongwu': ('Ibu Kota Hakka', 'Meizhou dianggap sebagai ibu kota spiritual masyarakat Hakka yang tersebar di seluruh dunia. Rumah weilongwu berbentuk tapal kuda bersandar di lereng bukit, menghimpun seluruh klan besar di bawah satu atap, dan festival silsilah keluarga masih memenuhi halaman-halamannya hingga kini.'),
  'meizhou/saltchicken': ('Ayam Panggang Garam', 'Ayam panggang garam adalah hidangan klasik paling terkenal dari masakan Hakka: seekor ayam utuh dibungkus kertas lalu dibenamkan dalam garam kasar yang panas untuk dimasak. Alih-alih mengeringkan daging, garam justru mengunci sarinya, menghasilkan daging selembut sutra yang harum jahe.'),
  'meizhou/football': ('Kota Sepak Bola', 'Meizhou adalah salah satu tempat sepak bola modern pertama kali berakar di Tiongkok, sehingga dijuluki \'buaian sepak bola Tiongkok\'. Penyerang legendaris Li Huitang lahir di tanah ini, dan gairahnya masih hidup, mengalir dari lapangan desa hingga klub-klub profesional.'),
  'meizhou/plum': ('Bunga Plum', 'Nama Meizhou berasal dari aksara yang berarti \'plum\', dan Sungai Meijiang, Sungai Plum, mengairi kotanya. Mekar di tengah dinginnya musim salju, bunga plum menjadi lambang semangat tangguh dan pekerja keras masyarakat Hakka, dan motifnya muncul di seluruh penjuru kota.'),
  'jiangmen/diaolou': ('Kaiping Diaolou', 'Menara-menara diaolou yang menjulang di antara sawah Kaiping dibangun pada awal abad kedua puluh oleh para perantau yang pulang dari luar negeri. Dirancang bagai benteng melawan bandit dan banjir, bangunan ini memadukan pilar gaya Barat dengan atap Tiongkok, dan kini menjadi Situs Warisan Dunia UNESCO.'),
  'jiangmen/qiaoxiang': ('Kampung Halaman Perantau Tionghoa', 'Jiangmen dan kawasan Wuyi di sekitarnya adalah kampung halaman leluhur jutaan orang Tionghoa perantauan. Diaspora yang membentang dari Amerika hingga Asia Tenggara ini mendanai sekolah, jalan, dan rumah-rumah besar di kampung halaman, memberi kota ini wajah yang memadukan Timur dan Barat.'),
  'jiangmen/chenpi': ('Kulit Jeruk Kering', 'Kulit jeruk mandarin kering dari Xinhui, chenpi, dijemur di bawah matahari lalu disimpan bertahun-tahun agar matang sebelum digunakan. Ia memberi aroma dalam pada masakan Kanton dan sangat dihargai dalam pengobatan tradisional; kulit yang berumur panjang diperlakukan hampir seperti anggur tua yang berharga.'),
  'jiangmen/birds': ('Surga Burung', '\'Surga Burung\' di Xinhui adalah sebatang pohon beringin raksasa yang cabang-cabangnya berakar hingga menutupi seluruh pulau kecil. Ribuan kuntul dan burung air bertengger di sini, dan esai terkenal karya penulis Ba Jin membuat pulau hijau ini dicintai seluruh Tiongkok.'),
  'yangjiang/knife': ('Ibu Kota Pisau', 'Yangjiang adalah ibu kota pisau dan gunting Tiongkok; sebagian besar pisau dapur di negeri ini lahir dari bengkel dan pabrik kota ini. Tradisi pandai besi berusia ratusan tahun berpadu dengan teknologi baja modern, membawa merek-merek lokal hingga ke dapur-dapur di seluruh dunia.'),
  'yangjiang/shipwreck': ('Bangkai Kapal Nanhai No. 1', 'Nanhai No.1 adalah kapal dagang dinasti Song yang tenggelam di Jalur Sutra Maritim dan tertidur di dasar laut selama ratusan tahun. Diangkat dalam keadaan utuh, kapal ini kini bersemayam di museum bertangki kaca di Pulau Hailing, tempat puluhan ribu keping porselen dan barang berharga muncul dari palkanya.'),
  'yangjiang/hailing': ('Pulau Hailing', 'Pulau Hailing, dengan Teluk Dajiao berbentuk bulan sabit dan pantai berpasir lembut, adalah salah satu pulau wisata laut paling dicintai di Guangdong. Siang hari untuk berenang di ombak, malam hari untuk menikmati hidangan laut segar dari pelabuhan nelayan — dan pulau ini juga menjadi rumah museum kapal karam Nanhai No.1.'),
  'yangjiang/kite': ('Kota Layang-layang', 'Yangjiang, bersama Weifang di utara, dianggap sebagai salah satu dari dua ibu kota layang-layang Tiongkok. Layang-layang tradisional berangka bambu dibuat dengan tangan di sini secara turun-temurun, dan setiap musim gugur pada Festival Sembilan Ganda langit dipenuhi sayap-sayap warna-warni.'),
  'qingyuan/rafting': ('Ibu Kota Arung Jeram', 'Dengan arus deras yang mengalir turun dari pegunungannya, Qingyuan dikenal di Tiongkok sebagai \'kampung halaman arung jeram\'. Di musim panas ribuan pengunjung menaklukkan jalur-jalur berbuih dengan perahu, sementara lembah-lembahnya menawarkan hutan sejuk dan kolam batu jauh dari panasnya kota.'),
  'qingyuan/chicken': ('Ayam Qingyuan', 'Ayam lokal Qingyuan yang berbulu totol, bertulang halus dan berkaldu dalam, adalah unggas paling dicari dalam masakan Kanton. Dibesarkan dengan berkeliaran bebas, ayam ini sering hanya direbus sederhana dan disajikan dengan saus jahe-daun bawang — kesederhanaannya justru bukti kualitasnya.'),
  'qingyuan/hotspring': ('Pemandian Air Panas', 'Air panas kaya mineral yang muncul dari lembah-lembah pegunungan Qingyuan menjadikan kota ini pusat pemandian air panas Guangdong. Uap mengepul dari kolam-kolam terbuka di antara gemerisik hutan bambu, dan para pelancong akhir pekan dari Guangzhou datang ke sini untuk melepas penat.'),
  'qingyuan/yaoterrace': ('Terasering Sawah Yao', 'Di desa-desa Yao di Liannan, terasering padi memeluk lereng gunung undakan demi undakan. Dibangun dengan tangan selama berabad-abad, terasering ini berubah menjadi cermin air di musim semi dan tangga emas di musim gugur, sementara desa-desa Yao kuno masih hidup di antaranya.'),
  'chaozhou/guangjibridge': ('Jembatan Guangji', 'Jembatan Guangji yang melintasi Sungai Han, mulai dibangun pada dinasti Song, unik karena bagian tengahnya tersusun dari perahu-perahu yang diikat berdampingan. Bagian ponton ini dibuka setiap hari untuk memberi jalan bagi kapal, menjadikannya salah satu dari empat jembatan kuno termasyhur di Tiongkok.'),
  'chaozhou/woodcarving': ('Ukiran Kayu Lapis Emas', 'Ukiran kayu berlapis emas dari Chaozhou adalah kerajinan legendaris yang menumpuk adegan demi adegan dalam satu panel. Setiap detail, dari jala nelayan hingga pahlawan opera, dipahat dengan cermat, dan karya-karya berdaun emas ini memenuhi kuil serta rumah besar dengan kilau yang gemerlap.'),
  'chaozhou/chaoxiu': ('Sulam Chaozhou', 'Sulaman Chaozhou adalah cabang paling mewah dari seni jahit Guangdong: benang emas dan perak disulam di atas isian sehingga menghasilkan efek timbul yang nyaris seperti pahatan. Naga dan burung phoenix tampak siap melompat dari kain, menghiasi busana pengantin maupun kostum opera.'),
  'chaozhou/kaiyuan': ('Kuil Kaiyuan', 'Didirikan pada tahun 738 pada era Kaiyuan dinasti Tang, kuil ini menyandang nama era tersebut hingga hari ini. Ibadah tak pernah terputus di halamannya selama lebih dari seribu tahun; tungku dupa raksasa mengepul di bawah aula-aula yang dihiasi ukiran kayu terbaik Chaozhou.'),
  'jieyang/citygate': ('Gerbang Jinxian', 'Gerbang Jinxian, \'Gerbang Penyambut Kaum Berbudi\', adalah lambang anggun kota tua Jieyang yang masih bertahan. Menara kayunya yang beratap bersusun menghadap parit kota, dan namanya membawa harapan kota untuk menyambut orang-orang bijak dan berbudi luhur.'),
  'jieyang/jade': ('Ibu Kota Giok', 'Yangmei, sebuah kota kecil di bawah Jieyang, adalah salah satu pusat pengukiran dan perdagangan giok terbesar di Tiongkok. Jadeit mentah dari Myanmar dipotong, diukir, dan dipoles di sini, dan di lorong-lorong pasar para ahli membaca warna hijau yang tersembunyi di dalam setiap batu bagaikan sebuah pertaruhan.'),
  'jieyang/jieyanglou': ('Menara Jieyang', 'Menara Jieyang adalah monumen modern yang menghidupkan kembali arsitektur kuno dengan atap tradisional yang melengkung megah dan sosok yang anggun. Di dalamnya digelar pameran budaya, dan menara ini berdiri sebagai wujud kebanggaan masyarakat Chaoshan akan akar mereka, terukir dalam batu dan kayu.'),
  'jieyang/beefbroth': ('Sup Daging Sapi Chaoshan', 'Sup dan hotpot daging sapi Chaoshan adalah kuliner yang mengabdi pada kesegaran: setiap bagian sapi punya nama sendiri dan waktu rebus yang dihitung dalam hitungan detik di kaldu bening yang mendidih. Disajikan dengan saus celup sacha, kepiawaian dalam kesederhanaan ini adalah kebanggaan daerahnya.'),
  'yunfu/marble': ('Kerajaan Batu', 'Yunfu dikenal sebagai ibu kota pengolahan batu Tiongkok; marmer dan granit telah dipotong serta dipoles di kota ini selama beberapa generasi. Ribuan bengkel yang berjajar di sepanjang jalan raya mengirim meja dapur, patung, dan pelapis dinding ke seluruh dunia; batu adalah sumber penghidupan kota ini.'),
  'yunfu/patriarch': ('Patriark Keenam', 'Huineng, Patriark Keenam Buddhisme Chan, lahir di Xinxing yang berada di bawah Yunfu dan menghabiskan hari-hari terakhirnya di sini. Kuil Guoen yang didirikan untuk menghormatinya adalah pusat damai yang dibanjiri peziarah — tempat kisahnya bermula, dari bocah penebang kayu menjadi guru yang tercerahkan.'),
  'yunfu/tianlu': ('Gunung Tianlu', 'Gunung Tianlu adalah mahkota hijau Yunfu, dengan punggung bukit yang menjangkau awan dan lereng yang berselimut kebun teh. Di pagi hari lembah-lembahnya kerap dipenuhi lautan awan, menghadiahi para pendaki yang mengejar matahari terbit dengan pemandangan puncak-puncak yang muncul dari kabut.'),
  'yunfu/xijiang': ('Sungai Xi', 'Xijiang, atau Sungai Barat, adalah cabang utama sistem Sungai Mutiara dan salah satu jalur air tersibuk di Tiongkok selatan. Tongkang-tongkang barang melintas di depan Yunfu siang dan malam; sungai ini adalah urat nadi yang mengangkut batu dan hasil pertanian ke Guangzhou lalu ke seluruh dunia.'),
  'liuzhou/luosifen': ('Luosifen', 'Mi siput Liuzhou, luosifen, terkenal dengan kuahnya yang direbus bersama siput sungai dan aroma tajam rebung asam. Baunya memecah pendapat dari kejauhan, tetapi sekali mencicipinya orang biasanya langsung jatuh hati; dalam bentuk kemasan instan, hidangan lokal ini telah menaklukkan Tiongkok dan dunia.'),
  'liuzhou/autocity': ('Kota Otomotif', 'Liuzhou adalah jantung industri Guangxi dan salah satu basis manufaktur mobil utama Tiongkok. Mobil listrik kecil dan terjangkau yang diproduksi di sini telah menjadi ikon jalan-jalannya, dicintai warga karena bisa menyelip ke tempat parkir yang paling sempit sekalipun.'),
  'liuzhou/karst': ('Karst Sungai Liu', 'Sungai Liu melingkari kota bagaikan sabuk, dengan puncak-puncak batu kapur menjulang di sekelilingnya. Lekukan besar ini membuat Liuzhou dijuluki \'kota teko\', dan di jantung kota industri ini, taman-taman sungai serta puncak karst menyuguhkan keindahan alam yang mengejutkan.'),
  'liuzhou/liuhou': ('Penyair Liu Zongyuan', 'Liu Zongyuan, sastrawan besar dinasti Tang, menjabat gubernur di tempat pengasingannya, Liuzhou, di mana ia menggali sumur untuk rakyat dan melindungi kaum miskin. Sebuah kuil untuk mengenangnya berdiri di Taman Liuhou di pusat kota, dan sang penyair tetap tak terpisahkan dari kota tempat ia menghabiskan tahun-tahun terakhirnya.'),
  'wuzhou/gemstone': ('Ibu Kota Batu Permata', 'Wuzhou adalah ibu kota permata buatan dunia; sebagian besar zirkonia sintetis dipotong dan dipoles di bengkel-bengkel kota sungai ini. Tangan-tangan terampil mengukir faset demi faset pada batu-batu mungil, dan permata gemerlap itu menyebar dari sini ke pasar perhiasan di seluruh dunia.'),
  'wuzhou/liubaotea': ('Teh Hitam Liubao', 'Teh Liubao dari Wuzhou adalah teh fermentasi gelap yang semakin matang seiring bertahun-tahun penyimpanan. Dulu dikirim dengan perahu sungai ke para penambang di Asia Tenggara, yang percaya teh ini menyeimbangkan tubuh di iklim lembap; keranjang-keranjang tuanya kini diburu para kolektor.'),
  'wuzhou/turtlejelly': ('Guilinggao', 'Wuzhou dianggap sebagai tanah kelahiran guilinggao, jeli hitam yang diramu dari herba penyembuh. Sedikit pahit, jeli ini dimaniskan dengan madu dan disantap dingin — tradisi menyegarkan yang dipercaya menarik keluar \'panas dalam\' tubuh di musim panas selatan yang lembap.'),
  'wuzhou/dragonmother': ('Kuil Ibu Naga', 'Kuil Ibu Naga di tepi Sungai Xijiang dipersembahkan bagi dewi yang dianggap pelindung masyarakat sungai. Legenda menuturkan bahwa Ibu Naga mengangkat lima naga sebagai anak dan melindungi rakyat dari banjir; pada hari-hari festival, kuil ini dipenuhi asap dupa dan pita-pita harapan.'),
  'beihai/silverbeach': ('Pantai Perak', 'Pantai Perak Beihai berkilau sesuai namanya; pasir putihnya yang kaya kuarsa memantulkan cahaya keperakan di bawah matahari. Dijuluki \'pantai nomor satu di kolong langit\', garis pantainya membentang berkilo-kilometer, dan lautnya yang dangkal dan hangat menawarkan ruang tak berujung untuk berenang dan berjalan-jalan.'),
  'beihai/pearl': ('Kota Mutiara', 'Hepu, di bawah Beihai, termasyhur akan mutiaranya sejak dinasti Han; \'mutiara selatan\' termasuk upeti paling berharga yang dipersembahkan kepada istana. Peribahasa \'mutiara kembali ke Hepu\' lahir di pesisir ini, dan kini tambak mutiara serta pasar perhiasan tetap menghidupkan tradisi itu.'),
  'beihai/weizhou': ('Pulau Weizhou', 'Weizhou, di lepas pantai Beihai, dikenal sebagai pulau vulkanik termuda Tiongkok. Tebing lava hitam, terumbu karang, dan kebun pisang mengelilingi pantainya, dan sebuah gereja batu Katolik yang dibangun para misionaris pada abad kesembilan belas menjadi kejutan paling menakjubkan di pulau ini.'),
  'beihai/oldstreet': ('Jalan Tua', 'Jalan Tua Beihai dipenuhi bangunan qilou beratap lengkung yang bermunculan ketika pelabuhan dibuka untuk perdagangan asing pada akhir abad kesembilan belas. Fasad-fasad berlengkungnya membawa gema Asia Tenggara dan Eropa, dan kini jalan ini menghidupkan masa lalunya di antara lapak omelet tiram dan jejak konsulat-konsulat lama.'),
  'qinzhou/nixingpottery': ('Tembikar Nixing', 'Tembikar Nixing dari Qinzhou, meski dibakar tanpa glasir, dengan sendirinya memunculkan rona perunggu, merah tua, dan ungu di dalam tungku. Dibuat dari campuran tanah liat kedua tepi sungai, kerajinan ini termasuk salah satu dari empat tradisi tembikar termasyhur di Tiongkok.'),
  'qinzhou/dolphin': ('Lumba-lumba Putih', 'Teluk Sanniang di Qinzhou adalah salah satu habitat paling terkenal bagi lumba-lumba putih Tiongkok yang langka. Mamalia anggun ini berubah merah muda seiring bertambahnya usia dan muncul ke permukaan di dekat perahu wisata; warga teluk dengan bangga melindungi hewan yang mereka juluki \'panda laut\' ini.'),
  'qinzhou/oysterfarm': ('Budidaya Tiram', 'Laut Maowei di Qinzhou yang dangkal dan kaya nutrisi adalah salah satu tempat pembenihan tiram muda terbesar di Tiongkok. Perairannya dipenuhi deretan rakit apung, dan panen yang gemuk berdaging menjadikan kota ini ibu kota tiram di selatan — saat festival tiba, panggangannya tak pernah padam.'),
  'qinzhou/general': ('Jenderal Feng Zicai', 'Jenderal Qing Feng Zicai kembali dari masa pensiunnya di usia senja dan meraih kemenangan bersejarah melawan invasi di Celah Zhennan, perbatasan Vietnam. Di kampung halamannya, Qinzhou, bekas kediamannya dilestarikan sebagai museum, dan namanya dikenang sebagai lambang pembelaan tanah air.'),
  'guigang/lotus': ('Kota Teratai', 'Guigang dikenal di Tiongkok sebagai \'Kota Teratai\': di musim panas kolam dan ladang di sekitarnya berselimut bunga merah muda dan putih. Akar dan biji teratai adalah bahan pokok dapur setempat, dan festival teratai tahunan memenuhi kota dengan kemeriahan.'),
  'guigang/uprising': ('Pemberontakan Jintian', 'Pada tahun 1851, di desa Jintian di Guiping, Hong Xiuquan mengibarkan panji Pemberontakan Taiping. Salah satu gerakan rakyat terbesar abad kesembilan belas lahir dari sini dan mengguncang separuh Tiongkok; kini kompleks peringatan di desa itu menuturkan kembali masa yang penuh badai tersebut.'),
  'guigang/nanshan': ('Kuil Nanshan', 'Kuil Nanshan di Guigang adalah tempat ibadah berusia seribu tahun yang dibangun di dalam gua-gua alami sebuah bukit batu kapur. Prasasti dan puisi yang dipahat sepanjang berbagai dinasti menghiasi dinding guanya, sementara patung-patung Buddha duduk hening di aula-aula batu yang sejuk.'),
  'guigang/sugarcane': ('Tebu', 'Guangxi adalah sumber gula terbesar Tiongkok, dan dataran sungai Guigang yang subur merupakan bagian penting dari panen manis itu. Di musim gugur, ladang tebu tumbuh melampaui tinggi manusia, dan pada musim panen jalan-jalan dipenuhi truk yang mengangkut tebu ke pabrik-pabrik.'),
  'yulin/medicine': ('Pasar Obat Herbal', 'Pasar herbal Yulin termasuk pusat perdagangan obat tradisional terbesar di Tiongkok selatan. Di lorong-lorongnya, aroma akar, kulit kayu, dan bunga kering saling berbaur, dan para pedagang hafal watak setiap tanaman di luar kepala — pewaris pengetahuan yang diturunkan selama berabad-abad.'),
  'yulin/goldenpalace': ('Istana Yuntian', 'Istana Yuntian adalah bangunan budaya monumental yang menafsirkan kembali arsitektur istana tradisional dalam skala raksasa. Lantai-lantainya memamerkan ukiran halus, patung perunggu, dan adegan-adegan mitologi, dan menara-menaranya yang berlapis emas menjadi bagian paling mencolok dari cakrawala kota.'),
  'yulin/lychee': ('Kebun Leci', 'Bukit dan lembah Yulin yang hangat berselimut kebun leci dan lengkeng. Di awal musim panas, dahan-dahan merunduk oleh tandan buah merah; lapak pasar meluap dengan panen yang harum manis, dan keluarga-keluarga merayakan hari memetik buah bagaikan sebuah festival.'),
  'yulin/beef': ('Daging Sapi Yulin', 'Camilan khas Yulin, niuba, dibuat dengan mengeringkan dan memasak perlahan irisan tipis daging sapi dalam saus berbumbu. Berwarna gelap, sedikit manis, dan kaya rasa, daging ini disantap dengan nasi atau ditemani teh, dan resepnya diwariskan dalam keluarga dari generasi ke generasi.'),
  'baise/redbase': ('Pemberontakan Baise', 'Pada tahun 1929, Pemberontakan Baise yang dipimpin Deng Xiaoping muda mendirikan basis revolusioner di tepi Sungai You. Kota ini karenanya menjadi persinggahan penting di jalur \'memori merah\' Tiongkok; aula peringatan dan gedung markas lamanya membawa masa itu hingga ke masa kini.'),
  'baise/sinkhole': ('Lubang Raksasa Leye', 'Lubang runtuhan raksasa, atau tiankeng, di kabupaten Leye membentuk salah satu gugusan lubang terpadat di Bumi. Hutan-hutan perawan tumbuh di dasarnya yang berkedalaman ratusan meter, dan sungai bawah tanah serta sistem guanya menjadikan kawasan ini favorit para ahli geologi dan penjelajah gua.'),
  'baise/mango': ('Ibu Kota Mangga', 'Lembah-lembah Baise yang panas dan cerah termasuk kawasan penghasil mangga terpenting di Tiongkok. Di pertengahan musim panas lereng-lereng bukit berubah keemasan; truk-truk mengangkut buah manis itu ke segala penjuru negeri, dan mangga telah menjadi sumber penghidupan sekaligus lambang kebanggaan kabupaten-kabupaten pegunungan ini.'),
  'baise/aluminum': ('Kota Aluminium', 'Pegunungan Baise kaya akan bauksit, bijih yang menjadikan kota ini basis selatan industri aluminium Tiongkok. Tambang dan pabrik peleburan menjadi tulang punggung ekonomi kawasan, dan logam \'perak\' di bawah tanah merah ini memberi pekerjaan bagi ribuan keluarga.'),
  'hechi/longevity': ('Bama, Desa Panjang Umur', 'Bama, di bawah Hechi, adalah \'negeri panjang umur\' yang mendunia, dengan jumlah warga berusia di atas seratus tahun yang mencolok dibanding populasinya. Udara bersih, makanan sederhana, dan hidup tanpa tergesa dianggap sebagai rahasianya, dan ribuan pengunjung datang ke lembah-lembah ini setiap tahun untuk mencari kesehatan.'),
  'hechi/folksong': ('Liu Sanjie', 'Yizhou di Hechi dihormati sebagai kampung halaman Liu Sanjie, penyanyi rakyat legendaris masyarakat Zhuang. Dalam dongeng, sang \'peri lagu\' mengalahkan para tuan tanah lewat adu nyanyi improvisasi — tradisi yang hingga kini masih hidup penuh semangat di pekan-pekan lagu rakyat.'),
  'hechi/bronzedrum': ('Gendang Perunggu', 'Genderang perunggu termasuk benda paling sakral bagi bangsa-bangsa selatan seperti Zhuang dan Yao, dan Hechi dianggap sebagai jantung budaya genderang perunggu yang masih hidup. Genderang berukiran timbul ini ditabuh saat festival, suaranya diyakini memanggil berkah dan perlindungan, dan banyak desa menjaga genderang berusia ratusan tahun bagai pusaka keluarga.'),
  'hechi/geopark': ('Geopark Karst', 'Bentang karst Hechi adalah laboratorium alam berisi lubang runtuhan, aula gua raksasa, dan sungai bawah tanah. Jembatan batu alami dan jendela gua di sekitar Fengshan adalah bintang geopark ini, dan di tempat cahaya menembus lubang-lubangnya, dunia tersembunyi tampak di bawah sana.'),
  'laibin/sugarcity': ('Kota Gula', 'Dataran Laibin tertutup tebu sejauh mata memandang, sehingga kota ini dijuluki \'ibu kota gula Tiongkok\'. Saat panen musim salju dimulai, cerobong pabrik mulai mengepul, mengubah tebu menjadi gula, tetes, dan kertas, sementara aroma manis melayang menyelimuti kota-kota kecilnya.'),
  'laibin/yao': ('Suku Yao Dayao', 'Pegunungan Dayao di Jinxiu, di bawah Laibin, menjadi rumah bagi lima cabang berbeda suku Yao, masing-masing dengan busana, dialek, dan upacaranya sendiri. Perhiasan perak dan hiasan kepala bersulam berkilau di festival-festival desa pegunungan, menjadikan Jinxiu sebuah museum budaya yang hidup.'),
  'laibin/hongshui': ('Sungai Hongshui', 'Hongshui, yang dinamai dari lumpur merah yang dibawanya, adalah sungai perkasa yang membelah pegunungan Guangxi. Bendungan-bendungan di sepanjang lembahnya mengalirkan listrik ke seluruh selatan, sementara desa-desa di tepiannya menikmati pemandangan yang diukir sungai di antara puncak-puncak karst.'),
  'laibin/shengtang': ('Gunung Shengtang', 'Gunung Shengtang adalah puncak tertinggi barisan Dayao dan termasuk salah satu atap tertinggi Guangxi. Di musim semi lerengnya menyala oleh rhododendron merah, sementara di puncaknya lautan awan, matahari terbit, dan kabut yang diterbangkan angin menjadi hadiah bagi para pendaki.'),
  'chongzuo/waterfall': ('Air Terjun Detian', 'Air Terjun Detian jatuh dalam undakan-undakan lebar di atas sungai di perbatasan Tiongkok–Vietnam dan dianggap sebagai air terjun lintas negara terbesar di Asia. Rakit bambu membawamu mendekat ke kabut sejuk tirai airnya, sementara puncak-puncak karst di sekelilingnya mengubah pemandangan menjadi lukisan Tiongkok.'),
  'chongzuo/langur': ('Lutung Kepala Putih', 'Lutung kepala putih hanya hidup di bukit-bukit batu kapur Chongzuo dan termasuk primata paling langka di dunia. Ia tidur di celah tebing pada malam hari dan melompat-lompat di batu terjal pada siang hari; berkat kawasan konservasi, populasinya perlahan-lahan mulai pulih.'),
  'chongzuo/rockart': ('Seni Cadas Huashan', 'Dilukis di tebing Sungai Zuojiang sekitar dua ribu tahun silam oleh bangsa Luoyue, figur-figur merah itu menggambarkan ribuan orang menari dalam pose menyerupai katak. Bagaimana lukisan itu dibuat di permukaan tebing yang begitu sulit dijangkau masih diperdebatkan, dan seni cadas ini telah tercatat sebagai Warisan Dunia UNESCO.'),
  'chongzuo/borderpass': ('Gerbang Persahabatan', 'Celah Persahabatan adalah gerbang perbatasan bersejarah yang menghubungkan Tiongkok dengan Vietnam dan termasuk salah satu celah termasyhur di Tiongkok. Menara berlengkungnya di antara gunung-gunung hijau telah menyambut pasukan, kafilah, dan utusan selama berabad-abad, dan hingga kini tetap menjadi gerbang perdagangan perbatasan yang ramai.'),
  'beijing/great-wall': ('Tembok Besar Tiongkok', 'Benteng terpanjang di dunia — lebih dari 20.000 km yang dibangun selama berabad-abad untuk menjaga perbatasan utara Tiongkok. Bagian Badaling dekat Beijing, dengan anak tangga batu dan menara pengawas di sepanjang punggung bukitnya, adalah ruas yang paling banyak dikunjungi.'),
  'beijing/temple': ('Kuil Surga', 'Kompleks suci tempat para kaisar Ming dan Qing berdoa kepada langit setiap tahun demi panen yang melimpah. Atap birunya yang bundar bertingkat tiga — dibangun tanpa satu paku pun — adalah salah satu ikon paling dikenal dalam arsitektur Tiongkok.'),
  'beijing/pagoda': ('Pagoda Tianning', 'Pagoda bata 13 tingkat setinggi sekitar 57 meter dari Dinasti Liao. Dengan relief ukirannya dan badannya yang segi delapan, ini adalah salah satu bangunan tertua yang masih berdiri di Beijing — saksi sejarah kota yang berusia seribu tahun.'),
  'beijing/opera': ('Opera Beijing', 'Seni panggung tradisional Tiongkok berusia 200 tahun yang memadukan nyanyian, dialog, seni bela diri, dan akrobatik. Riasan wajah warna-warni para pemainnya (lianpu) mengungkap watak setiap tokoh: merah melambangkan kesetiaan, putih melambangkan kelicikan.'),
  'zunyi/huiyi': ('Konferensi Zunyi', 'Pada hari-hari tergelap Mars Panjang, para pemimpin Partai Komunis berkumpul di gedung batu abu-abu ini pada tahun 1935, menggambar ulang arah revolusi dan membuka jalan Mao menuju kepemimpinan. Kini menjadi museum, rumah ini menempatkan Zunyi di jantung peta \'wisata merah\' Tiongkok.'),
  'zunyi/moutai': ('Kota Moutai', 'Kota kecil Moutai di tepi Sungai Chishui adalah rumah baijiu legendaris yang dijuluki minuman nasional Tiongkok. Disuling dari sorgum dan disimpan bertahun-tahun, minuman keras yang membara ini menjadi hidangan wajib jamuan kenegaraan; bahkan udara kotanya pun sarat dengan aroma fermentasi.'),
  'zunyi/loushan': ('Celah Loushan', 'Celah Loushan yang terjal, membelah pegunungan, menjadi panggung kemenangan bersejarah Tentara Merah selama Mars Panjang. Mao mengabadikannya lewat puisi terkenal yang ditulisnya di sini; kini para pengunjung mendaki tebing berkabut dan membaca bait-bait itu terukir di batu.'),
  'zunyi/chishui': ('Air Terjun Chishui', 'Air terjun mengalir deras dari tebing Danxia merah Chishui ke lembah penuh hutan bambu dan pakis pohon raksasa yang bertahan sejak zaman dinosaurus. Namanya berarti \'air merah\', diambil dari sungai yang mengalir kemerahan setelah hujan, dan lanskap ini termasuk warisan alam Danxia Tiongkok versi UNESCO.'),
  'liupanshui/coolcity': ('Kota Sejuk', 'Bertengger di dataran tinggi dengan musim panas yang tetap sejuk, Liupanshui dengan bangga menyandang gelar \'ibu kota sejuk Tiongkok\'. Warga Sichuan dan Chongqing yang gerah berbondong-bondong melarikan diri ke sini setiap musim panas, dan kota ini pandai mengubah udaranya yang segar menjadi festival dan wisata dataran tinggi.'),
  'liupanshui/coal': ('Lautan Batu Bara Barat Daya', 'Dibangun di atas lapisan batu bara yang kaya, Liupanshui lama menjadi tungku energi Tiongkok barat daya. Kota ini tumbuh bersama tambang dan baja pada masa pembangunan industri besar abad kedua puluh, dan kini berusaha menyeimbangkan identitas penambangnya dengan energi hijau dan pariwisata.'),
  'liupanshui/grassland': ('Padang Rumput Wumeng', 'Padang rumput tak berujung di dataran tinggi Wumeng, bertetangga dengan awan, dihiasi kawanan kuda dan barisan turbin angin di cakrawala. Warga desa Yi dan Miao menggembalakan ternak sepanjang musim panas yang sejuk, dan kabut dataran tinggi bisa turun seketika, mengubah seluruh pemandangan menjadi negeri dongeng.'),
  'liupanshui/kiwi': ('Kiwi Berinti Merah', 'Kiwi berhati merah tumbuh subur di dataran tinggi yang sejuk dan berkabut di sekitar Liupanshui dan menjadi harta hijau manis kota ini. Dengan inti merah delima, rasanya lebih manis dari kiwi biasa, dan pada musim panen desa-desa pegunungan penuh dengan peti-peti buah.'),
  'anshun/huangguoshu': ('Air Terjun Huangguoshu', 'Huangguoshu, air terjun terbesar di Tiongkok, menderu jatuh setinggi 77 meter dan menebar pelangi lewat kabutnya. Sebuah jalur menembus Gua Tirai Air di balik air terjun, memungkinkanmu memandang keluar dari balik derasnya air — adegan serial TV klasik Perjalanan ke Barat pun difilmkan di sini.'),
  'anshun/dixi': ('Opera Tanah Dixi', 'Dipentaskan di alun-alun desa dengan topeng prajurit kayu berukir dan dentuman gong, Dixi dijuluki \'fosil hidup opera Tiongkok\'. Dibawa ke Guizhou bersama prajurit garnisun Ming, teater ritual ini telah menuturkan kembali epos perang kuno dengan semangat yang sama selama sekitar enam abad.'),
  'anshun/batik': ('Seni Batik', 'Para perempuan Buyi dan Miao menggambar burung, bunga, dan pola berpusar di atas kain dengan lilin cair, lalu mencelupkan kainnya ke pewarna nila. Warna yang meresap ke retakan halus lilin membuat setiap lembar menjadi satu-satunya, itulah sebabnya batik Anshun dikenal sebagai kerajinan tanpa kembaran.'),
  'anshun/tunpu': ('Desa Tunpu', 'Di desa-desa garnisun batu yang didirikan tentara Ming sekitar 600 tahun lalu, masyarakat Tunpu masih mengenakan busana gaya Nanjing kuno warisan leluhur dan menuturkan dialek lama. Menyusuri lorong berdinding batu terasa seperti melangkah ke kota Ming yang membeku dalam waktu.'),
  'bijie/azalea': ('Sabuk Azalea Ratusan Li', 'Setiap musim semi punggung-punggung gunung Bijie menyala merah, merah muda, dan ungu oleh bunga azalea, dan \'Sabuk Azalea Seratus Li\' dianggap hutan azalea alami terbesar di dunia. Selama festival bulan April, warga desa Yi dan Miao menyambut musim semi dengan nyanyian di tengah lautan bunga.'),
  'bijie/zhijin': ('Gua Zhijin', 'Gua Zhijin, tempat stalagmit raksasa menjulang bagai hutan batu, dijuluki \'istana bawah tanah\' dan termasuk gua paling menakjubkan di Tiongkok. Di ruang-ruang seluas katedral, formasi halus seperti \'Pohon Hujan Perak\' membuat pengunjung terpukau.'),
  'bijie/caohai': ('Burung Bangau Caohai', 'Caohai, danau dangkal berumput di dataran tinggi Weining, menjadi tempat berlindung musim dingin bagi burung jenjang leher hitam yang langka setiap tahunnya. Saat kabut pagi terangkat, suara ribuan burung memenuhi permukaan air, sementara para pendayung mengantar pengunjung dengan tenang menembus rerumpunan gelagah.'),
  'bijie/potato': ('Ibu Kota Kentang', 'Kentang yang tumbuh di dataran tinggi yang sejuk dan cerah menjadikan Bijie salah satu lumbung kentang besar Tiongkok, dan kentang Weining terkenal di seluruh negeri. Dipanggang di atas bara, digoreng renyah, dan dibalur saus cabai di lapak-lapak jalanan, kentang yang sederhana ini adalah mahkota dapur dataran tinggi.'),
  'qujing/rapeseed': ('Lautan Bunga Kanola Luoping', 'Di penghujung musim dingin, dataran Luoping tenggelam dalam bunga kanola keemasan, dengan bukit-bukit karst menjulang dari ladang bagai pulau di lautan kuning. Hamparan bunga ini menarik peternak lebah, fotografer, dan pencinta madu dari berbagai penjuru, dan udaranya pun terasa manis.'),
  'qujing/ham': ('Ham Xuanwei', 'Diasinkan dan dikeringkan di udara pegunungan selama berabad-abad, ham Xuanwei adalah kebanggaan meja makan Yunnan. Dagingnya yang merah mawar dan aromanya yang dalam menempatkannya di antara ham paling terkenal di Tiongkok, membumbui segalanya mulai dari sup hingga kue bulan perayaan.'),
  'qujing/jiulong': ('Air Terjun Jiulong', 'Di dekat Luoping, sungai \'Sembilan Naga\' turun dalam rangkaian air terjun bertingkat, masing-masing dengan lebar dan karakternya sendiri. Saat air melimpah, pemandangan yang dibingkai ladang kanola keemasan ini dianggap salah satu rantai air terjun terindah di Tiongkok.'),
  'qujing/sandforest': ('Hutan Pasir Berwarna', 'Di Hutan Pasir Warna-warni di Luliang, pilar-pilar pasir yang dipahat angin dan hujan berpendar dalam gradasi emas, karat, putih, hingga ungu. Warnanya berubah mengikuti cahaya, menjadikan taman patung alami ini panggung favorit kru film dan fotografer.'),
  'yuxi/fuxian': ('Danau Fuxian', 'Fuxian, salah satu danau terdalam di Tiongkok, terbenam di dataran tinggi Yunnan bagai cermin gunung berair sebening kristal. Legenda bertutur tentang permukiman kuno di bawah permukaannya, dan para nelayan di desa-desa tepi danau masih menjala ikan kecil kanglang yang terkenal.'),
  'yuxi/nieer': ('Komponis Nie Er', 'Nie Er, pencipta lagu kebangsaan Tiongkok, berasal dari keluarga Yuxi, dan kota ini dengan bangga mengakuinya sebagai putra daerah. Lewat taman musik, monumen, dan festival yang menyandang namanya, Yuxi mewariskan melodi sang komponis yang wafat di usia muda dari generasi ke generasi.'),
  'yuxi/chengjiang': ('Fosil Chengjiang', 'Lapisan fosil Kambrium berusia 530 juta tahun di Chengjiang membentuk Situs Warisan Dunia UNESCO yang mengungkap fajar kehidupan hewan dengan detail menakjubkan. Bahkan jaringan lunak pun tercetak di batu, menjadikan makhluk-makhluk ini salah satu saksi terkaya \'ledakan Kambrium\'.'),
  'yuxi/kiln': ('Tungku Yuxi', 'Tungku kuno Yuxi, yang berasal dari era Yuan, dianggap tempat lahir keramik biru-putih Yunnan. Bekerja jauh dari Jingdezhen yang termasyhur, para perajin lokal mengembangkan gaya mereka sendiri, menorehkan jejak pada tradisi keramik barat daya dengan wadah-wadah berhias kobalt.'),
  'dali/threepagodas': ('Tiga Pagoda', 'Menjulang di kaki pegunungan Cangshan selama seribu tahun, tiga pagoda anggun ini adalah lambang kerajaan kuno Nanzhao dan Dali. Tegar melewati gempa berabad-abad, ketiganya membingkai pemandangan kartu pos paling dicintai di Dali, dengan puncak bersalju di belakang dan kolam pemantul di depan.'),
  'dali/erhai': ('Danau Erhai', 'Dinamai dari bentuknya yang menyerupai telinga, Erhai adalah danau dataran tinggi yang terbentang antara pegunungan Cangshan dan dataran Dali. Desa-desa Bai berdinding putih menghiasi tepiannya, dan bersepeda mengelilingi danau atau menyaksikan perahu nelayan saat matahari terbit termasuk kenikmatan klasik Dali.'),
  'dali/cangshan': ('Pegunungan Cangshan', 'Dengan sembilan belas puncak dan delapan belas anak sungai yang mengalir di antaranya, Cangshan menjulang bagai tirai hijau di belakang Dali. Marmer dalam bahasa Tionghoa secara harfiah disebut \'batu Dali\': batu berpola yang ditambang dari urat-urat gunung ini telah menghias istana dan kuil selama berabad-abad.'),
  'dali/wind': ('Angin, Bunga, Salju, Bulan', 'Angin Xiaguan, bunga Shangguan, salju Cangshan, dan bulan di atas Erhai — empat keindahan Dali dilantunkan bagai satu puisi. Bahkan hiasan kepala perempuan Bai menganyam keempat simbol ini, sebuah rumusan anggun yang dipakai kota untuk merangkum alamnya sendiri.'),
  'lijiang/oldtown': ('Kota Tua Lijiang', 'Terjalin dari kanal, lorong berbatu, dan rumah kayu beratap genting, Kota Tua Lijiang adalah jantung hidup budaya Naxi. Kota UNESCO yang terkenal dibangun tanpa tembok ini dulu menjamu kafilah Jalur Teh-Kuda, dan gemericik air mengalir masih menemanimu di setiap lorong.'),
  'lijiang/snowmountain': ('Gunung Salju Naga Giok', 'Dengan puncak bergletser setinggi 5.596 meter, Gunung Salju Naga Giok berkilau di atas Lijiang bagai naga yang sedang tertidur. Masyarakat Naxi menganggap gunung ini suci; kereta gantung membawa pengunjung menuju taman gletser, sementara Lembah Bulan Biru di kakinya memikat dengan kolam-kolam berwarna pirus.'),
  'lijiang/dongba': ('Aksara Dongba', 'Dongba, tulisan gambar para pendeta Naxi, dianggap satu-satunya aksara piktografik di dunia yang masih digunakan. Ribuan naskah merekam ritual untuk roh-roh alam dan pandangan Naxi tentang kosmos, sebuah arsip yang tercatat dalam daftar Memory of the World UNESCO.'),
  'lijiang/tigerleaping': ('Ngarai Lompatan Harimau', 'Legenda mengisahkan seekor harimau melompati titik tersempit Sungai Jinsha dalam satu lompatan, memberi nama pada ngarai ini. Menghunjam di antara gunung salju Naga Giok dan Haba, ngarai ini termasuk yang terdalam di bumi, dan jalur tinggi di lerengnya adalah impian para petrek.'),
  'lincang/dianhong': ('Teh Hitam Dianhong', 'Dianhong, teh hitam berpucuk emas dari Fengqing, adalah teh muda yang lahir pada abad lalu, namun dengan cepat membawa nama Yunnan mendunia. Dihargai karena seduhannya bernuansa madu dan karamel, teh ini termasuk teh hitam paling disegani di Tiongkok, memperoleh kedalaman ekstra dari daun pohon-pohon teh purba.'),
  'lincang/wadrum': ('Gendang Kayu Wa', 'Masyarakat Wa menganggap gendang kayu itu suci; suaranya konon menjembatani langit dan manusia. Di desa-desa perbukitan Cangyuan, tarian gendang pengibas rambut — para perempuan mengayunkan rambut panjang mengikuti irama — memenuhi seluruh lembah dengan gemuruh pada hari panen dan festival.'),
  'lincang/teatrees': ('Pohon Teh Kuno', 'Pegunungan berkabut Lincang menaungi pohon-pohon teh liar dan purba yang usianya dihitung dalam abad, bahkan milenium, menjaga hutan tempat teh dilahirkan. Saat panen musim semi warga desa memanjat pohon-pohon raksasa itu dengan tangga, dan daun-daun tua ini menjadi sebagian pu\'er paling diburu di dunia.'),
  'lincang/lancang': ('Sungai Lancang', 'Lancang, alur hulu Sungai Mekong, turun dari Tibet dan membelah lembah-lembah dalam Lincang dalam perjalanannya ke selatan menuju Asia Tenggara. Bendungan-bendungan di sepanjang alirannya menerangi kawasan ini, sementara kebun teh dan kebun buah tropis menanjak berundak di lereng atas tepiannya.'),
  'puer/tea': ('Teh Pu\'er', 'Teh pu\'er padat yang dinamai dari kota pegunungan ini adalah harta hidup yang semakin matang dan bernilai seiring usianya. Dicetak menjadi bentuk kue, daunnya dapat disimpan puluhan tahun, dan dahulu kafilah bagal mengangkut cetakan-cetakan ini melintasi pegunungan menuju Tibet dan istana kekaisaran.'),
  'puer/coffee': ('Ibu Kota Kopi Tiongkok', 'Sebagian besar kopi Tiongkok tumbuh di kebun arabika di lereng berkabut Pu\'er, sehingga ibu kota teh ini, anehnya, kini beraroma latte. Kebun-kebun kopi menggelar tur cicip di antara buah kopi, dan para barista muda bertekad membawa biji lokal ini ke panggung dunia.'),
  'puer/teahorse': ('Jalur Teh dan Kuda', 'Jalur Teh-Kuda kuno, tempat kafilah bagal mengangkut balok-balok teh ke Tibet dan membawa pulang kuda ke Tiongkok, bermula dari Pu\'er dan mendaki celah-celah gunung berselimut awan. Jejak jalur kafilah berlapis batu dan kota-kota persinggahan tua masih menjaga kenangan perdagangan yang berat itu tetap hidup.'),
  'puer/peafowl': ('Merak Hijau', 'Hutan tropis di sekitar Pu\'er termasuk tempat perlindungan terakhir merak hijau, salah satu burung paling langka di Tiongkok. Cagar alam di sini menaungi bukan hanya burung megah ini, tetapi juga gajah liar dan owa, dan kota ini membanggakan hutannya sama besarnya dengan tehnya.'),
  'baoshan/volcano': ('Gunung Berapi Tengchong', 'Sembilan puluh tujuh kerucut gunung berapi tidur berjajar di dataran Tengchong, memberi lanskap ini rupa permukaan bulan. Pengunjung mendaki ke bibir kawah atau melayang di atas kerucut-kerucut itu dengan balon udara, dan batu lava hitam bahkan terpasang di dinding rumah-rumah kota.'),
  'baoshan/rehai': ('Lembah Rehai', 'Di lembah \'Laut Panas\' Tengchong, geiser mengepul dan kolam-kolam mendidih; yang paling terkenal adalah \'Kuali Mendidih Besar\' yang raksasa. Pengunjung mencicipi telur yang dimasak dengan uap mata air, lalu berendam di pemandian mineral, mencari kehangatan penyembuh dari tanah vulkanik ini.'),
  'baoshan/heshun': ('Kota Heshun', 'Heshun, kota batu para saudagar yang berabad-abad berdagang hingga ke Burma dan lebih jauh lagi, menyaksikan putra-putranya mengirim pulang kekayaan dalam wujud rumah-rumah anggun dan sekolah. Menjadi rumah salah satu perpustakaan desa tertua di Tiongkok, kota ini memancarkan ketenangan dengan kolam teratai dan jembatan batunya.'),
  'baoshan/gaoligong': ('Pegunungan Gaoligong', 'Membentang di sepanjang perbatasan Myanmar, Pegunungan Gaoligong adalah gudang harta kehidupan, dengan lembah kupu-kupu, hutan hangat, dan ribuan spesies tumbuhan. Menanjak dari lembah tropis ke punggungan bersalju, pegunungan ini menaungi tak terhitung makhluk langka, dari owa hingga burung-burung yang jarang terlihat.'),
  'deyang/sanxingdui': ('Reruntuhan Sanxingdui', 'Topeng-topeng perunggu raksasa bermata menonjol, digali dari lubang persembahan yang ditemukan pada 1986, mengangkat peradaban Shu misterius berusia 3.000 tahun ke permukaan. Dengan tongkat emas dan pohon perunggu sucinya, Sanxingdui termasuk kejutan terbesar dalam arkeologi Tiongkok.'),
  'deyang/jiannanchun': ('Arak Jiannanchun', 'Jiannanchun, yang disuling di Mianzhu, adalah baijiu bersejarah yang namanya tercatat di antara minuman yang dihidangkan di istana Tang. Dengan lubang fermentasi kuno yang terus dipakai tanpa henti dan aroma bunganya, ia berdiri di antara nama paling disegani dalam tradisi minuman keras Sichuan.'),
  'deyang/nianhua': ('Lukisan Tahun Baru Mianzhu', 'Cetakan Tahun Baru dari balok kayu yang dilukis tangan khas Mianzhu menggantungkan keberuntungan di pintu-pintu: dewa penjaga, bayi montok, dan lambang kelimpahan. Terhitung di antara tradisi nianhua besar Tiongkok, sapuan kuas akhir para maestro yang hidup mengubah setiap cetakan menjadi karya tersendiri.'),
  'deyang/turbine': ('Ibu Kota Industri Berat', 'Sebagian besar turbin raksasa, generator, dan peralatan pembangkit listrik negeri ini ditempa di bengkel-bengkel raksasa Deyang. Dianggap sebagai ibu kota alat berat, kota ini adalah salah satu otot baja yang diam-diam menopang infrastruktur energi Tiongkok.'),
  'mianyang/libai': ('Kampung Halaman Li Bai', 'Li Bai, sang abadi di antara para penyair, melewatkan masa kecilnya di antara pegunungan Jiangyou, tempat bait-baitnya tentang cahaya bulan dan anggur pertama kali bersemi. Monumen dan museum yang menyandang namanya mengumpulkan para pencinta puisi setiap tahun untuk menapaki jejak maestro legendaris zaman Tang ini.'),
  'mianyang/sciencecity': ('Kota Sains', 'Mianyang, satu-satunya kota yang menyandang gelar resmi \'Kota Sains dan Teknologi\' Tiongkok, membangun masa depan dengan lembaga riset dan pabrik elektronik. Kampung halaman televisi Changhong, kota ini adalah wajah Sichuan yang paling \'cerdas\', berjas laboratorium.'),
  'mianyang/qiang': ('Menara Batu Qiang', 'Di desa-desa pegunungan Beichuan, menara pengawas batu masyarakat Qiang telah berdiri selama berabad-abad, dibangun dengan mahir sebagai lambang pertahanan sekaligus martabat. Sambil menjaga kepercayaan batu putih dan sulaman wol mereka tetap hidup, desa-desa Qiang melestarikan budaya pegunungan yang kuno.'),
  'mianyang/mifen': ('Mi Beras Mianyang', 'Bihun halus yang mengepul dalam kaldu ayam, sapi, atau jeroan membangunkan Mianyang di pagi buta. Helai-helai lembutnya matang dalam hitungan detik, dan kerumunan yang menunduk di atas mangkuk di depan lapak adalah ritual pagi paling setia kota ini.'),
  'nanchong/langzhong': ('Kota Kuno Langzhong', 'Langzhong, salah satu kota kuno terawat terbaik yang ditata menurut prinsip feng shui, tertidur dalam pelukan kelokan Sungai Jialing. Sebagai kampung halaman astronom zaman Han Luoxia Hong, kota ini dihormati sebagai tanah kelahiran tradisi Tahun Baru Tiongkok, dan lorong-lorongnya yang beraroma cuka menjaga jalinan kota era Ming-Qing.'),
  'nanchong/silk': ('Ibu Kota Sutra', 'Dengan tradisi menanam murbei dan menenun lebih dari dua ribu tahun, Nanchong menyandang gelar ibu kota sutra Tiongkok di barat. Kota yang dulu memasok kain bagi Jalur Sutra ini masih hidup dari pabrik pemintalan dan museum sutranya; kain berkilaunya tetap melanglang ke pasar dunia.'),
  'nanchong/zhangfei': ('Daging Sapi Zhang Fei', 'Zhang Fei, pahlawan Tiga Kerajaan, lama bertugas di Langzhong, dan kuilnya masih berdiri di kota ini. Daging sapi berbumbu yang diawetkan dan menyandang namanya — hitam legam di luar, merah mawar di dalam — adalah sentilan jenaka pada citra sang pahlawan yang terkenal berwajah gelap.'),
  'nanchong/zhude': ('Kampung Halaman Zhu De', 'Marsekal Zhu De, salah satu panglima pendiri Tentara Pembebasan Rakyat, lahir di sebuah rumah petani miskin di Yilong. Rumah tani sederhana dan aula peringatannya menjadi persinggahan ziarah sejarah Tiongkok modern, tempat pengunjung merasakan kekuatan dari awal yang bersahaja.'),
  'yibin/wuliangye': ('Arak Wuliangye', 'Disuling dari sorgum, beras, beras ketan, gandum, dan jagung, Wuliangye mengambil namanya dari \'lima biji-bijian\' ini dan termasuk merek baijiu paling berharga di Tiongkok. Iklim lembap Yibin dan lubang fermentasi berusia berabad-abad memberi minuman ini aroma berlapis yang khas.'),
  'yibin/firstcity': ('Kota Pertama di Sungai Yangtze', 'Di titik pertemuan sungai Min dan Jinsha, sungai itu mulai menyandang nama Yangtze — itulah sebabnya Yibin dijuluki \'kota pertama di Yangtze\'. Tanjung tempat kedua air bertemu dengan warna berbeda, kini menjadi taman tepi sungai, adalah pemandangan simbolik yang paling dibanggakan kota ini.'),
  'yibin/bamboosea': ('Lautan Bambu Shunan', 'Laut Bambu Shunan, yang menyelimuti lebih dari seratus bukit, bergoyang tertiup angin bagai samudra hijau tanpa batas. Jalur hutan yang sejuk, air terjun tersembunyi, dan kuliner berbahan rebung memeluk pengunjung, dan kru film pun kembali lagi dan lagi ke hamparan hijau ini.'),
  'yibin/ranmian': ('Mi Bakar (Ranmian)', 'Diuleni nyaris tanpa air dan diaduk dengan minyak harum, \'ranmian\' mendapat julukan \'mi terbakar\' karena cukup kering hingga minyaknya bisa tersulut api. Dibumbui cabai, andaliman Sichuan, dan kacang tanah sangrai, mi ini adalah bintang sarapan Yibin yang sanggup membuka mata.'),
  'luzhou/laojiao': ('Tempat Penyulingan Laojiao', 'Lubang fermentasi lumpur yang dipakai tanpa henti sejak tahun 1573 adalah jantung tradisi baijiu \'aroma kuat\' Luzhou. Kultur mikroba hidup dalam lubang-lubang itu diwariskan dari generasi ke generasi, dan para ahli penyulingan meyakini lubang tertua memberi minuman keharuman paling dalam.'),
  'luzhou/port': ('Pelabuhan Yangtze', 'Didirikan di tempat Sungai Tuo bertemu Yangtze, Luzhou adalah gerbang air Sichuan menuju laut. Selama berabad-abad dermaganya memuat garam, minuman keras, dan biji-bijian, dan kini pelabuhan peti kemasnya masih menghubungkan provinsi pedalaman dengan hilir Yangtze dan dunia.'),
  'luzhou/longan': ('Kebun Kelengkeng', 'Longan, buah kecil semanis madu yang dijuluki \'mata naga\', tumbuh di lereng hangat lembah-lembah sungai Luzhou. Kota ini menjadi rumah bagi sebagian kebun longan besar paling utara di Tiongkok, dan buah yang matang terlambat ini memenuhi lapak-lapak pasar pada musim gugur.'),
  'luzhou/umbrella': ('Payung Kertas Minyak', 'Payung kertas minyak buatan tangan para perajin Fenshui, dengan rangka bambu dan motif yang dilukis tangan, adalah kerajinan anggun berusia empat abad. Setiap payung melewati puluhan tahap pengerjaan dan terbuka untuk keberuntungan sebagaimana untuk hujan — bentuk bundarnya melambangkan keutuhan dan kebahagiaan.'),
  'leshan/giantbuddha': ('Patung Buddha Raksasa Leshan', 'Terpahat di tebing, Buddha duduk setinggi 71 meter ini telah dengan tenang mengawasi pertemuan bergolak tiga sungai selama dua belas abad. Dimulai oleh biksu zaman Tang, Haitong, untuk melindungi perahu yang lewat, proyek kolosal ini kini menjadi situs UNESCO — di jari-jari kakinya saja puluhan orang bisa berdiri.'),
  'leshan/emei': ('Gunung Emei', 'Gunung Emei, salah satu dari empat gunung suci agama Buddha, memanggil peziarah dan pendaki dengan Puncak Emasnya yang bersinar di atas lautan awan. Jalur-jalur pendakian melewati biara-biara kuno, dan pada hari yang beruntung puncaknya menampakkan pelangi berbentuk cincin yang dikenal sebagai \'cahaya Buddha\'.'),
  'leshan/monkeys': ('Monyet Emei', 'Monyet-monyet makaka nakal yang hidup di sepanjang jalur Emei terkenal berani menggeledah tas para peziarah. Warga setempat menyebut mereka \'tuan rumah gunung\'; bertengger di pagar pembatas dan berpose untuk foto, monyet-monyet ini meninggalkan kenangan pendakian yang paling lucu — sekaligus paling bandel.'),
  'leshan/qiaojiao': ('Sup Daging Sapi Qiaojiao', '\'Qiaojiao\', sup sapi yang direbus berjam-jam dengan rempah dan herba, mengambil namanya dari para pelanggan yang dulu menumpangkan kaki di bangku tinggi sambil menyantapnya. Menjadi klasik jalanan Leshan selama sekitar satu abad, mangkuk mengepul ini mengubah bahkan jeroan sederhana menjadi jamuan.'),
  'zigong/saltwell': ('Sumur Garam Sedalam Satu Kilometer', 'Zigong telah hidup dari sumur garamnya selama sekitar dua ribu tahun, dan kepiawaian pengeboran bertali bambunya mencapai puncak dengan Sumur Shenhai — lubang bor pertama di bumi yang menembus kedalaman seribu meter. Menara bor kayu dan museum garam masih menuturkan kisah \'ibu kota garam\' ini.'),
  'zigong/lantern': ('Festival Lampion Zigong', 'Setiap musim Tahun Baru, Zigong berubah menjadi negeri dongeng dengan taman-taman lentera raksasa yang bercahaya. Naga, istana, dan tokoh-tokoh dongeng menjulang dari sutra dan baja, dan kini para maestro lentera kota ini membangun festival cahaya serupa di berbagai kota di seluruh dunia.'),
  'zigong/dinosaur': ('Museum Dinosaurus', 'Ribuan fosil yang bermunculan dari lapisan Jura di Dashanpu menjadikan Zigong ibu kota dinosaurus Tiongkok. Museum yang dibangun tepat di atas lokasi penggalian memamerkan hamparan tulang persis seperti saat ditemukan, dan kerangka sauropoda yang menjulang membawa pengunjung jauh ke kedalaman zaman Jura.'),
  'zigong/rabbit': ('Daging Kelinci Dingin', '\'Lengtu\', daging kelinci yang disajikan dingin dalam minyak cabai dengan andaliman Sichuan dan kacang tanah, adalah salah satu hidangan pembuka paling berani di Sichuan, dan Zigong adalah kampung halamannya. Lahir dari meja makan mengenyangkan para pekerja garam, kuliner kota ini meneruskan tradisi kemurahan bumbu itu hingga kini.'),
  'panzhihua/steel': ('Ibu Kota Vanadium-Titanium', 'Dibangun di lembah pegunungan Sungai Jinsha, Panzhihua adalah kota baja raksasa yang mengolah cadangan vanadium-titanium terkaya di dunia. Bangkit dari nol pada masa pembangunan industri besar abad kedua puluh, kota ini mengambil namanya dari bunga merah menyala pohon kapuk khas daerah ini.'),
  'panzhihua/fruitvalley': ('Lembah Buah Cerah', 'Mangga, delima, dan pisang di lembah Jinsha yang kering dan panas matang dalam iklim mikro bermandikan matahari ini bahkan hingga musim dingin. Mangga panen akhir adalah kebanggaan kota, dan kebun-kebun buahnya memberi kota baja ini cita rasa tropis yang tak terduga.'),
  'panzhihua/sunshine': ('Kota Matahari Musim Dingin', 'Dengan sekitar 2.700 jam sinar matahari per tahun, Panzhihua menjadi persinggahan kebugaran bagi mereka yang mendambakan musim dingin yang hangat dan cerah. Para pensiunan yang melarikan diri dari dinginnya utara menetap di sini sepanjang musim, dan kota ini memahkotai mataharinya dengan kamp olahraga dan resor pemandian air panas.'),
  'panzhihua/jinsha': ('Sungai Jinsha', 'Jinsha — \'sungai pasir emas\' — adalah alur hulu Yangtze, mengukir lembah-lembah dalam saat mengalir deras menembus jantung Panzhihua. Bendungan pembangkit listrik tenaga air di sepanjang alirannya memasok daya bagi kawasan ini, sementara jembatan dan jalan tepi sungai menghidupkan tepiannya.'),
  'dazhou/gas': ('Ibu Kota Gas Alam', 'Di bawah Dazhou terhampar Puguang, salah satu ladang gas alam terbesar di Tiongkok, yang menjadikan kota ini salah satu basis energi nasional. Jaringan pipa membentang dari sini ke kota-kota industri di timur, dan ekonomi gas telah membuka era baru bagi sudut Sichuan yang bergunung-gunung ini.'),
  'dazhou/ba': ('Warisan Kerajaan Ba', 'Inilah tanah para pejuang Ba kuno yang termasyhur dengan pedang berbentuk daun willow; perunggu-perunggu bermotif harimau mereka berbicara lewat reruntuhan Luojiaba. Budaya misterius bangsa pejuang lembah sungai ini membentuk salah satu lapisan tertua sejarah Sichuan.'),
  'dazhou/dengying': ('Daging Sapi Dengying', 'Daging sapi \'dengying\', diiris setipis mungkin hingga tembus cahaya lampu, mengambil namanya dari pertunjukan wayang bayangan yang dulu dimainkan di depan lentera. Irisan renyah setipis kertas ini dibalur bumbu manis dan pedas membara, dan camilan elegan khas Dazhou ini telah menghiasi meja makan lebih dari satu abad.'),
  'dazhou/hanque': ('Gerbang Batu Dinasti Han', 'Menara batu \'que\' berusia dua ribu tahun yang berdiri di ladang-ladang Quxian adalah keanggunan langka arsitektur Han yang bertahan hingga kini. Dulu memahkotai jalan menuju makam, menara gerbang berukir ini menorehkan dunia Han ke dalam batu lewat makhluk-makhluk mitos dan adegan kehidupan sehari-hari.'),
  'guangyuan/jianmen': ('Celah Jianmen', 'Celah Jianmen, tempat \'satu orang dapat menahan sepuluh ribu\', adalah gembok jalan Shu kuno, dengan tebing-tebing yang menjulang bagai bilah pedang. Menjadi simpul pergerakan pasukan sejak zaman Tiga Kerajaan, celah ini mengingatkan pada bait Li Bai bahwa jalan ke Shu \'lebih sulit daripada mendaki ke langit\'.'),
  'guangyuan/wuzetian': ('Tempat Kelahiran Wu Zetian', 'Wu Zetian, satu-satunya kaisar perempuan dalam sejarah Tiongkok, diyakini lahir di Guangyuan, dan Kuil Huangze telah menghormatinya selama seribu tahun. Kota ini merayakan penguasa perkasa itu dengan festival perempuan tahunan, sementara patungnya duduk tenang di kuil tepi sungai.'),
  'guangyuan/plankroad': ('Jalan Papan Kuno', 'Jalan papan yang dipasang di atas balok-balok yang ditancapkan ke tebing curam adalah monumen keberanian yang membuat jalan Shu, yang \'lebih sulit daripada mendaki ke langit\', dapat dilalui. Jejak jalur kuno itu masih terlihat di Ngarai Mingyue, tempat pengunjung berjalan di papan-papan yang dipugar dan merasakan debar jantung kafilah zaman dahulu.'),
  'guangyuan/cypress': ('Koridor Pohon Sipres Cuiyun', 'Puluhan ribu pohon cemara sipres tua berjajar di kedua sisi jalan kuno, mengubah Koridor Cuiyun menjadi terowongan hijau. Legenda menyebut sebagian penanamannya diperintahkan oleh pahlawan Tiga Kerajaan, Zhang Fei, dan jalan rindang ini termasuk penghijauan tepi jalan tertua yang terawetkan di dunia.'),
  'yaan/panda': ('Tempat Kelahiran Panda', 'Panda raksasa pertama kali diperkenalkan kepada dunia ilmu pengetahuan di Baoxing pada tahun 1869, ketika laporan naturalis Prancis Armand David memperkenalkan spesies tercinta ini kepada dunia. Pusat panda Bifengxia menjaga warisan itu tetap hidup, dan hutan bambu berkabut Ya\'an tetap menjadi tanah air sang panda.'),
  'yaan/rain': ('Kota Hujan', '\'Hujan Ya\' membasuh atap-atap hampir setiap malam, dan setiap pagi kota ini berkilau dalam seribu nuansa hijau yang baru tercuci. Warga setempat menghitung tiga keindahan — hujan Ya, ikan Ya, dan gadis Ya — trio yang merangkum jiwa lembut dan berlimpah kota hujan ini.'),
  'yaan/mengding': ('Teh Gunung Mengding', 'Tradisi menuturkan bahwa teh pertama kali ditanam oleh tangan manusia di Gunung Mengding sekitar dua ribu tahun lalu, sehingga gunung ini dianggap tempat lahirnya budaya teh. Daun dari kebun-kebun kuno di puncaknya berabad-abad dipersembahkan kepada para kaisar, dan upacara teh masih digelar di lereng-lerengnya yang berkabut.'),
  'yaan/yayu': ('Ikan Ya', 'Ikan Ya yang melegenda, hidup di sungai-sungai yang dialiri lelehan salju, dihidangkan dalam kuali mendidih dan terhitung sebagai salah satu dari tiga keindahan kota ini. Terkenal karena dagingnya yang putih dan kenyal, ikan ini menyimpan tulang kecil berbentuk pedang di kepalanya, yang di sekelilingnya legenda setempat merajut berbagai kisah.'),
  'xianyang/qincapital': ('Ibu Kota Kekaisaran Qin', 'Di sinilah berdiri ibu kota Qin, dinasti yang pertama kali menyatukan Tiongkok; Qin Shi Huang menapaki jalan menuju kekaisaran dari Xianyang. Bekas istananya kini terhampar sebagai situs arkeologi, tempat perunggu dan fondasi bangunan berbisik tentang kekuasaan berusia lebih dari dua ribu tahun.'),
  'xianyang/qianling': ('Makam Qianling', 'Qianling, makam bersama Wu Zetian dan suaminya, Kaisar Gaozong, yang dipahat ke dalam gunung, adalah salah satu mausoleum Tang langka yang sampai kepada kita tanpa pernah dijarah. Jalan arwahnya dihiasi penjaga batu dan patung utusan asing, sementara prasasti kosong tanpa tulisan yang didirikan Wu Zetian menyerahkan penilaian atas dirinya kepada sejarah.'),
  'xianyang/zhengguo': ('Kanal Zhengguo', 'Digali pada penghujung era Negara-Negara Berperang, Kanal Zhengguo mengairi dataran Guanzhong, mengubahnya menjadi lumbung padi Qin dan meletakkan dasar ekonomi bagi penyatuan Tiongkok. Sistem yang telah memberi makan kawasan ini selama lebih dari dua milenium itu berdiri sebagai karya jenius rekayasa kuno.'),
  'xianyang/guokui': ('Roti pipih Guokui', '\'Guokui\', roti pipih renyah yang sebesar dan setebal tutup kuali, terhitung di antara \'sepuluh keanehan\' Shaanxi yang termasyhur. Dipanggang perlahan di atas api kayu, roti ini tahan berhari-hari, dan hikayat menelusurinya hingga ke ekspedisi kuno ketika para prajurit konon memanggangnya di dalam helm mereka.'),
  'baoji/bronze': ('Ibu Kota Perunggu', 'Dari tanah Baoji, jantung dinasti Zhou, telah muncul ribuan bejana perunggu berprasasti — di antaranya He zun, yang memuat tulisan tertua yang diketahui dari nama \'Tiongkok\' (Zhongguo). Museum perunggu kota ini memamerkan keahlian berusia tiga ribu tahun itu dalam salah satu koleksi terkaya di dunia.'),
  'baoji/famen': ('Kuil Famen', 'Kuil Famen, penjaga relik tulang jari Buddha, menjadi perbendaharaan suci para kaisar Tang. Ketika ruang bawah tanah tersembunyi di bawah pagodanya dibuka pada 1987, harta karun Tang yang memukau berupa emas, perak, dan sutra terungkap ke dunia; kini sebuah kompleks raksasa menaungi relik tersebut.'),
  'baoji/taibai': ('Gunung Taibai', 'Taibai, atap pegunungan Qinling setinggi 3.771 meter, menyuburkan legenda dengan saljunya yang bertahan bahkan hingga musim panas — \'salju bulan Juni di Taibai\' adalah salah satu pemandangan termasyhur Guanzhong kuno. Jalur pendakian menuju danau-danau glasialnya menyusuri garis batas alami antara Tiongkok utara dan selatan.'),
  'baoji/saozi': ('Mi Saozi', 'Mi \'saozi\' Qishan dengan saus daging asam-pedas dianggap cita rasa hidup masakan era Zhou, dengan helai yang tipis, panjang, dan kenyal. Cuka dan cabai goreng menari bersama wortel, telur, dan jamur kuping, dan menyuguhkan mangkuk demi mangkuk kepada tamu di pesta pernikahan adalah tradisi berusia berabad-abad.'),
};
